// Garantit que console.info, console.warn, console.error existent toujou
// Sur certains anciens Safari iOS, seul console.log est défini.
(function(){
  if (typeof console === 'undefined') { window.console = {}; }
  var c = window.console;
  
  if (typeof c.log !== 'function') c.log = function(){};
  if (typeof c.info !== 'function') c.info = c.log;
  if (typeof c.warn !== 'function') c.warn = c.log;
  if (typeof c.error !== 'function') c.error = c.log;
  if (typeof c.debug !== 'function') c.debug = c.log;
})();
