// MIN-14 — Demander un stockage PERSISTANT (réduit le risque d'éviction iOS/Safari
// des contrôles et de la file photos lorsque l'espace se fait rare). Sans effet
// sur les navigateurs qui ne le supportent pas.
(function _demanderStockagePersistant(){
  try {
    if (navigator.storage && navigator.storage.persist && navigator.storage.persisted) {
      navigator.storage.persisted().then(function(deja){
        if (!deja) { navigator.storage.persist().then(function(ok){
          console.info('[HACCP] Stockage persistant : ' + (ok ? 'accordé' : 'refusé par le navigateur'));
        }).catch(function(){}); }
      }).catch(function(){});
    }
  } catch(e) {}
})();

// ══════════════════════════════════════════════════════════════
// ── SYNCHRONISEUR PHOTOS — Livraison 2A ──
// V116 — Envoie les photos en attente vers Supabase Storage
// Tourne toutes les 5 secondes + dès que la connexion revient
// ══════════════════════════════════════════════════════════════
var PHOTO_SYNC_BUCKET = 'haccp-photos';
var PHOTO_SYNC_ACTIF = false;       // Verrou pour éviter chevauchements
var PHOTO_SYNC_INIT = false;        // Évite double initialisation

// Convertit "data:image/jpeg;base64,..." en Blob binaire
function base64VersBlob(b64) {
  try {
    var parts = b64.split(',');
    var mime = (parts[0].match(/:(.*?);/) || [null, 'image/jpeg'])[1];
    var bin = atob(parts[1]);
    var len = bin.length;
    var arr = new Uint8Array(len);
    for (var i = 0; i < len; i++) arr[i] = bin.charCodeAt(i);
    return new Blob([arr], { type: mime });
  } catch(e) {
    console.error('[HACCP Sync] Erreur conversion base64:', e);
    return null;
  }
}

// Nettoie une chaîne pour qu'elle soit utilisable comme nom de fichier
function nettoyerNomFichier(s) {
  return String(s || 'x')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-zA-Z0-9_-]/g, '_')
    .replace(/_+/g, '_');
}

// Construit un nom de fichier unique pour la photo
function construireNomFichierPhoto(photo) {
  var clientId = nettoyerNomFichier(ETAB_ID || 'inconnu');
  var src = nettoyerNomFichier(photo.source || 'photo');
  var d = new Date();
  var ts = d.getFullYear()
    + String(d.getMonth() + 1).padStart(2, '0')
    + String(d.getDate()).padStart(2, '0')
    + '_'
    + String(d.getHours()).padStart(2, '0')
    + String(d.getMinutes()).padStart(2, '0')
    + String(d.getSeconds()).padStart(2, '0');
  var rand = (function(){
    try { if (typeof crypto !== 'undefined' && crypto.randomUUID) return crypto.randomUUID().replace(/-/g, '').substring(0, 12); } catch(_) {}
    return Math.random().toString(36).substring(2, 8) + Math.random().toString(36).substring(2, 8);
  })();
  // Déduit l'extension à partir du base64 (jpg par défaut, pdf si c'est un PDF)
  var ext = 'jpg';
  if (photo.base64 && photo.base64.indexOf('application/pdf') !== -1) ext = 'pdf';
  else if (photo.base64 && photo.base64.indexOf('image/png') !== -1) ext = 'png';
  // V116 Livraison 4-B — Pour les photos rattachées à un produit (etiquette_reception, etiquette_tracabilite),
  // on insère le numéro du produit (p1, p2…) dans le nom du fichier. Pour les photos générales (BL, document, nuisibles…),
  // le controleId n'est pas numérique → on n'ajoute rien.
  var produitMarker = '';
  if (photo.source === 'etiquette_reception' || photo.source === 'etiquette_tracabilite') {
    var n = parseInt(photo.controleId, 10);
    if (!isNaN(n) && n > 0) produitMarker = '_p' + n;
  }
  return clientId + '_' + src + produitMarker + '_' + ts + '_' + rand + '.' + ext;
}

// Upload UNE photo vers Supabase Storage et renvoie l'URL publique
async function uploadPhotoVersStorage(photo) {
  var blob = base64VersBlob(photo.base64);
  if (!blob) return { ok: false, msg: 'Conversion base64 échouée' };

  var nomFichier = construireNomFichierPhoto(photo);
  var urlUpload = SUPABASE_URL + '/storage/v1/object/' + PHOTO_SYNC_BUCKET + '/' + nomFichier;

  try {
    var response = await fetch(urlUpload, {
      method: 'POST',
      headers: {
        'apikey':        SUPABASE_ANON,
        'Authorization': 'Bearer ' + _sbBearer(),
        'Content-Type':  blob.type || 'image/jpeg',
        // CONC-7 : nom de fichier désormais unique (UUID) → on refuse l'écrasement
        // silencieux d'une autre photo (deux clichés à la même seconde).
        'x-upsert':      'false'
      },
      body: blob
    });
    if (!response.ok) {
      var txt = '';
      try { txt = await response.text(); } catch(_) {}
      return { ok: false, msg: 'HTTP ' + response.status + ' ' + txt };
    }
    var urlPublique = SUPABASE_URL + '/storage/v1/object/public/' + PHOTO_SYNC_BUCKET + '/' + nomFichier;
    return { ok: true, url: urlPublique, nom: nomFichier };
  } catch(err) {
    return { ok: false, msg: 'Erreur réseau: ' + (err && err.message ? err.message : err) };
  }
}

// Synchronise toutes les photos en attente — appelée toutes les 5 sec
async function synchroniserPhotos() {
  // Sécurités
  if (PHOTO_SYNC_ACTIF) return;                       // Déjà en cours, on attend
  if (!photoQueueDB) return;                          // Boîte d'attente indispo
  if (!ETAB_ID) return;                               // Pas connecté : on n'envoie rien
  if (typeof navigator !== 'undefined' && navigator.onLine === false) return;  // Hors-ligne

  PHOTO_SYNC_ACTIF = true;
  try {
    // ── PASSE 1 : Upload des photos en attente vers Storage ──
    var enAttente = await photoQueueDB.photos.where('status').equals('pending').toArray();
    if (enAttente.length > 0) {
      console.info('[HACCP Sync] ' + enAttente.length + ' photo(s) à envoyer…');
      for (var i = 0; i < enAttente.length; i++) {
        var photo = enAttente[i];
        try {
          await photoQueueDB.photos.update(photo.id, { status: 'uploading' });
        } catch(_) { continue; }

        var res = await uploadPhotoVersStorage(photo);

        if (res.ok) {
          await photoQueueDB.photos.update(photo.id, {
            status:   'synced',
            url:      res.url,
            nom:      res.nom,
            syncedAt: new Date().toISOString(),
            linkTries: 0
          });
          console.info('[HACCP Sync] ✓ Photo id=' + photo.id + ' envoyée — ' + res.nom);
        } else {
          await photoQueueDB.photos.update(photo.id, { status: 'pending' });
          console.warn('[HACCP Sync] ✗ Photo id=' + photo.id + ' échec — ' + res.msg);
        }
      }
    }

    // ── PASSE 2 : Lier les photos uploadées au contrôle correspondant (Livraison 2B) ──
    var aLier = await photoQueueDB.photos.where('status').equals('synced').toArray();
    // CONC-3 : backoff exponentiel + jitter — au lieu de retenter chaque photo non
    // liée toutes les 5 s (pic = 15-30 GET/s à 20 clients), on espace les tentatives
    // (5s, 10s, 20s… plafonné à 5 min). 60 tentatives couvrent alors plusieurs heures.
    var nowMs = Date.now();
    aLier = aLier.filter(function(p) {
      if (p.controleSupabaseId || (p.linkTries || 0) >= 60) return false;
      var tries = p.linkTries || 0;
      if (tries > 0 && p.lastLinkTry) {
        var base = Math.min(5000 * Math.pow(2, tries - 1), 5 * 60 * 1000);
        var attente = base + base * 0.2 * Math.random(); // jitter ±20%
        if (nowMs - new Date(p.lastLinkTry).getTime() < attente) return false;
      }
      return true;
    });
    if (aLier.length > 0) {
      for (var j = 0; j < aLier.length; j++) {
        await lierPhotoAuControle(aLier[j]);
      }
    }

    // ── PASSE 3 : Nettoyage local (V116 Livraison 8) ──
    // Une fois qu'une photo est en sécurité dans Supabase ET liée à son contrôle,
    // on libère l'espace local sur l'iPhone (ce qui évite la saturation au fil du temps).
    try {
      var aSupprimer = await photoQueueDB.photos.toArray();
      var nbSupprimees = 0;
      for (var k = 0; k < aSupprimer.length; k++) {
        var p = aSupprimer[k];
        if (p.controleSupabaseId && p.status === 'synced' && p.url) {
          await photoQueueDB.photos.delete(p.id);
          nbSupprimees++;
        }
      }
      if (nbSupprimees > 0) {
        console.info('[HACCP Sync] 🧹 ' + nbSupprimees + ' photo(s) locale(s) libérée(s) (déjà sauvegardées dans le cloud)');
      }
    } catch(eCleanup) {
      console.warn('[HACCP Sync] Erreur nettoyage local:', eCleanup);
    }
  } catch(e) {
    console.error('[HACCP Sync] Erreur boucle:', e);
  } finally {
    PHOTO_SYNC_ACTIF = false;
  }
}

// Déduit un motif de recherche pour le nom du module HACCP à partir de la source de la photo
// Retourne un pattern PostgREST (avec * = wildcard) qui matche les variations de nom
// V116 — patterns raccourcis pour éviter les soucis d'accents (ex: "Réception" ne contient pas "eception")
function deduireModule(source) {
  if (!source) return null;
  if (source === 'etiquette_reception' || source === 'bon_livraison') return '*ception*';
  // MIN-3 — la traçabilité est stockée sous « Traçabilité produits reçus » (pas
  // « Réception ») : la photo d'étiquette de traçabilité doit cibler ce module,
  // sinon elle n'était jamais rattachée au bon contrôle.
  if (source === 'etiquette_tracabilite') return '*abilit*';
  if (source === 'document') return '*ocument*';
  if (source.indexOf('nuisibles') === 0) return '*uisible*';
  if (source === 'analyses_micro_rapport') return '*icrobio*';
  return null;
}

// Cherche le contrôle correspondant à la photo et ajoute l'URL dans sa colonne photos
async function lierPhotoAuControle(photo) {
  if (!ETAB_ID || !photo.url || !photo.createdAt) return;

  var moduleAttendu = deduireModule(photo.source);
  if (!moduleAttendu) {
    // Pas de module connu → on abandonne sans réessayer
    try { await photoQueueDB.photos.update(photo.id, { linkTries: 999 }); } catch(_){}
    return;
  }

  // Incrémente compteur de tentatives + horodate (pour le backoff CONC-3)
  try { await photoQueueDB.photos.update(photo.id, { linkTries: (photo.linkTries || 0) + 1, lastLinkTry: new Date().toISOString() }); } catch(_){}

  // Fenêtre temporelle : contrôle créé entre photo.createdAt - 5 min et photo.createdAt + 2h
  var dPhoto = new Date(photo.createdAt);
  var dMin = new Date(dPhoto.getTime() - 5 * 60 * 1000).toISOString();
  var dMax = new Date(dPhoto.getTime() + 2 * 60 * 60 * 1000).toISOString();

  var url = SUPABASE_URL + '/rest/v1/controles_haccp'
    + '?code_client=eq.' + encodeURIComponent(String(ETAB_ID))
    + '&module=ilike.' + encodeURIComponent(moduleAttendu)
    + '&date_controle=gte.' + encodeURIComponent(dMin)
    + '&date_controle=lte.' + encodeURIComponent(dMax)
    + '&order=date_controle.asc'
    + '&limit=1'
    + '&select=id,photos';

  console.info('[HACCP Sync] 🔍 Recherche photo id=' + photo.id + ' — pattern="' + moduleAttendu + '" client="' + ETAB_ID + '"');

  try {
    var resp = await fetch(url, {
      method: 'GET',
      headers: {
        'apikey':        SUPABASE_ANON,
        'Authorization': 'Bearer ' + _sbBearer()
      }
    });
    if (!resp.ok) {
      console.warn('[HACCP Sync] ✗ Recherche HTTP ' + resp.status);
      return;
    }
    var arr = await resp.json();
    console.info('[HACCP Sync] 🔍 Réponse Supabase : ' + arr.length + ' contrôle(s) trouvé(s)');
    if (!arr || arr.length === 0) {
      // CONC-5 — diagnostic cross-tenant retiré (lisait des contrôles sans filtre
      // client). Pas de contrôle correspondant trouvé → on retentera plus tard.
      return;
    }

    var controle = arr[0];
    console.info('[HACCP Sync] 🔍 Contrôle candidat id=' + controle.id);
    var photosActuelles = [];
    if (typeof controle.photos === 'string') {
      try { photosActuelles = JSON.parse(controle.photos) || []; } catch(_) { console.warn('[HACCP Sync] ⚠️ photos JSON parse error'); }
    } else if (Array.isArray(controle.photos)) {
      photosActuelles = controle.photos.slice();
    }

    // Évite les doublons (compat : anciennes entrées = simple URL, nouvelles = objet {u,r,s})
    var urlExiste = photosActuelles.some(function(it){
      return (typeof it === 'string' ? it : (it && it.u)) === photo.url;
    });
    if (urlExiste) {
      await photoQueueDB.photos.update(photo.id, {
        controleSupabaseId: controle.id,
        linkedAt: new Date().toISOString()
      });
      return;
    }

    // On range l'URL AVEC son étiquette : à quel produit (ou bon de livraison) elle appartient
    photosActuelles.push({ u: photo.url, r: (photo.controleId != null ? String(photo.controleId) : ''), s: (photo.source || '') });

    var updResp = await fetch(SUPABASE_URL + '/rest/v1/controles_haccp?id=eq.' + encodeURIComponent(controle.id), {
      method: 'PATCH',
      headers: {
        'apikey':        SUPABASE_ANON,
        'Authorization': 'Bearer ' + _sbBearer(),
        'Content-Type':  'application/json',
        'Prefer':        'return=minimal'
      },
      body: JSON.stringify({ photos: photosActuelles })
    });

    if (updResp.ok) {
      await photoQueueDB.photos.update(photo.id, {
        controleSupabaseId: controle.id,
        linkedAt: new Date().toISOString()
      });
      console.info('[HACCP Sync] ✓ Photo id=' + photo.id + ' liée au contrôle ' + controle.id);
    } else {
      var errTxt = '';
      try { errTxt = await updResp.text(); } catch(_) {}
      console.warn('[HACCP Sync] ✗ Update contrôle HTTP ' + updResp.status + ' ' + errTxt);
    }
  } catch(e) {
    console.warn('[HACCP Sync] Erreur liaison photo:', e);
  }
}

// Démarre le synchroniseur (setInterval + écoute online)
// Appelé une seule fois après chargement du document
function demarrerSynchroniseurPhotos() {
  if (PHOTO_SYNC_INIT) return;
  PHOTO_SYNC_INIT = true;
  // Premier tick après 3 sec (laisse le temps à Supabase de s'initialiser)
  setTimeout(synchroniserPhotos, 3000);
  // Puis toutes les 5 secondes
  setInterval(synchroniserPhotos, 5000);
  // Réessai immédiat dès que la connexion revient
  if (typeof window !== 'undefined' && window.addEventListener) {
    window.addEventListener('online', function() {
      console.info('[HACCP Sync] Connexion revenue — relance immédiate');
      synchroniserPhotos();
    });
  }
  console.info('[HACCP Sync] ✓ Synchroniseur photos démarré (toutes les 5 sec)');
}

// Lancement au chargement de la page
if (typeof document !== 'undefined') {
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', demarrerSynchroniseurPhotos);
  } else {
    demarrerSynchroniseurPhotos();
  }
}
