// SW-6 — insertion via REST direct (et non via le SDK supabase-js, qui peut lever
// un DataCloneError sur Safari iOS et faire échouer en silence une écriture — ex.
// une inscription client envoyée depuis un iPhone). Renvoie {ok, status, body}.
async function _restInsert(table, rows, prefer) {
  try {
    if (typeof SUPABASE_URL === 'undefined' || typeof SUPABASE_ANON === 'undefined') {
      return { ok: false, msg: 'Cloud indisponible' };
    }
    var resp = await fetch(SUPABASE_URL + '/rest/v1/' + table, {
      method: 'POST',
      headers: {
        'apikey': SUPABASE_ANON,
        'Authorization': 'Bearer ' + _sbBearer(),
        'Content-Type': 'application/json',
        'Prefer': prefer || 'return=minimal'
      },
      body: JSON.stringify(Array.isArray(rows) ? rows : [rows])
    });
    var body = ''; try { body = await resp.text(); } catch(e) {}
    return { ok: resp.ok, status: resp.status, body: body };
  } catch(err) {
    return { ok: false, msg: (err && err.message) || 'Erreur réseau' };
  }
}

async function sbLoginTentative(codeAcces, pwd) {
  // SEC — connexion via la fonction serveur sécurisée login_etab : le mot de passe est
  // vérifié CÔTÉ SERVEUR et la table des comptes (ni les mots de passe) n'est jamais
  // exposée à la clé publique.
  var url = SUPABASE_URL + '/rest/v1/rpc/login_etab';
  var response;
  try {
    response = await fetch(url, {
      method: 'POST',
      headers: {
        'apikey': SUPABASE_ANON,
        'Authorization': 'Bearer ' + _sbBearer(),
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ p_code: String(codeAcces || ''), p_pwd: String(pwd || '') })
    });
  } catch(fetchErr) {
    var emsg = (fetchErr && fetchErr.message) ? fetchErr.message : String(fetchErr);
    console.error('Supabase rpc erreur réseau:', emsg);
    return { ok: false, msg: 'Erreur réseau.', retry: true };
  }

  if (!response.ok) {
    console.error('Supabase HTTP erreur:', response.status);
    return { ok: false, msg: 'Erreur serveur (' + response.status + ').', retry: true };
  }

  var res;
  try {
    res = await response.json();
  } catch(jsonErr) {
    return { ok: false, msg: 'Erreur lecture réponse serveur.', retry: true };
  }

  if (!res || res.ok !== true) {
    return { ok: false, msg: (res && res.msg) ? res.msg : 'Code d\'accès ou mot de passe incorrect.' };
  }
  var etab = res.data || {};
  if (etab.date_expiration) {
    // Expiration INCLUSIVE jusqu'à la fin de journée locale (cohérent avec le
    // compte à rebours tickEssaiCountdown et avec le message « jusqu'au … inclus »).
    // Sans cela, une date seule (AAAA-MM-JJ) expire à minuit UTC → blocage dès
    // 1h-2h du matin le jour J en France.
    var exp = new Date(etab.date_expiration); exp.setHours(23, 59, 59, 999);
    if (exp < new Date()) {
      return { ok: false, msg: 'Votre abonnement a expiré le ' + exp.toLocaleDateString('fr-FR') + '. Contactez HACCP Pro pour le renouveler.' };
    }
  }
  // SUIVI ADMIN — horodate la dernière connexion réussie (fire&forget, n'impacte
  // jamais la connexion). Permet à l'admin de voir qui utilise / n'utilise pas.
  try {
    fetch(SUPABASE_URL + '/rest/v1/etablissements?code_acces=eq.' + encodeURIComponent(codeAcces.toUpperCase()), {
      method: 'PATCH',
      headers: { 'apikey': SUPABASE_ANON, 'Authorization': 'Bearer ' + _sbBearer(), 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify({ derniere_connexion: new Date().toISOString() })
    }).catch(function(){});
  } catch(eDc) {}
  return { ok: true, data: etab };
}

async function sbLogin(codeAcces, pwd) {
  var code = codeAcces.toUpperCase().trim();
  // Essayer d'abord en local (instantané, pas de réseau)
  var localResult = sbLoginLocal(code, pwd);
  if (localResult.ok) {
    console.info('Mode local — connexion directe');
    return localResult;
  }
  // Si le code n'est pas dans la liste locale, essayer Supabase
  // Si le code EST dans la liste locale mais mauvais mot de passe → erreur immédiate
  if (CODES_LOCAUX[code] && !localResult.ok) {
    return localResult; // Mauvais mot de passe local
  }
  // Code inconnu localement → tenter Supabase
  try {
    var result = await sbLoginTentative(code, pwd);
    if (result.ok) { MODE_LOCAL = false; return result; }
    if (result.retry) {
      console.info('Supabase inaccessible — tentative de connexion hors-ligne');
      // DATA-5 : réseau indisponible → autoriser l'entrée si une empreinte locale
      // valide (< 7 jours) correspond. Sinon message clair selon le cas.
      var off = await _tryOfflineLogin(code, pwd);
      if (off.ok) { MODE_LOCAL = false; return off; }
      if (off.subExpired) return { ok: false, msg: 'Abonnement expiré. Contactez HACCP Pro.' };
      if (off.expired) return { ok: false, msg: 'Connexion hors-ligne expirée (plus de 7 jours). Reconnectez-vous avec du réseau au moins une fois.' };
      return { ok: false, msg: 'Pas de réseau et aucune connexion récente sur cet appareil. Connectez-vous une fois avec du réseau.' };
    }
    return result;
  } catch(e) {
    var emsg = (e && e.message) ? e.message : String(e);
    console.error('sbLogin exception:', emsg);
    return { ok: false, msg: 'Erreur de connexion. Vérifiez votre réseau.' };
  }
}

function sbLoginLocal(code, pwd) {
  var etab = CODES_LOCAUX[code];
  if (!etab) {
    return { ok: false, msg: 'Code d\'accès non reconnu. Vérifiez le code et réessayez.' };
  }
  if (!etab.actif) {
    return { ok: false, msg: 'Cet établissement est désactivé. Contactez HACCP Pro.' };
  }
  // Vérification mot de passe local
  if (etab.mot_de_passe && etab.mot_de_passe !== pwd) {
    return { ok: false, msg: 'Mot de passe incorrect.' };
  }
  MODE_LOCAL = true;
  console.info('Mode local activé pour :', etab.nom);
  // Les comptes LOCAUX (CODES_LOCAUX, ex. RTH75) sont des comptes de test/démo :
  // ils restent MULTI-SECTEUR (multi_secteur:true) pour pouvoir tester tous les
  // secteurs — sinon la règle de verrouillage par défaut les enfermerait.
  return { ok: true, data: { id: 'local-' + code, nom: etab.nom, secteur: etab.secteur, actif: true, multi_secteur: true, formule: etab.formule || 'complet' }, local: true };
}

// ── DATA-5 — CONNEXION HORS-LIGNE (jusqu'à 7 jours) ──
// Un client déjà connecté récemment doit pouvoir rouvrir l'app SANS réseau (cuisine
// en zone blanche, réveil de veille). On ne stocke JAMAIS le mot de passe en clair :
// seulement une empreinte SHA-256 de (code::mot de passe), comparée hors-ligne.
var OFFLINE_CRED_KEY = 'haccp_offline_cred_v1';
var OFFLINE_CRED_MAX_MS = 7 * 24 * 60 * 60 * 1000; // 7 jours
async function _sha256Hex(str) {
  try {
    if (!(window.crypto && window.crypto.subtle)) return null;
    var buf = await window.crypto.subtle.digest('SHA-256', new TextEncoder().encode(String(str)));
    return Array.prototype.map.call(new Uint8Array(buf), function(b){ return ('0' + b.toString(16)).slice(-2); }).join('');
  } catch(e) { return null; }
}
async function _saveOfflineCred(code, pwd, d) {
  try {
    var h = await _sha256Hex(String(code).toUpperCase() + '::' + String(pwd));
    if (!h) return; // contexte non sécurisé : on s'abstient plutôt que stocker en clair
    lsSet(OFFLINE_CRED_KEY, JSON.stringify({
      code: String(code).toUpperCase(),
      h: h,
      at: Date.now(),
      etab: {
        id: d.id, nom: d.nom, secteur: d.secteur, siret: d.siret,
        adresse: d.adresse, date_expiration: d.date_expiration, code_acces: d.code_acces,
        multi_secteur: d.multi_secteur === true // SEC — préserver le droit multi-secteur hors-ligne
      }
    }));
  } catch(e) {}
}
async function _tryOfflineLogin(code, pwd) {
  try {
    var raw = lsGet(OFFLINE_CRED_KEY);
    if (!raw) return { ok: false };
    var c = JSON.parse(raw);
    if (!c || String(c.code) !== String(code).toUpperCase()) return { ok: false };
    if (Date.now() - (c.at || 0) > OFFLINE_CRED_MAX_MS) return { ok: false, expired: true };
    var h = await _sha256Hex(String(code).toUpperCase() + '::' + String(pwd));
    if (!h || h !== c.h) return { ok: false };
    // Respecter l'expiration d'abonnement même hors-ligne.
    if (c.etab && c.etab.date_expiration) {
      var exp = new Date(c.etab.date_expiration); exp.setHours(23, 59, 59, 999);
      if (exp < new Date()) return { ok: false, subExpired: true };
    }
    console.info('[HACCP] Connexion hors-ligne acceptée (empreinte locale valide)');
    return { ok: true, data: c.etab, offline: true };
  } catch(e) { return { ok: false }; }
}

// ─── PIN VOCAL — connexion rapide par code à 4 chiffres (dictable) ───
// OPTIONNEL : tant qu'aucun PIN n'est activé, la connexion classique est
// inchangée. Le PIN n'est jamais stocké en clair (empreinte SHA-256). Le
// code + mot de passe sont obfusqués (XOR clé dérivée du PIN). ⚠️ Un PIN de
// 4 chiffres reste faible : confort de déverrouillage sur VOTRE appareil.
function _pinObf(str, keyHex) {
  var out = '';
  for (var i = 0; i < str.length; i++) {
    var k = parseInt(keyHex.substr((i * 2) % keyHex.length, 2), 16) || 0;
    out += String.fromCharCode(str.charCodeAt(i) ^ k);
  }
  try { return btoa(unescape(encodeURIComponent(out))); } catch (e) { return ''; }
}
function _pinDeobf(b64, keyHex) {
  try {
    var s = decodeURIComponent(escape(atob(b64))), out = '';
    for (var i = 0; i < s.length; i++) {
      var k = parseInt(keyHex.substr((i * 2) % keyHex.length, 2), 16) || 0;
      out += String.fromCharCode(s.charCodeAt(i) ^ k);
    }
    return out;
  } catch (e) { return ''; }
}
function pinVocalActif() { try { return !!lsGet('haccp_pinv'); } catch (e) { return false; } }

async function activerPinVocal() {
  var code = (document.getElementById('login_code') ? document.getElementById('login_code').value : '').trim().toUpperCase();
  var pwd = (document.getElementById('login_pwd') ? document.getElementById('login_pwd').value : '').trim();
  if (!code || !pwd) { alert('Entrez d\'abord votre code d\'accès et votre mot de passe, puis activez le PIN.'); return; }
  var pin = prompt('Choisissez un code PIN à 4 chiffres pour cet appareil :');
  if (pin === null) return;
  pin = String(pin).replace(/\D/g, '');
  if (pin.length !== 4) { alert('Le PIN doit comporter exactement 4 chiffres.'); return; }
  var pin2 = prompt('Confirmez le PIN à 4 chiffres :');
  if (pin2 === null) return;
  if (String(pin2).replace(/\D/g, '') !== pin) { alert('Les deux PIN ne correspondent pas.'); return; }
  var keyHex = await _sha256Hex(pin);
  if (!keyHex) { alert('Contexte non sécurisé : PIN indisponible ici.'); return; }
  var h = await _sha256Hex(pin + '|' + code);
  try {
    lsSet('haccp_pinv', JSON.stringify({ h: h, c: _pinObf(code, keyHex), p: _pinObf(pwd, keyHex), at: Date.now() }));
    alert('✅ PIN activé sur cet appareil.\n\nLa prochaine fois, touchez « Connexion par PIN » et dictez (ou tapez) vos 4 chiffres.');
    if (typeof _pinUiRefresh === 'function') _pinUiRefresh();
  } catch (e) { alert('Impossible d\'enregistrer le PIN (stockage plein ?).'); }
}

function desactiverPinVocal() {
  try { lsRemove('haccp_pinv'); } catch (e) {}
  if (typeof _pinUiRefresh === 'function') _pinUiRefresh();
}

async function connexionParPin(pin) {
  pin = String(pin || '').replace(/\D/g, '');
  if (pin.length !== 4) { alert('Dictez ou saisissez vos 4 chiffres.'); return; }
  var raw; try { raw = lsGet('haccp_pinv'); } catch (e) {}
  if (!raw) { alert('Aucun PIN activé sur cet appareil.'); return; }
  var o; try { o = JSON.parse(raw); } catch (e) { return; }
  var keyHex = await _sha256Hex(pin);
  var code = _pinDeobf(o.c, keyHex), pwd = _pinDeobf(o.p, keyHex);
  var hVerif = await _sha256Hex(pin + '|' + code);
  if (hVerif !== o.h) { alert('PIN incorrect.'); return; }
  var ce = document.getElementById('login_code'), pe = document.getElementById('login_pwd');
  if (ce) ce.value = code;
  if (pe) pe.value = pwd;
  if (typeof connexion === 'function') connexion();   // réutilise la connexion CLASSIQUE (sûr)
}

function _pinUiRefresh() {
  var actif = pinVocalActif();
  var b = document.getElementById('pinLoginWrap'); if (b) b.style.display = actif ? 'block' : 'none';
  var a = document.getElementById('pinActiverWrap'); if (a) a.style.display = actif ? 'none' : 'block';
}
if (typeof window !== 'undefined') {
  window.activerPinVocal = activerPinVocal; window.desactiverPinVocal = desactiverPinVocal;
  window.connexionParPin = connexionParPin; window.pinVocalActif = pinVocalActif;
}

