function getEtabHeader() {
  var lines = [];
  if (ETAB.nom) lines.push(ETAB.nom);
  if (ETAB.adresse) lines.push(ETAB.adresse + (ETAB.cp ? ' — ' + ETAB.cp + ' ' + ETAB.ville : ''));
  if (ETAB.tel) lines.push('Tél : ' + ETAB.tel + (ETAB.email ? ' | ' + ETAB.email : ''));
  if (ETAB.siret) lines.push('SIRET : ' + ETAB.siret);
  if (ETAB.responsable) lines.push('Responsable HACCP : ' + ETAB.responsable + (ETAB.fonction ? ' — ' + ETAB.fonction : ''));
  return lines;
}

// Nettoie le texte pour jsPDF : supprime emojis, remplace caractères accentués

// ═══════════════════════════════════════════════════════
// COLLECTE UNIVERSELLE — fonctionne pour tous les modules
// et tous les secteurs sans connaître les IDs à l'avance
// ═══════════════════════════════════════════════════════

function collectPageDataUniversel(pageId) {
  var page = document.getElementById(pageId);
  if (!page) return null;
  var data = {
    pageId: pageId,
    module: '',
    secteur: SECTEUR_ACTIF,
    etab: ETAB.nom || '',
    timestamp: getNowStr(),
    signe: '',
    champs: [],
    statuts: [],
    observations: [],
    ncs: [],
    actions: [],
  };

  var titleEl = page.querySelector('.mod-header-title');
  if (titleEl) data.module = titleEl.textContent.trim();

  var prenomEl = page.querySelector('[id*="sig_prenom"]');
  var nomEl = page.querySelector('[id*="sig_nom"]');
  if (prenomEl && nomEl) data.signe = (prenomEl.value + ' ' + nomEl.value).trim();

  // IDs à exclure de la collecte générale
  var skipPatterns = ['sig_prenom','sig_nom','sig_required','timestamp','Canvas',
    'Container','Block','preview','required','seuil_info','seuil_txt',
    'nouv_nom','nouv_num','act_type_','act_detail_','act_resp_','act_heure_',
    'nc_act_','s_ga_','d_ga_','r_ga_','h_ga_','emb_abime_','generic_action',
    'act_type','act_detail','act_resp','act_heure'];

  function shouldSkip(el) {
    if (!el.id && !el.name) return false;
    var id = el.id || '';
    // Exclure les champs dans les blocs nc-action
    if (el.closest && el.closest('.nc-action')) return true;
    if (el.closest && el.closest('[data-generic]')) return true;
    return skipPatterns.some(function(p){ return id.includes(p); });
  }

  // Champs remplis (hors actions correctives)
  page.querySelectorAll('input:not([type=button]):not([type=submit]):not([type=checkbox]):not([type=radio]), select').forEach(function(el) {
    if (!el.value || !el.value.trim()) return;
    if (shouldSkip(el)) return;
    if (el.tagName === 'SELECT' && el.selectedIndex <= 0) return;
    var label = '';
    var row = el.closest('.frow');
    if (row) { var lbl = row.querySelector('.flabel'); if (lbl) label = lbl.textContent.trim().replace(/[*]/g,'').trim(); }
    // V85 — Si pas dans .frow, chercher dans .tcard
    if (!label) {
      var tc = el.closest('.tcard');
      if (tc) {
        var tcLbl = tc.querySelector('.tcard-lbl');
        if (tcLbl) label = tcLbl.textContent.trim().replace(/[*]/g,'').trim();
      }
    }
    if (!label && el.placeholder && el.placeholder !== '0') label = el.placeholder;
    if (!label && el.id) label = el.id.replace(/_/g,' ').replace(/[0-9]+$/,'').trim();
    var val = el.tagName === 'SELECT' ? el.options[el.selectedIndex].text : el.value.trim();
    // V85 — Ajouter unité si .tcard
    var tcU = el.closest('.tcard');
    if (tcU) {
      var tu = tcU.querySelector('.tunit');
      if (tu && tu.textContent.trim()) val = val + ' ' + tu.textContent.trim();
    }
    data.champs.push({ label: label, valeur: val });
  });

  // Textareas (hors actions correctives)
  page.querySelectorAll('textarea').forEach(function(el) {
    if (!el.value || !el.value.trim()) return;
    if (shouldSkip(el)) return;
    if (el.closest && el.closest('.nc-action')) return;
    var label = 'Observations';
    var row = el.closest('.frow');
    if (row) { var lbl = row.querySelector('.flabel'); if (lbl) label = lbl.textContent.trim(); }
    data.observations.push({ label: label, valeur: el.value.trim() });
  });

  // Statuts
  page.querySelectorAll('.frow').forEach(function(row) {
    var grp = row.querySelector('.status-group');
    if (!grp) return;
    if (row.closest && row.closest('.nc-action')) return;
    // V112 — Ne pas pousser les status-groups internes aux pt_action_X (sous-blocs Fermeture)
    // sinon doublon "Action corrective — Nettoyage & désinfection complets effectués ?" en statut
    if (row.closest && row.closest('[id^="pt_action_"]')) return;
    var lbl = row.querySelector('.flabel');
    if (!lbl) return;
    var label = lbl.textContent.trim().replace(/[⚠️🔴⚡*]/g,'').trim();
    var okBtn = grp.querySelector('.status-btn.active-ok');
    var warnBtn = grp.querySelector('.status-btn.active-warn');
    var badBtn = grp.querySelector('.status-btn.active-bad');
    // V80 — Ne pas pousser les contrôles non renseignés (sinon Pack DDPP affiche "—" partout)
    if (!okBtn && !warnBtn && !badBtn) return;
    var statut = okBtn ? 'Conforme' : (warnBtn ? 'N/A' : 'Non conforme');

    // V112 — Attacher l'action corrective DIRECTEMENT au statut (mapping fiable par DOM)
    // Bug racine V111 : data.statuts et data.actions stockés séparément, mapping textuel
    // par .indexOf() produisait des inversions (module hygiene) et des actions vides.
    // Stratégie : capter en priorité 0 le sous-bloc pt_action_X (Fermeture intra-frow),
    // sinon nc-action sibling (autres modules), sinon nc-action dans le bloc parent.
    var action = null;
    var constatNC = '';
    if (!!badBtn || !!warnBtn) {
      // Priorité 0 — Fermeture : pt_action_X intra-frow avec status-group Oui/Non
      var ptAction = row.querySelector('[id^="pt_action_"]');
      if (ptAction && (ptAction.classList.contains('visible') || ptAction.style.display === 'block' || ptAction.style.display === 'flex')) {
        var ptGrp = ptAction.querySelector('.status-group');
        if (ptGrp) {
          var ptActive = ptGrp.querySelector('.status-btn.active-ok, .status-btn.active-warn, .status-btn.active-bad');
          if (ptActive) {
            action = { type: ptActive.textContent.trim().replace(/[✅✗⚠️🚨]/g,'').trim(), detail: '', responsable: '', heure: '' };
          }
        }
      }
      // Priorité 1 — nc-action SIBLING du frow (modules avec action par ligne)
      if (!action) {
        var sib = row.nextElementSibling;
        var hops = 0;
        while (sib && hops < 4) {
          if (sib.classList && sib.classList.contains('nc-action')) {
            // Ne prendre que si AU MOINS un champ rempli
            // V-NC16 — cibler explicitement le select/input d'action (classes dédiées)
            // pour ne pas confondre avec le menu "Non-conformité constatée"
            var aSel = sib.querySelector('.nc-act-select') || sib.querySelector('select');
            var aDet = sib.querySelector('.nc-act-detail') || sib.querySelector('input[type="text"]:not(.nc-constat-autre)') || sib.querySelector('input[type="text"]');
            var aResp = sib.querySelector('input[id*="resp"]') || row.querySelector('input[id*="resp"]') || (row.closest('.fblock') ? row.closest('.fblock').querySelector('input[id*="resp"]') : null);
            var aHeure = sib.querySelector('input[type="time"]');
            var aType = (aSel && aSel.selectedIndex > 0) ? aSel.options[aSel.selectedIndex].text : '';
            var aDetVal = aDet ? aDet.value.trim() : '';
            var aRespVal = aResp ? aResp.value.trim() : '';
            var aHeureVal = aHeure ? aHeure.value.trim() : '';
            // V-NC16 — non-conformité constatée (menu déroulant adapté au point)
            var cSel = sib.querySelector('.nc-constat-select');
            if (cSel && cSel.selectedIndex > 0) {
              var cTxt = cSel.options[cSel.selectedIndex].text;
              if (/autre/i.test(cTxt)) {
                var cA = sib.querySelector('.nc-constat-autre');
                constatNC = (cA && cA.value.trim()) ? cA.value.trim() : cTxt;
              } else { constatNC = cTxt; }
            }
            if (aType || aDetVal || aRespVal) {
              action = { type: aType, detail: aDetVal, responsable: aRespVal, heure: aHeureVal };
            }
            break;
          }
          if (sib.classList && (sib.classList.contains('frow') || sib.classList.contains('fblock'))) break;
          sib = sib.nextElementSibling;
          hops++;
        }
      }
      // Priorité 2 — nc-action dans le bloc parent .fblock (modules Ouverture, Affichages : 1 action globale)
      if (!action) {
        var parentBlock = row.closest('.fblock');
        if (parentBlock) {
          var blockAction = parentBlock.querySelector('.nc-action.visible, .nc-action[style*="block"], .nc-action[style*="flex"]');
          if (blockAction) {
            var bSel = blockAction.querySelector('.nc-act-select') || blockAction.querySelector('select');
            var bDet = blockAction.querySelector('.nc-act-detail') || blockAction.querySelector('input[type="text"]:not(.nc-constat-autre)') || blockAction.querySelector('input[type="text"]');
            var bResp = blockAction.querySelector('input[id*="resp"]');
            var bHeure = blockAction.querySelector('input[type="time"]');
            var bType = (bSel && bSel.selectedIndex > 0) ? bSel.options[bSel.selectedIndex].text : '';
            var bDetVal = bDet ? bDet.value.trim() : '';
            var bRespVal = bResp ? bResp.value.trim() : '';
            var bHeureVal = bHeure ? bHeure.value.trim() : '';
            if (bType || bDetVal || bRespVal) {
              action = { type: bType, detail: bDetVal, responsable: bRespVal, heure: bHeureVal };
            }
          }
        }
      }
    }

    var entry = { label: label, statut: statut, nc: !!badBtn };
    if (action) entry.action = action;
    // V-NC16 — enregistrer la norme attendue (seuil qualitatif) et la NC constatée
    if (!!badBtn) {
      var _catE = (typeof getCatalogueNC === 'function') ? getCatalogueNC(label) : null;
      if (_catE && _catE.norme) entry.norme = _catE.norme;
      if (constatNC) entry.constat = constatNC;
    }
    data.statuts.push(entry);
  });

// NC actives
  page.querySelectorAll('.nc-auto').forEach(function(el) {
    if (el.style.display === 'flex' || el.style.display === 'block') {
      // V117 — on enregistre AUSSI action corrective + responsable + heure + seuil + valeur relevée
      // pour que le tableau récap les retrouve même fiche fermée (corrige les NC de température)
      var ncAct='', ncResp='', ncHeureAct='', ncSeuil='', ncVal='';
      try {
        var idNum = (el.id||'').split('_').pop();
        var sib = el.nextElementSibling;
        while (sib && !(sib.classList && sib.classList.contains('nc-action'))) sib = sib.nextElementSibling;
        if (sib) {
          var selEl = sib.querySelector('.nc-act-select') || sib.querySelector('select');
          var detEl = sib.querySelector('.nc-act-detail') || sib.querySelector('input[type="text"]:not(.nc-constat-autre)') || sib.querySelector('input[type="text"]');
          var rspEl = sib.querySelector('input[id*="resp"]');
          var hrEl  = sib.querySelector('input[type="time"]');
          var tVal = (selEl && selEl.selectedIndex > 0) ? selEl.options[selEl.selectedIndex].text : '';
          var dVal = detEl ? (detEl.value||'') : '';
          ncAct = tVal + (dVal ? ' — ' + dVal : '');
          ncResp = rspEl ? (rspEl.value||'') : '';
          ncHeureAct = hrEl ? (hrEl.value||'') : '';
        }
        var cont = el.parentNode;
        if (cont && idNum) {
          var sEl = cont.querySelector('input[id*="seuil_' + idNum + '"]');
          var vEl = cont.querySelector('input[id*="val_' + idNum + '"]');
          ncSeuil = sEl ? (sEl.value||'') : '';
          ncVal = vEl ? (vEl.value||'') : '';
        }
      } catch(e){}
      data.ncs.push({
  desc: el.textContent.replace(/[⚡]/g,'').trim(),
  date: new Date().toLocaleDateString('fr-FR'),
  heure: new Date().toLocaleTimeString('fr-FR',{hour:'2-digit',minute:'2-digit'}),
  action: ncAct,
  responsable: ncResp,
  heureAction: ncHeureAct,
  seuil: ncSeuil,
  valeur: ncVal,
  toString: function(){ return this.desc; }
});
    }
  });
  // Photos + N° lot des blocs produits (réception, traçabilité)
  var photos = [];
  var lots = [];
  page.querySelectorAll('[id^="photo_"]').forEach(function(img) {
    if (img.src && img.src.indexOf('data:image') > -1) {
      var id = img.id.replace('photo_', '');
      var typeEl = document.getElementById('type_' + id);
      var lotEl = document.getElementById('lot_' + id);
      photos.push({
        id: id,
        src: img.src,
        produit: typeEl ? (typeEl.options[typeEl.selectedIndex] ? typeEl.options[typeEl.selectedIndex].text : '') : '',
        lot: lotEl ? lotEl.value : '',
      });
    }
    });
  page.querySelectorAll('[id^="lot_"]').forEach(function(el) {
    if (!el.value) return;
    var id = el.id.replace('lot_', '');
    if (!lots.find(function(l){ return l.id === id; })) {
      var typeEl = document.getElementById('type_' + id);
      lots.push({
        id: id,
        lot: el.value,
        produit: typeEl ? (typeEl.options[typeEl.selectedIndex] ? typeEl.options[typeEl.selectedIndex].text : '') : '',
      });
    }
  });
  data.photos = photos;
  data.lots = lots;

  // Actions correctives — collecter TOUTES les nc-action qui ont au moins un champ rempli
  // (peu importe la classe .visible : on regarde si l'utilisateur a saisi quelque chose)
  page.querySelectorAll('.nc-action').forEach(function(block) {
    var action = { type:'', detail:'', responsable:'', heure:'', contexte:'' };
    // Titre
    var titleEl2 = block.querySelector('.nc-action-title');
    if (titleEl2) action.contexte = titleEl2.textContent.replace(/[🛠️🚨]/g,'').trim();
    // Champs
    block.querySelectorAll('select, input, textarea').forEach(function(el) {
      var val = el.tagName === 'SELECT' ? (el.selectedIndex > 0 ? el.options[el.selectedIndex].text : '') : (el.value || '');
      if (!val.trim()) return;
      var id = el.id || '';
      // IDs fixes (nc_act_type_xxx) et IDs génériques (s_ga_xxx)
      if (el.tagName === 'SELECT' || id.includes('type') || id.match(/^s_/)) {
        action.type = val;
      } else if (id.includes('detail') || id.match(/^d_/)) {
        action.detail = val;
      } else if (id.includes('resp') || id.match(/^r_/)) {
        action.responsable = val;
      } else if (id.includes('heure') || id.match(/^h_/)) {
        action.heure = val;
      }
    });
    // Ne garder que si AU MOINS un champ a été rempli
    if (action.type || action.detail || action.responsable) {
      data.actions.push(action);
    }
  });

  // V80 fix Pack DDPP — Si le DOM est vide (module non ouvert actuellement), utiliser les
  // dernières données sauvegardées en localStorage pour que Pack DDPP ait quand même les infos.
  var domEmpty = (data.champs.length === 0
                  && data.statuts.length === 0
                  && data.observations.length === 0
                  && data.ncs.length === 0
                  && (!data.actions || data.actions.length === 0));
  if (domEmpty && typeof getDernieresDonnees === 'function') {
    try {
      var saved = getDernieresDonnees(pageId);
      if (saved && saved.data) {
        // Retourner les données sauvegardées (avec leurs champs, statuts, NC, actions, photos)
        return saved.data;
      }
    } catch(e) {}
  }

  return data;
}

function pdfSafe(str) {
  if (!str) return '';
  var s = String(str);
  s = s.replace(/‘|’|′|″/g, "'");
  s = s.replace(/“|”|«|»/g, '"');
  s = s.replace(/–|—|―/g, '-');
  s = s.replace(/…/g, '...');
  s = s.replace(/[àáâãäå]/g, 'a').replace(/[ÀÁÂÃÄÅ]/g, 'A');
  s = s.replace(/[èéêë]/g, 'e').replace(/[ÈÉÊË]/g, 'E');
  s = s.replace(/[ìíîï]/g, 'i').replace(/[ÌÍÎÏ]/g, 'I');
  s = s.replace(/[òóôõöø]/g, 'o').replace(/[ÒÓÔÕÖØ]/g, 'O');
  s = s.replace(/[ùúûü]/g, 'u').replace(/[ÙÚÛÜ]/g, 'U');
  s = s.replace(/[ýÿ]/g, 'y').replace(/[Ý]/g, 'Y');
  s = s.replace(/[ñ]/g, 'n').replace(/[Ñ]/g, 'N');
  s = s.replace(/[ç]/g, 'c').replace(/[Ç]/g, 'C');
  s = s.replace(/œ/g, 'oe').replace(/Œ/g, 'OE');
  s = s.replace(/æ/g, 'ae').replace(/Æ/g, 'AE');
  s = s.replace(/ß/g, 'ss');
  s = s.replace(/[^ -~]/g, '');
  return s;
}


