function initEnceinteSelect(id) {
  var sel = document.getElementById('enc_ref_type_' + id);
  if (!sel) return;
  var secteur = (typeof SECTEUR_ACTIF !== 'undefined' && SECTEUR_ACTIF) ? SECTEUR_ACTIF : 'resto';
  var base = (TYPES_ENCEINTES && TYPES_ENCEINTES.base) ? TYPES_ENCEINTES.base : [];
  var spec = (TYPES_ENCEINTES && TYPES_ENCEINTES[secteur]) ? TYPES_ENCEINTES[secteur] : [];
  var valsBase = base.map(function(t){ return t.val; });
  var specFiltered = spec.filter(function(t){ return valsBase.indexOf(t.val) === -1; });
  sel.innerHTML = '<option value="">— Selectionner le type —</option>';
  if (specFiltered.length > 0) {
    var grpBase = document.createElement('optgroup');
    grpBase.label = '── Commun tous secteurs ──';
    base.forEach(function(t) {
      var s2 = t.seuil !== null ? ' (<=' + (t.seuil < 0 ? '' : '+') + t.seuil + 'C)' : ' (Manuel)';
      var opt = document.createElement('option');
      opt.value = t.val; opt.textContent = t.label + s2;
      grpBase.appendChild(opt);
    });
    sel.appendChild(grpBase);
    var grpSpec = document.createElement('optgroup');
    grpSpec.label = '── Specifique ' + secteur + ' ──';
    specFiltered.forEach(function(t) {
      var s2 = t.seuil !== null ? ' (<=' + (t.seuil < 0 ? '' : '+') + t.seuil + 'C)' : ' (Manuel)';
      var opt = document.createElement('option');
      opt.value = t.val; opt.textContent = t.label + s2;
      grpSpec.appendChild(opt);
    });
    sel.appendChild(grpSpec);
  } else {
    base.forEach(function(t) {
      var s2 = t.seuil !== null ? ' (<=' + (t.seuil < 0 ? '' : '+') + t.seuil + 'C)' : ' (Manuel)';
      var opt = document.createElement('option');
      opt.value = t.val; opt.textContent = t.label + s2;
      sel.appendChild(opt);
    });
  }
}

