function collecterDonneesTemperatures() {
  var allBlocks = document.querySelectorAll('[id^="enc_block_"]');
  var enceintes = [];
  allBlocks.forEach(function(block) {
    var id = block.id.replace('enc_block_', '');
    var precisionEl = document.getElementById('enc_precision_' + id);
    var typeEl = document.getElementById('enc_ref_type_' + id);
    var tempEl = document.getElementById('enc_temp_' + id);
    var confEl = document.getElementById('enc_conf_' + id);
    var ncEl = document.getElementById('enc_nc_' + id);
    var actionTypeEl = document.getElementById('nc_act_type_enc_nc_' + id);
    var actionDetailEl = document.getElementById('nc_act_detail_enc_nc_' + id);
    var refNumEl = document.getElementById('enc_ref_num_' + id);
    var refNum = refNumEl ? refNumEl.value || '' : '';
    var typeTxt = typeEl && typeEl.selectedIndex > 0 ? typeEl.options[typeEl.selectedIndex].text : '—';
    // Nom de l'enceinte (titre du bloc, sans l'icône) — nécessaire pour la
    // colonne du Tableau Excel des températures (appariement par nom d'enceinte).
    var titleSpan = block.querySelector('.fblock-title span');
    var encNom = titleSpan ? titleSpan.textContent.replace(/^[^0-9A-Za-zÀ-ÿ]+/, '').trim() : '';
    var isNC = ncEl ? ncEl.style.display !== 'none' : false;
    var actionTxt = (actionTypeEl && actionTypeEl.value) ? actionTypeEl.value : ((actionDetailEl && actionDetailEl.value) ? actionDetailEl.value : '');
    enceintes.push({
      id: id,
      precision: precisionEl ? precisionEl.value || '' : '',
      refNum: refNum,
      type: typeTxt,
      nom: encNom,
      temp: tempEl ? tempEl.value : '',
      conf: confEl ? confEl.textContent.trim() : '—',
      isNC: isNC,
      action: actionTxt,
    });
  });
  // V111 — Fallback localStorage : si le DOM est vide (Pack DDPP hors module),
  // lire la dernière sauvegarde du module qui contient data.temperatures
  if (enceintes.length === 0) {
    try {
      var _etabId = (typeof ETAB_ID !== 'undefined' && ETAB_ID) ? ETAB_ID : (lsGet('haccp_etab_id') || 'local');
      var _stored = JSON.parse(lsGet('haccp_module_data_page-temperatures_' + _etabId) || '[]');
      for (var _i = 0; _i < _stored.length; _i++) {
        var _e = _stored[_i];
        if (_e && _e.data && Array.isArray(_e.data.temperatures) && _e.data.temperatures.length > 0) {
          return _e.data.temperatures;
        }
      }
    } catch(eFb) { console.warn('Fallback températures erreur:', eFb.message||eFb); }
  }
  return enceintes;
}


function collecterDonneesCuisson() {
  var plats = [];
  var allBlocks = document.querySelectorAll('[id^="plat_"]');
  var platIds = [];
  allBlocks.forEach(function(b) {
    var m = b.id.match(/^plat_(\d+)$/);
    if (m) platIds.push(m[1]);
  });
  platIds.forEach(function(id) {
    var nom = document.getElementById('plat_nom_' + id);
    var qte = document.getElementById('plat_qte_' + id);
    var mode = document.getElementById('plat_mode_' + id);
    var type = document.getElementById('plat_type_' + id);
    var temp = document.getElementById('plat_temp_' + id);
    var conf = document.getElementById('plat_conf_' + id);
    var nc = document.getElementById('plat_nc_' + id);
    var actType = document.getElementById('nc_act_type_plat_nc_' + id);
    var actDetail = document.getElementById('nc_act_detail_plat_nc_' + id);
    // Remise en T°
    var remiseT0 = document.getElementById('remise_t0_' + id);
    var remiseTf = document.getElementById('remise_tf_' + id);
    var remiseConf = document.getElementById('remise_conf_' + id);
    var remiseNc = document.getElementById('remise_nc_' + id);
    var remiseActType = document.getElementById('nc_act_type_remise_nc_' + id);
    var typeTxt = type && type.selectedIndex > 0 ? type.options[type.selectedIndex].text : '—';
    var isNC = nc ? nc.style.display !== 'none' : false;
    var isRemiseNC = remiseNc ? remiseNc.style.display !== 'none' : false;
    var action = (actType && actType.selectedIndex > 0 ? actType.options[actType.selectedIndex].text : '') || (actDetail ? actDetail.value : '');
    var remiseAction = (remiseActType && remiseActType.selectedIndex > 0 ? remiseActType.options[remiseActType.selectedIndex].text : '');
    plats.push({
      id: id,
      nom: nom ? nom.value || '—' : '—',
      qte: qte ? qte.value || '' : '',
      mode: mode ? mode.value || '' : '',
      type: typeTxt,
      temp: temp ? temp.value || '' : '',
      conf: conf ? conf.textContent.trim() : '—',
      isNC: isNC,
      action: action,
      remiseT0: remiseT0 ? remiseT0.value || '' : '',
      remiseTf: remiseTf ? remiseTf.value || '' : '',
      remiseConf: remiseConf ? remiseConf.textContent.trim() : '',
      isRemiseNC: isRemiseNC,
      remiseAction: remiseAction,
    });
  });
  // V111 — Fallback localStorage : si DOM vide (Pack DDPP hors module)
  if (plats.length === 0) {
    try {
      var _etabId = (typeof ETAB_ID !== 'undefined' && ETAB_ID) ? ETAB_ID : (lsGet('haccp_etab_id') || 'local');
      var _stored = JSON.parse(lsGet('haccp_module_data_page-cuisson_' + _etabId) || '[]');
      for (var _i = 0; _i < _stored.length; _i++) {
        var _e = _stored[_i];
        if (_e && _e.data && Array.isArray(_e.data.cuisson) && _e.data.cuisson.length > 0) {
          return _e.data.cuisson;
        }
      }
    } catch(eFb) { console.warn('Fallback cuisson erreur:', eFb.message||eFb); }
  }
  return plats;
}

function imprimerCuisson() {
  var plats = collecterDonneesCuisson();
  var filled = plats.filter(function(p){ return p.nom !== '—' || p.temp; });
  if (filled.length === 0) { showToast('Aucun plat saisi', 'warn'); return; }
  var sigPrenom = document.getElementById('cuis_sig_prenom');
  var sigNom = document.getElementById('cuis_sig_nom');
  var signataire = sigPrenom && sigNom ? (sigPrenom.value + ' ' + sigNom.value).trim() : '—';
  var ncCount = filled.filter(function(p){ return p.isNC || p.isRemiseNC; }).length;

  var html = '<div style="padding:0 16px 20px;font-family:Arial,sans-serif">';
  // Header
  html += '<div style="background:linear-gradient(135deg,#dc2626,#f87171);color:white;padding:14px 16px;border-radius:10px;margin-bottom:14px">';
  html += '<div style="font-weight:800;font-size:15px">Cuisson & Remise en Temperature</div>';
  html += '<div style="font-size:11px;opacity:.85;margin-top:4px">' + _echap(ETAB.nom||'') + ' — ' + getNowStr() + '</div>';
  html += '<div style="font-size:11px;opacity:.85">Émargement : ' + _echap(signataire || '—') + '</div>';
  html += '<div style="font-size:11px;opacity:.85">Secteur : ' + (((typeof SECTEURS_CONFIG!=='undefined' && SECTEURS_CONFIG[SECTEUR_ACTIF] && SECTEURS_CONFIG[SECTEUR_ACTIF].label)) || SECTEUR_ACTIF || '—') + '</div>';
  if (ncCount > 0) html += '<div style="margin-top:6px;background:rgba(0,0,0,.25);border-radius:6px;padding:4px 8px;font-size:11px;font-weight:700">' + ncCount + ' non-conformite(s)</div>';
  html += '</div>';

  filled.forEach(function(plat, i) {
    var borderColor = (plat.isNC || plat.isRemiseNC) ? '#dc2626' : '#dc2626';
    html += '<div style="border:2px solid #dc2626;border-radius:10px;margin-bottom:14px;overflow:hidden">';
    // Header plat
    html += '<div style="background:#dc2626;color:white;padding:8px 12px;font-weight:800;font-size:13px">';
    html += 'Plat N' + (i+1) + ' — ' + plat.nom;
    html += '</div>';
    // Infos
    html += '<table style="width:100%;border-collapse:collapse;font-size:11px">';
    if (plat.qte) html += '<tr><td style="padding:5px 10px;border-bottom:1px solid #fee2e2;width:45%;font-weight:600">Quantite</td><td style="padding:5px 10px;border-bottom:1px solid #fee2e2">' + plat.qte + '</td></tr>';
    if (plat.mode) html += '<tr><td style="padding:5px 10px;border-bottom:1px solid #fee2e2;font-weight:600">Mode de cuisson</td><td style="padding:5px 10px;border-bottom:1px solid #fee2e2">' + plat.mode + '</td></tr>';
    html += '<tr><td style="padding:5px 10px;border-bottom:1px solid #fee2e2;font-weight:600">Type produit</td><td style="padding:5px 10px;border-bottom:1px solid #fee2e2">' + plat.type + '</td></tr>';
    // Temperature cuisson
    html += '<tr style="background:#fff8f8"><td colspan="2" style="padding:6px 10px;border-bottom:1px solid #fee2e2;font-weight:800;color:#dc2626;font-size:11px">Temperature a coeur</td></tr>';
    html += '<tr><td style="padding:5px 10px;border-bottom:1px solid #fee2e2;font-weight:600">T° mesuree</td><td style="padding:5px 10px;border-bottom:1px solid #fee2e2">' + (plat.temp ? plat.temp + '°C' : '—') + (plat.temp ? ' <span style="color:#0891b2;font-weight:600;font-size:9px">(seuil : ' + (function(){ var pp=String(plat.type||'').toLowerCase(); if(pp.indexOf('volaille')>-1||pp.indexOf('poulet')>-1||pp.indexOf('dinde')>-1)return '74°C min à cœur'; if(pp.indexOf('hach')>-1)return '70°C min à cœur'; return '63°C min à cœur'; })() + ')</span>' : '') + '</td></tr>';
    var confColor = plat.isNC ? '#dc2626' : '#16a34a';
    html += '<tr><td style="padding:5px 10px;' + (plat.isNC?'border-bottom:1px solid #fee2e2;':'') + 'font-weight:600">Conformite</td><td style="padding:5px 10px;' + (plat.isNC?'border-bottom:1px solid #fee2e2;':'') + 'color:' + confColor + ';font-weight:700">' + plat.conf + '</td></tr>';
    if (plat.isNC) html += '<tr style="background:#fff0f0"><td style="padding:5px 10px;color:#dc2626;font-weight:700' + (plat.remiseT0?';border-bottom:1px solid #fee2e2':'') + '">Action corrective</td><td style="padding:5px 10px;color:#dc2626;font-weight:700' + (plat.remiseT0?';border-bottom:1px solid #fee2e2':'') + '">' + (plat.action||'A definir') + '</td></tr>';
    // Remise en temperature
    if (plat.remiseT0 || plat.remiseTf) {
      html += '<tr style="background:#fff8f8"><td colspan="2" style="padding:6px 10px;border-top:1px solid #fee2e2;border-bottom:1px solid #fee2e2;font-weight:800;color:#dc2626;font-size:11px">Remise en temperature</td></tr>';
      html += '<tr><td style="padding:5px 10px;border-bottom:1px solid #fee2e2;font-weight:600">T° initiale</td><td style="padding:5px 10px;border-bottom:1px solid #fee2e2">' + (plat.remiseT0 ? plat.remiseT0 + '°C' : '—') + '</td></tr>';
      html += '<tr><td style="padding:5px 10px;border-bottom:1px solid #fee2e2;font-weight:600">T° finale</td><td style="padding:5px 10px;border-bottom:1px solid #fee2e2">' + (plat.remiseTf ? plat.remiseTf + '°C' : '—') + '</td></tr>';
      var remiseConfColor = plat.isRemiseNC ? '#dc2626' : '#16a34a';
      html += '<tr><td style="padding:5px 10px;font-weight:600">Conformite</td><td style="padding:5px 10px;color:' + remiseConfColor + ';font-weight:700">' + (plat.remiseConf||'—') + '</td></tr>';
      if (plat.isRemiseNC) html += '<tr style="background:#fff0f0"><td style="padding:5px 10px;color:#dc2626;font-weight:700">Action corrective</td><td style="padding:5px 10px;color:#dc2626;font-weight:700">' + (plat.remiseAction||'A definir') + '</td></tr>';
    }
    html += '</table></div>';
  });

  html += '<div style="font-size:8pt;color:#9ca3af;text-align:center;margin-top:16px;border-top:1px solid #e5e7eb;padding-top:8px">HACCP Pro — À conserver par vos soins 3 ans minimum — Preuve légale en cas de contrôle DDPP</div>';
  html += '</div>';

  var existing = document.getElementById('printOverlay');
  if (existing) existing.remove();
  var overlay = document.createElement('div');
  overlay.id = 'printOverlay';
  overlay.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:white;z-index:99999;overflow-y:auto;-webkit-overflow-scrolling:touch';
  var tb = document.createElement('div');
  tb.className = 'no-print';
  tb.style.cssText = 'background:#dc2626;padding:10px 16px;display:flex;justify-content:space-between;align-items:center;position:sticky;top:0;z-index:1';
  var tbTitle = document.createElement('div');
  tbTitle.style.cssText = 'color:white;font-weight:800;font-size:13px';
  tbTitle.textContent = 'Cuisson — ' + filled.length + ' plat(s)';
  var tbBtns = document.createElement('div');
  tbBtns.style.cssText = 'display:flex;gap:8px';
  var btnImpr = document.createElement('button');
  btnImpr.textContent = 'Imprimer';
  btnImpr.style.cssText = 'background:#10b981;color:white;border:none;border-radius:8px;padding:8px 14px;font-weight:700;cursor:pointer;font-size:12px';
  btnImpr.onclick = function() { window.print(); };
  var btnFerm = document.createElement('button');
  btnFerm.textContent = 'Fermer';
  btnFerm.style.cssText = 'background:#374151;color:white;border:none;border-radius:8px;padding:8px 14px;font-weight:700;cursor:pointer;font-size:12px';
  btnFerm.onclick = function() { var el = document.getElementById('printOverlay'); if (el) el.remove(); };
  tbBtns.appendChild(btnImpr); tbBtns.appendChild(btnFerm);
  tb.appendChild(tbTitle); tb.appendChild(tbBtns);
  var ct = document.createElement('div');
  ct.innerHTML = html;
  overlay.appendChild(tb); overlay.appendChild(ct);
  document.body.appendChild(overlay);
  overlay.scrollTop = 0;
}

