function imprimerTemperatures(dataOverride, signataireOverride, tsOverride) {
  var enceintes = (dataOverride && Array.isArray(dataOverride)) ? dataOverride : collecterDonneesTemperatures();
  var sigPrenom = document.getElementById('temp_sig_prenom');
  var sigNom = document.getElementById('temp_sig_nom');
  var signataire = signataireOverride || (sigPrenom && sigNom ? (sigPrenom.value + ' ' + sigNom.value).trim() : '—');
  var filled = enceintes.filter(function(e){ return e.temp || e.type !== '—'; });
  if (filled.length === 0) { showToast('Aucune enceinte saisie', 'warn'); return; }
  var ncCount = filled.filter(function(e){ return e.isNC; }).length;
  var html = '<div style="padding:0 16px 20px;font-family:Arial,sans-serif">';
  html += '<div style="background:linear-gradient(135deg,#0891b2,#22d3ee);color:white;padding:14px 16px;border-radius:10px;margin-bottom:14px">';
  html += '<div style="font-weight:800;font-size:15px">Temperatures Enceintes Froides</div>';
  html += '<div style="font-size:11px;opacity:.85;margin-top:4px">' + _echap(ETAB.nom||'') + ' — ' + (tsOverride || getNowStr()) + '</div>';
  html += '<div style="font-size:11px;opacity:.85">Émargement : ' + (signataire || '—') + '</div>';
  html += '<div style="font-size:11px;opacity:.85">Secteur : ' + (((typeof SECTEURS_CONFIG!=='undefined' && SECTEURS_CONFIG[SECTEUR_ACTIF] && SECTEURS_CONFIG[SECTEUR_ACTIF].label)) || SECTEUR_ACTIF || '—') + '</div>';
  if (ncCount > 0) html += '<div style="margin-top:6px;background:rgba(220,38,38,.3);border-radius:6px;padding:4px 8px;font-size:11px;font-weight:700">' + ncCount + ' non-conformite(s)</div>';
  html += '</div>';
  filled.forEach(function(enc, i) {
    var borderColor = enc.isNC ? '#dc2626' : '#0891b2';
    var confColor = enc.isNC ? '#dc2626' : '#16a34a';
    var seuilTxt = seuilEnceinteDepuisLabel(String(enc.type||'')+' '+String(enc.precision||'')) || '—';
    html += '<div style="border:2px solid ' + borderColor + ';border-radius:10px;margin-bottom:12px;overflow:hidden">';
    html += '<div style="background:' + borderColor + ';color:white;padding:8px 12px;display:flex;justify-content:space-between">';
    var encLabel = 'Enceinte N' + (i+1);
    if (enc.precision) encLabel += ' — ' + enc.precision;
    if (enc.refNum) encLabel += ' (Ref: ' + enc.refNum + ')';
    html += '<span style="font-weight:800;font-size:13px">' + encLabel + '</span>';
    if (enc.isNC) html += '<span style="font-size:11px;font-weight:700">NC</span>';
    html += '</div>';
    html += '<table style="width:100%;border-collapse:collapse;font-size:10pt">';
    html += '<tr><td style="padding:6px 10px;border-bottom:1px solid #e5e7eb;width:40%;font-weight:600">Type</td><td style="padding:6px 10px;border-bottom:1px solid #e5e7eb">' + enc.type + '</td></tr>';
    html += '<tr><td style="padding:6px 10px;border-bottom:1px solid #e5e7eb;font-weight:600">T relevee</td><td style="padding:6px 10px;border-bottom:1px solid #e5e7eb">' + (enc.temp ? enc.temp + '°C' : '—') + (seuilTxt && seuilTxt !== '—' ? ' <span style="color:#0891b2;font-weight:600;font-size:9px">(seuil : ' + seuilTxt + ')</span>' : '') + '</td></tr>';
    html += '<tr><td style="padding:6px 10px;' + (enc.isNC?'border-bottom:1px solid #e5e7eb;':'') + 'font-weight:600">Conformite</td><td style="padding:6px 10px;' + (enc.isNC?'border-bottom:1px solid #e5e7eb;':'') + 'color:' + confColor + ';font-weight:700">' + enc.conf + '</td></tr>';
    if (enc.isNC) html += '<tr style="background:#fff8f8"><td style="padding:6px 10px;color:#dc2626;font-weight:700">Action corrective</td><td style="padding:6px 10px;color:#dc2626;font-weight:700">' + (enc.action||'A definir') + '</td></tr>';
    html += '</table></div>';
  });
  html += '<div style="font-size:8pt;color:#9ca3af;text-align:center;margin-top:16px;border-top:1px solid #e5e7eb;padding-top:8px">HACCP Pro — À conserver par vos soins 3 ans minimum — Preuve légale en cas de contrôle DDPP</div>';
  html += '</div>';
  var existing = document.getElementById('printOverlay');
  if (existing) existing.remove();
  var overlay = document.createElement('div');
  overlay.id = 'printOverlay';
  overlay.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:white;z-index:99999;overflow-y:auto;-webkit-overflow-scrolling:touch';
  var tb = document.createElement('div');
  tb.className = 'no-print';
  tb.style.cssText = 'background:#0891b2;padding:10px 16px;display:flex;justify-content:space-between;align-items:center;position:sticky;top:0;z-index:1';
  var tbTitle = document.createElement('div');
  tbTitle.style.cssText = 'color:white;font-weight:800;font-size:13px';
  tbTitle.textContent = 'Temperatures — ' + filled.length + ' enceinte(s)';
  var tbBtns = document.createElement('div');
  tbBtns.style.cssText = 'display:flex;gap:8px';
  var btnImpr = document.createElement('button');
  btnImpr.textContent = 'Imprimer';
  btnImpr.style.cssText = 'background:#10b981;color:white;border:none;border-radius:8px;padding:8px 14px;font-weight:700;cursor:pointer;font-size:12px';
  btnImpr.onclick = function() { window.print(); };
  var btnFerm = document.createElement('button');
  btnFerm.textContent = 'Fermer';
  btnFerm.style.cssText = 'background:#dc2626;color:white;border:none;border-radius:8px;padding:8px 14px;font-weight:700;cursor:pointer;font-size:12px';
  btnFerm.onclick = function() { var el = document.getElementById('printOverlay'); if (el) el.remove(); };
  tbBtns.appendChild(btnImpr); tbBtns.appendChild(btnFerm);
  tb.appendChild(tbTitle); tb.appendChild(tbBtns);
  var ct = document.createElement('div');
  ct.innerHTML = html;
  overlay.appendChild(tb); overlay.appendChild(ct);
  document.body.appendChild(overlay);
  overlay.scrollTop = 0;
}

function fermerPrintOverlay() { var el = document.getElementById('printOverlay'); if (el) el.remove(); }
function imprimerModule(pageId, titre) {
  // V80 — Si le module a des blocs (.fblock), utiliser le format "1 bloc/section"
  var page = document.getElementById(pageId);
  if (page) {
    // Cas 1 : blocs répétables (ID terminant par _<num>) — Réception, Cuisson, etc.
    var blocsRepetes = [];
    page.querySelectorAll(':scope .fblock[id]').forEach(function(b) {
      if (/_\d+$/.test(b.id || '')) blocsRepetes.push(b);
    });
    if (blocsRepetes.length > 0) {
      return imprimerModuleParBloc(pageId, titre, blocsRepetes, 'repete');
    }
    // Cas 2 : blocs thématiques avec titre (.fblock > .fblock-title) — Hygiène, Documents, Ouverture, NC, etc.
    var blocsThematiques = [];
    page.querySelectorAll(':scope .fblock').forEach(function(b) {
      var t = b.querySelector('.fblock-title');
      if (t) blocsThematiques.push(b);
    });
    if (blocsThematiques.length > 0) {
      return imprimerModuleParBloc(pageId, titre, blocsThematiques, 'thematique');
    }
  }
  // Sinon, ancien format générique (très rares modules sans blocs)
  return imprimerModuleAplat(pageId, titre);
}

// V80 — PDF "1 bloc par élément" : un bloc visuel séparé avec bandeau coloré, identification, mesures, actions correctives, bilan élément
// type = 'repete' (Produit N°1, Plat N°2…) | 'thematique' (Tenue, Bijoux, Mains…)
function genererRapportParBlocHTML(pageId, titre, blocs, type) {
  type = type || 'repete';
  var data = collectPageDataUniversel(pageId);
  if (!data) { return ''; }

  var css = '<style>' +
    'body{font-family:Arial,sans-serif;font-size:12px;color:#111;margin:0;padding:0}' +
    '.header{background:#1e1b4b;color:white;padding:14px 20px;margin-bottom:16px}' +
    '.header h2{margin:0 0 4px;font-size:15px}' +
    '.header .meta{font-size:11px;opacity:.85;margin-top:3px}' +
    '.section-title{font-size:13px;font-weight:800;color:#1e1b4b;margin:18px 0 10px;padding-bottom:4px;border-bottom:2px solid #1e1b4b}' +
    '.bilan-global{background:#f0f9ff;border:2px solid #0ea5e9;border-radius:8px;padding:10px 14px;margin-bottom:14px;font-size:12px;font-weight:700;color:#075985}' +
    '.element-block{border:2px solid #e5e7eb;border-radius:10px;margin-bottom:14px;page-break-inside:avoid;overflow:hidden}' +
    '.element-block.bloc-nc{border-color:#dc2626}' +
    '.element-block.bloc-ok{border-color:#16a34a}' +
    '.bandeau{padding:8px 14px;font-weight:800;color:white;font-size:13px;display:flex;justify-content:space-between;align-items:center}' +
    '.bandeau.ok{background:#16a34a}' +
    '.bandeau.nc{background:#dc2626}' +
    '.bandeau.na{background:#6b7280}' +
    '.element-body{padding:10px 14px;background:white}' +
    '.bloc-section{margin-bottom:10px}' +
    '.bloc-section-title{font-size:11px;font-weight:800;color:#374151;text-transform:uppercase;letter-spacing:.5px;margin-bottom:5px;padding-bottom:3px;border-bottom:1px dashed #e5e7eb}' +
    '.bloc-table{width:100%;border-collapse:collapse;font-size:11px}' +
    '.bloc-table td{padding:5px 8px;border:1px solid #f3f4f6;vertical-align:top}' +
    '.bloc-table td:first-child{width:40%;font-weight:600;color:#6b7280}' +
    '.bloc-table .ok{color:#16a34a;font-weight:700}' +
    '.bloc-table .nc{color:#dc2626;font-weight:700;background:#fff8f8}' +
    '.action-block{margin-top:8px;padding:8px 12px;background:#fffbeb;border-left:3px solid #f59e0b;border-radius:4px}' +
    '.action-block-title{font-size:11px;font-weight:800;color:#92400e;margin-bottom:5px}' +
    '.action-row{display:grid;grid-template-columns:1fr 2fr;gap:6px 12px;font-size:11px;margin-bottom:3px}' +
    '.action-row .lbl{color:#78350f;font-weight:700}' +
    '.bilan-element{margin-top:8px;padding:6px 10px;border-radius:4px;font-size:11px;font-weight:700}' +
    '.bilan-element.ok{background:#dcfce7;color:#166534}' +
    '.bilan-element.nc{background:#fee2e2;color:#991b1b}' +
    '.footer{font-size:9px;color:#9ca3af;text-align:center;margin-top:16px;border-top:1px solid #e5e7eb;padding-top:8px}' +
    '@media print{' +
      '.no-print{display:none!important}' +
      'body>*:not(#printOverlay){display:none!important}' +
      '#printOverlay{position:static!important;overflow:visible!important}' +
      '#printOverlay>div:first-child{display:none!important}' +
      '.element-block{break-inside:avoid;page-break-inside:avoid}' +
    '}' +
  '</style>';

  var html = css + '<div style="padding:0 20px 20px">';
  // En-tête
  html += '<div class="header">';
  html += '<h2>' + (titre||data.module||pageId) + '</h2>';
  html += '<div class="meta">Date : ' + data.timestamp + ' | Opérateur : ' + (data.signe||'Non renseigné') + '</div>';
  html += '<div class="meta">' + data.etab + ' | Secteur : ' + (((typeof SECTEURS_CONFIG!=='undefined' && SECTEURS_CONFIG[data.secteur] && SECTEURS_CONFIG[data.secteur].label)) || data.secteur || '—') + '</div>';
  html += '</div>';

  // Bilan global (adapté au type)
  var nbTotal = blocs.length;
  var nbNC = 0;
  blocs.forEach(function(b) {
    var hasBad = b.querySelector('.status-btn.active-bad') ||
                 (b.textContent && b.textContent.indexOf('❌') > -1) ||
                 (b.querySelector('.conformite-badge.bad'));
    if (hasBad) nbNC++;
  });
  var nbOK = nbTotal - nbNC;
  var motElem = type === 'thematique' ? 'section' : 'élément';
  html += '<div class="bilan-global">📊 Bilan : ' + nbTotal + ' ' + motElem + (nbTotal>1?'s':'') + ' contrôlé' + (nbTotal>1?'s':'') + ' — <span style="color:#16a34a">✅ ' + nbOK + ' conforme' + (nbOK>1?'s':'') + '</span> | <span style="color:#dc2626">❌ ' + nbNC + ' non conforme' + (nbNC>1?'s':'') + '</span></div>';

  html += '<div class="section-title">' + (type === 'thematique' ? 'Détail par section' : 'Détail des contrôles') + '</div>';

  // Pour chaque bloc, générer un bloc PDF séparé
  blocs.forEach(function(bloc, idx) {
    var titreBloc = (bloc.querySelector('.fblock-title span') || bloc.querySelector('.fblock-title') || bloc.querySelector(':scope > div')).textContent.trim();
    titreBloc = titreBloc.replace(/✕/g, '').replace(/✅ Tout conforme/g, '').trim();
    var hasBad = bloc.querySelector('.status-btn.active-bad') ||
                 bloc.querySelector('.conformite-badge.bad') ||
                 (bloc.textContent && bloc.textContent.indexOf('❌') > -1);
    var bandClass = hasBad ? 'nc' : 'ok';
    var bandLabel = hasBad ? '❌ NON CONFORME' : '✅ CONFORME';
    html += '<div class="element-block bloc-' + bandClass + '">';
    html += '<div class="bandeau ' + bandClass + '"><span>' + titreBloc + '</span><span>' + bandLabel + '</span></div>';
    html += '<div class="element-body">';

    // Identification : tous les inputs/selects avec valeur dans ce bloc
    var idents = [];
    var mesures = [];
    var inputs = bloc.querySelectorAll('input, select, textarea');
    inputs.forEach(function(inp) {
      // Skip inputs cachés ou dans nc-action
      if (inp.closest && inp.closest('.nc-action')) return;
      if (inp.type === 'hidden' || inp.type === 'checkbox' || inp.type === 'radio' || inp.type === 'button') return;
      var v = inp.value || '';
      if (!v) return;
      var lbl = '';
      // Trouver le label associé
      var fr = inp.closest('.frow');
      if (fr) {
        var lblEl = fr.querySelector('.flabel');
        if (lblEl) lbl = lblEl.textContent.trim().replace(/[★⚠️🔴⚡*]/g,'').trim();
      }
      if (!lbl) lbl = inp.placeholder || inp.id;
      // Pour les select : prendre le texte de l'option
      if (inp.tagName === 'SELECT' && inp.selectedIndex > 0) {
        v = inp.options[inp.selectedIndex].text;
      }
      // Distinguer mesures (T°, qty, etc) vs identification
      var isMesure = /^(\d+|\+\d|-\d|\d+\.\d+)/.test(v) || /°C|kg|g|min|h|%|L|ml/.test(v);
      if (isMesure) mesures.push({label:lbl, valeur:v});
      else idents.push({label:lbl, valeur:v});
    });

    // V117 — capter aussi les seuils affichés (encadrés, maxima) pour qu'ils figurent dans le PDF
    try {
      bloc.querySelectorAll('[id*="seuil"]').forEach(function(se) {
        if (se.tagName === 'INPUT' || se.tagName === 'SELECT' || se.tagName === 'TEXTAREA') return;
        if (se.children && se.children.length) return;
        var sv = (se.textContent || '').trim();
        if (!sv || sv === '—' || sv.length > 40) return;
        if (!/°c|%|min|max|≤|≥|\d/i.test(sv)) return;
        mesures.push({ label: 'Seuil réglementaire', valeur: sv });
      });
      bloc.querySelectorAll('div').forEach(function(dv) {
        if (dv.children && dv.children.length) return;
        var tv = (dv.textContent || '').trim();
        if (/^Max\s+[\d+\-]/.test(tv) && tv.length < 25) mesures.push({ label: 'Seuil', valeur: tv });
      });
    } catch(e){}

    // Section Identification
    if (idents.length > 0) {
      html += '<div class="bloc-section">';
      html += '<div class="bloc-section-title">📋 Identification</div>';
      html += '<table class="bloc-table">';
      idents.forEach(function(f) {
        html += '<tr><td>' + _echap(f.label) + '</td><td>' + _echap(f.valeur) + '</td></tr>';
      });
      html += '</table></div>';
    }

    // V80 — Photos du bloc (étiquettes, BL, preuves)
    var photos = bloc.querySelectorAll('img.photo-preview, img[src^="data:image"]');
    var photosValides = [];
    photos.forEach(function(img) {
      if (img.src && img.src.indexOf('data:image') > -1 && img.src.length > 100) {
        photosValides.push(img.src);
      }
    });
    if (photosValides.length > 0) {
      html += '<div class="bloc-section">';
      html += '<div class="bloc-section-title">📸 Photos</div>';
      html += '<div style="display:flex;gap:8px;flex-wrap:wrap">';
      photosValides.forEach(function(src) {
        html += '<img src="' + src + '" style="max-width:140px;max-height:100px;border:1px solid #e5e7eb;border-radius:6px;object-fit:cover" alt="Photo"/>';
      });
      html += '</div></div>';
    }

    // Section Mesures
    // V113 — A1 : collecter le statut ET son action corrective (sibling nc-action)
    var statutsBloc = [];
    var consumedNcActions = []; // nc-actions déjà affichées dans la table → exclure de l'action-block
    var allFrows = bloc.querySelectorAll('.frow');
    allFrows.forEach(function(row) {
      if (row.closest && row.closest('.nc-action')) return;
      var grp = row.querySelector('.status-group');
      if (!grp) return;
      var lbl = row.querySelector('.flabel');
      if (!lbl) return;
      var label = lbl.textContent.trim().replace(/[★⚠️🔴⚡*]/g,'').trim();
      var okBtn = grp.querySelector('.status-btn.active-ok');
      var warnBtn = grp.querySelector('.status-btn.active-warn');
      var badBtn = grp.querySelector('.status-btn.active-bad');
      if (!okBtn && !warnBtn && !badBtn) return;
      var statut = okBtn ? '✅ Conforme' : (warnBtn ? 'N/A' : '❌ Non conforme');
      var cls = badBtn ? 'nc' : 'ok';
      // V113 — A1 : si NC, chercher l'action corrective dans le sibling nc-action
      var actionTxt = '';
      var constatTxt = '';
      if (badBtn) {
        var sib = row.nextElementSibling;
        while (sib) {
          if (sib.classList && sib.classList.contains('nc-action')) {
            var visible = sib.offsetParent || sib.classList.contains('visible') || sib.style.display === 'block' || sib.style.display === 'flex';
            if (visible) {
              // V-NC16 — cibler explicitement le select/input d'action (classes dédiées)
              var aSel = sib.querySelector('.nc-act-select') || sib.querySelector('select');
              var aDet = sib.querySelector('.nc-act-detail') || sib.querySelector('input[type="text"]:not(.nc-constat-autre)') || sib.querySelector('input[type="text"]');
              var aTyp = (aSel && aSel.selectedIndex > 0) ? aSel.options[aSel.selectedIndex].text : '';
              var aDetV = aDet ? aDet.value : '';
              // V-NC16 — non-conformité constatée (menu déroulant adapté)
              var _cSel = sib.querySelector('.nc-constat-select');
              if (_cSel && _cSel.selectedIndex > 0) {
                var _cT = _cSel.options[_cSel.selectedIndex].text;
                if (/autre/i.test(_cT)) { var _cA = sib.querySelector('.nc-constat-autre'); _cT = (_cA && _cA.value.trim()) ? _cA.value.trim() : _cT; }
                constatTxt = _cT;
              }
              if (aTyp || aDetV) {
                actionTxt = aTyp + (aDetV ? (aTyp ? ' — ' : '') + aDetV : '');
                consumedNcActions.push(sib);
              } else if (constatTxt) {
                consumedNcActions.push(sib);
              }
            }
            break;
          }
          if (sib.classList && (sib.classList.contains('frow') || sib.classList.contains('fblock'))) break;
          sib = sib.nextElementSibling;
        }
      }
      statutsBloc.push({label:label, statut:statut, cls:cls, action:actionTxt, constat:constatTxt});
    });

    if (mesures.length > 0 || statutsBloc.length > 0) {
      html += '<div class="bloc-section">';
      html += '<div class="bloc-section-title">📏 Mesures & Contrôles</div>';
      html += '<table class="bloc-table">';
      // V113 — A1 : entête 3 colonnes pour aligner l'action en face de la NC
      html += '<tr><th style="text-align:left;font-size:11px;color:#6b7280;font-weight:700;padding:4px 8px;background:#f9fafb">Élément</th><th style="text-align:left;font-size:11px;color:#6b7280;font-weight:700;padding:4px 8px;background:#f9fafb">Constat</th><th style="text-align:left;font-size:11px;color:#6b7280;font-weight:700;padding:4px 8px;background:#f9fafb">Action corrective</th></tr>';
      mesures.forEach(function(m) {
        html += '<tr><td>' + _echap(m.label) + '</td><td><strong>' + _echap(m.valeur) + '</strong></td><td style="color:#9ca3af">—</td></tr>';
      });
      statutsBloc.forEach(function(s) {
        var actCell = s.action ? '<td style="color:#c2410c;font-weight:600">' + _echap(s.action) + '</td>' : '<td style="color:#9ca3af">—</td>';
        // V-NC16 — afficher la non-conformité constatée précise sous le statut
        var statutCell = _echap(s.statut) + (s.constat ? '<div style="font-size:10px;font-weight:600;margin-top:1px">' + _echap(s.constat) + '</div>' : '');
        html += '<tr><td>' + _echap(s.label) + '</td><td class="' + s.cls + '">' + statutCell + '</td>' + actCell + '</tr>';
      });
      var confEl = bloc.querySelector('.conformite-badge');
      if (confEl && confEl.textContent.trim() && confEl.textContent.indexOf('Saisissez') === -1 && confEl.textContent.indexOf('Sélectionnez') === -1) {
        var confTxt = confEl.textContent.trim();
        var confCls = confEl.classList.contains('bad') ? 'nc' : (confEl.classList.contains('ok') ? 'ok' : '');
        html += '<tr><td>Conformité</td><td class="' + confCls + '">' + confTxt + '</td><td style="color:#9ca3af">—</td></tr>';
      }
      html += '</table></div>';
    }

    // Actions correctives DANS le bloc
    // V113 — A1 : on n'affiche ici QUE les nc-actions non déjà rendues dans la table (cas nc-auto bandeau)
    var ncActions = bloc.querySelectorAll('.nc-action');
    var actionsAffichees = false;
    // V113 — A1/A2 : suivre si AU MOINS une action est visible (table OU bloc) pour le bandeau bilan
    var auMoinsUneActionRemplie = (consumedNcActions.length > 0);
    ncActions.forEach(function(nca) {
      if (nca.style.display === 'none') return;
      if (consumedNcActions.indexOf(nca) !== -1) return; // déjà dans la table
      var sel = nca.querySelector('.nc-act-select') || nca.querySelector('select');
      var detailEl = nca.querySelector('.nc-act-detail') || nca.querySelector('input[type="text"]:not(.nc-constat-autre)') || nca.querySelector('input[type="text"]');
      var respEl = nca.querySelector('input[id*="resp"]');
      var heureEl = nca.querySelector('input[type="time"]');
      var typeVal = (sel && sel.selectedIndex > 0) ? sel.options[sel.selectedIndex].text : '';
      var detailVal = detailEl ? detailEl.value : '';
      var respVal = respEl ? respEl.value : '';
      var heureVal = heureEl ? heureEl.value : '';
      if (!typeVal && !detailVal && !respVal) return;
      if (!actionsAffichees) {
        html += '<div class="action-block">';
        html += '<div class="action-block-title">🛠️ Action corrective</div>';
        actionsAffichees = true;
      }
      auMoinsUneActionRemplie = true;
      if (typeVal) html += '<div class="action-row"><div class="lbl">Action</div><div>' + _echap(typeVal) + '</div></div>';
      if (detailVal) html += '<div class="action-row"><div class="lbl">Précisions</div><div>' + _echap(detailVal) + '</div></div>';
      if (respVal) html += '<div class="action-row"><div class="lbl">Responsable</div><div>' + _echap(respVal) + '</div></div>';
      if (heureVal) html += '<div class="action-row"><div class="lbl">Heure</div><div>' + _echap(heureVal) + '</div></div>';
    });
    if (actionsAffichees) html += '</div>';

    // Bilan élément (adapté au type)
    // V113 — A2 : "enregistrée" si une action a été affichée (table OU bloc), "à enregistrer" sinon
    var bilanCls = hasBad ? 'nc' : 'ok';
    var bilanTxt;
    var bilanActionTxt = auMoinsUneActionRemplie ? 'action corrective enregistrée' : 'action corrective à enregistrer';
    if (type === 'thematique') {
      bilanTxt = hasBad ? ('❌ Non conforme — ' + bilanActionTxt) : '✅ Section conforme aux exigences HACCP';
    } else {
      bilanTxt = hasBad ? ('❌ Non conforme — ' + bilanActionTxt) : '✅ Élément conforme aux exigences HACCP';
    }
    html += '<div class="bilan-element ' + bilanCls + '">' + bilanTxt + '</div>';

    html += '</div></div>'; // /element-body /element-block
  });

  // Observations globales
  if (data.observations.length > 0) {
    html += '<div class="section-title">📝 Observations</div>';
    html += '<table class="bloc-table">';
    data.observations.forEach(function(obs) {
      html += '<tr><td>' + _echap(obs.label) + '</td><td>' + _echap(obs.valeur) + '</td></tr>';
    });
    html += '</table>';
  }

  html += '<div class="footer">HACCP Pro — À conserver par vos soins 3 ans minimum — Preuve légale en cas de contrôle DDPP</div>';
  html += '</div>';

  return html;
}

function imprimerModuleParBloc(pageId, titre, blocs, type) {
  var html = genererRapportParBlocHTML(pageId, titre, blocs, type);
  if (!html) { showToast('Erreur collecte', 'err'); return; }
  afficherRapportOverlay(html, titre);
}

function afficherRapportOverlay(html, titre) {
  // Overlay (réutilise le même mécanisme)
  var existing = document.getElementById('printOverlay');
  if (existing) existing.remove();
  var overlay = document.createElement('div');
  overlay.id = 'printOverlay';
  overlay.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:white;z-index:99999;overflow:auto;box-sizing:border-box';
  var _tb = document.createElement('div');
  _tb.className = 'no-print';
  _tb.style.cssText = 'background:#1e1b4b;padding:10px 16px;display:flex;justify-content:space-between;align-items:center;position:sticky;top:0;z-index:1';
  var _tbT = document.createElement('div');
  _tbT.style.cssText = 'color:white;font-weight:800;font-size:13px';
  _tbT.textContent = titre || 'Contrôle';
  var _tbB = document.createElement('div');
  _tbB.style.cssText = 'display:flex;gap:8px';
  var _bI = document.createElement('button');
  _bI.textContent = 'Imprimer';
  _bI.style.cssText = 'background:#10b981;color:white;border:none;border-radius:8px;padding:8px 14px;font-weight:700;cursor:pointer;font-size:12px';
  _bI.onclick = function() { window.print(); };
  var _bF = document.createElement('button');
  _bF.textContent = 'Fermer';
  _bF.style.cssText = 'background:#dc2626;color:white;border:none;border-radius:8px;padding:8px 14px;font-weight:700;cursor:pointer;font-size:12px';
  _bF.onclick = function() { fermerPrintOverlay(); };
  _tbB.appendChild(_bI); _tbB.appendChild(_bF);
  _tb.appendChild(_tbT); _tb.appendChild(_tbB);
  var _ios = document.createElement('div');
  _ios.className = 'no-print';
  _ios.style.cssText = 'background:#fef3c7;border-bottom:2px solid #fcd34d;padding:8px 16px;font-size:11px;color:#92400e;font-weight:600;text-align:center';
  _ios.textContent = 'Sur iPhone/iPad : bouton Partager du navigateur → Imprimer';
  var _ct = document.createElement('div');
  _ct.innerHTML = html;
  overlay.appendChild(_tb);
  overlay.appendChild(_ios);
  overlay.appendChild(_ct);
  document.body.appendChild(overlay);
  overlay.scrollTop = 0;
}

function imprimerModuleAplat(pageId, titre, dataOverride) {
  var data = dataOverride || collectPageDataUniversel(pageId);
  if (!data) { showToast('Erreur collecte', 'err'); return; }

  var css = '<style>' +
    'body{font-family:Arial,sans-serif;font-size:12px;color:#111;margin:0;padding:0}' +
    '.header{background:#1e1b4b;color:white;padding:14px 20px;margin-bottom:16px}' +
    '.header h2{margin:0 0 4px;font-size:15px}' +
    '.header .meta{font-size:11px;opacity:.85;margin-top:3px}' +
    '.section-title{font-size:12px;font-weight:700;color:#1e1b4b;border-bottom:2px solid #1e1b4b;' +
      'padding-bottom:3px;margin:14px 0 6px}' +
    'table{width:100%;border-collapse:collapse;margin-bottom:12px;font-size:11px}' +
    'th{background:#1e1b4b;color:white;padding:6px 8px;text-align:left;font-weight:700}' +
    'td{padding:5px 8px;border:1px solid #e5e7eb;vertical-align:top}' +
    'tr:nth-child(even) td{background:#f8f8fc}' +
    '.ok{color:#16a34a;font-weight:700}' +
    '.nc{color:#dc2626;font-weight:700;background:#fff8f8!important}' +
    '.na{color:#6b7280}' +
    '.action-cell{color:#92400e;font-weight:600}' +
    '.footer{font-size:9px;color:#9ca3af;text-align:center;margin-top:16px;border-top:1px solid #e5e7eb;padding-top:8px}' +
    '@media print{' +
      '.no-print{display:none!important}' +
      'body>*:not(#printOverlay){display:none!important}' +
      '#printOverlay{position:static!important;overflow:visible!important}' +
      '#printOverlay>div:first-child{display:none!important}' +
    '}' +
  '</style>';

  var html = css + '<div style="padding:0 20px 20px">';

  // En-tête
  html += '<div class="header">';
  html += '<h2>' + _echap(titre||data.module||pageId) + '</h2>';
  html += '<div class="meta">Date : ' + _echap(data.timestamp) + ' | Opérateur : ' + _echap(data.signe||'Non renseigné') + '</div>';
  html += '<div class="meta">' + _echap(data.etab) + ' | Secteur : ' + (((typeof SECTEURS_CONFIG!=='undefined' && SECTEURS_CONFIG[data.secteur] && SECTEURS_CONFIG[data.secteur].label)) || data.secteur || '—') + '</div>';
  html += '</div>';

  // 1. Informations saisies
  if (data.champs.length > 0) {
    html += '<div class="section-title">Informations saisies (' + data.champs.length + ')</div>';
    html += '<table><tr><th style="width:40%">Champ</th><th>Valeur</th></tr>';
    data.champs.forEach(function(f) {
      html += '<tr><td><strong>' + f.label + '</strong></td><td>' + f.valeur + '</td></tr>';
    });
    html += '</table>';
  }

  // 1b. Lots + Photos
  if (data.lots && data.lots.length > 0) {
    html += '<div class="section-title">N° de lot & Photos étiquettes</div>';
    html += '<table><tr><th style="width:35%">Produit</th><th style="width:30%">N° Lot</th><th>Photo</th></tr>';
    (data.lots||[]).forEach(function(l) {
      var photo = (data.photos||[]).find(function(p){ return p.id === l.id; });
      html += '<tr><td>' + (l.produit||'Produit') + '</td><td><strong>' + (l.lot||'—') + '</strong></td>';
      if (photo && photo.src) {
        html += '<td><img src="' + photo.src + '" alt="Photo étiquette produit" style="max-height:50px;max-width:80px;border:1px solid #e5e7eb"/></td></tr>';
      } else {
        html += '<td style="color:#9ca3af;font-size:11px">Pas de photo</td></tr>';
      }
    });
    html += '</table>';
  }

  // 2. Contrôles
  if (data.statuts.length > 0) {
    var conformes = data.statuts.filter(function(s){ return s.statut==='Conforme'; }).length;
    var pct = Math.round(conformes/data.statuts.length*100);
    html += '<div class="section-title">Controles effectues — ' + pct + '% conformes (' + conformes + '/' + data.statuts.length + ')</div>';
    html += '<table style="table-layout:fixed;width:100%;border-collapse:collapse"><tr>' +
    '<th style="width:52%;padding:6px 8px;border:2px solid #1e1b4b;background:#1e1b4b;color:white;text-align:left">Controle</th>' +
    '<th style="width:13%;padding:6px 8px;border:2px solid #1e1b4b;background:#1e1b4b;color:white;text-align:center">Resultat</th>' +
    '<th style="width:35%;padding:6px 8px;border:2px solid #1e1b4b;background:#1e1b4b;color:white">Action corrective</th>' +
    '</tr>';
    var actIdx2 = data.actions.slice();
    var pageElForRecap = dataOverride ? null : document.getElementById(pageId);
    data.statuts.forEach(function(s) {
      var cls, ico;
      if (s.nc) { cls = 'nc'; ico = '❌'; }
      else if (s.statut === 'N/A') { cls = 'na'; ico = 'N/A'; }
      else if (s.statut === 'Conforme') { cls = 'ok'; ico = '✅'; }
      else { cls = 'na'; ico = '—'; } // Non renseigné
      var actionTxt = '—';
      if (s.nc) {
        var found = null;
        // PRIORITÉ : action attachée au statut (lien fiable établi à la
        // sauvegarde) — évite tout matching par position/ordre erroné.
        if (s.action && typeof s.action === 'object' && (s.action.type || s.action.detail)) {
          found = { type: s.action.type || '', detail: s.action.detail || '', responsable: s.action.responsable || '', heure: s.action.heure || '' };
        }
        // ═══ recherche DOM directe (comme dans le récap NC) ═══
        if (!found && pageElForRecap) {
          var allRows = pageElForRecap.querySelectorAll('.frow');
          for (var ri = 0; ri < allRows.length; ri++) {
            var row = allRows[ri];
            var lbl = row.querySelector('.flabel');
            if (!lbl) continue;
            var rowLabel = lbl.textContent.trim().replace(/[⚠️🔴⚡*]/g,'').trim();
            if (rowLabel === s.label) {
              // Cas Fermeture : pt_action_X à l'intérieur du frow
              var ptActionImp = row.querySelector('[id^="pt_action_"]');
              if (ptActionImp) {
                var ptGroupImp = ptActionImp.querySelector('.status-group');
                if (ptGroupImp) {
                  var ptActiveBtnImp = ptGroupImp.querySelector('.active-ok, .active-warn, .active-bad');
                  if (ptActiveBtnImp) {
                    var ptTextImp = ptActiveBtnImp.textContent.trim().replace(/[✅✗⚠️🚨]/g,'').trim();
                    if (ptTextImp) {
                      found = { type: ptTextImp, detail: '', responsable:'', heure:'' };
                      break;
                    }
                  }
                }
              }
              // Chercher la nc-action sibling
              var sib = row.nextElementSibling;
              while (sib) {
                if (sib.classList && sib.classList.contains('nc-action')) {
                  var sel = sib.querySelector('.nc-act-select') || sib.querySelector('select');
                  var detailEl = sib.querySelector('.nc-act-detail') || sib.querySelector('input[type="text"]:not(.nc-constat-autre)') || sib.querySelector('input[type="text"]');
                  var respEl = sib.querySelector('input[id*="resp"]');
                  var heureEl = sib.querySelector('input[type="time"]');
                  var typeVal = (sel && sel.selectedIndex > 0) ? sel.options[sel.selectedIndex].text : '';
                  var detailVal = detailEl ? detailEl.value : '';
                  var respVal = respEl ? respEl.value : '';
                  var heureVal = heureEl ? heureEl.value : '';
                  if (typeVal || detailVal || respVal) {
                    found = { type:typeVal, detail:detailVal, responsable:respVal, heure:heureVal };
                  }
                  break;
                }
                if (sib.classList && (sib.classList.contains('frow') || sib.classList.contains('fblock'))) break;
                sib = sib.nextElementSibling;
              }
              break;
            }
          }
        }
        // Fallback : ancienne logique de matching par contexte
        if (!found) {
          var lk = s.label.toLowerCase().substring(0,12);
          for (var ai=0; ai<actIdx2.length; ai++) {
            var ac = (actIdx2[ai].contexte||'').toLowerCase();
            if (ac.indexOf(lk.substring(0,8))>-1||lk.indexOf(ac.substring(0,8))>-1) { found=actIdx2.splice(ai,1)[0]; break; }
          }
        }
        if (!found && actIdx2.length>0) found=actIdx2.shift();
        if (found) actionTxt=(found.type||'')+(found.detail?' — '+found.detail:'')+(found.responsable?' ('+found.responsable+')':'')+(found.heure?' '+found.heure:'');
        else actionTxt='A definir';
      }
      var rs=s.nc?' style="background-color:#fff8f8"':'';
      html+='<tr'+rs+'>';
      
      html+='<td style="word-wrap:break-word;padding:6px 8px;border:1px solid #e5e7eb;font-size:11px">'+s.label+'</td>';
      html+='<td style="text-align:center;padding:6px 4px;border:1px solid #e5e7eb;font-size:14px" class="'+cls+'">'+ico+'</td>';
      html+='<td style="padding:6px 8px;border:1px solid #e5e7eb;font-size:11px;word-wrap:break-word;overflow-wrap:break-word;'+(s.nc?'color:#c2410c;font-weight:700':'')+';word-break:break-word">'+actionTxt+'</td></tr>';
    });
    html += '</table>';
    html += '<div style="font-size:10px;color:#6b7280;margin-top:4px;padding:4px 8px;background:#f9fafb;border-radius:4px">L&eacute;gende : &#x2705; = Conforme &nbsp;|&nbsp; &#x274C; = Non conforme &nbsp;|&nbsp; N/A = Non applicable</div>';
  }

  // 3. NC — combiner NC manuelles (statuts) + NC automatiques
  var allNCs = [];
  data.statuts.forEach(function(s) {
    if (s.nc) {
      // Porter l'action/responsable/heure DIRECTEMENT depuis le statut (lien
      // fiable établi à la sauvegarde) plutôt que par position dans data.actions.
      var _act = '', _resp = '', _heure = '';
      if (s.action && typeof s.action === 'object') {
        _act = (s.action.type || '') + (s.action.detail ? ' — ' + s.action.detail : '');
        _resp = s.action.responsable || '';
        _heure = s.action.heure || '';
      }
      allNCs.push({ label: s.label, _action: _act, _resp: _resp, _heure: _heure, date: s.date || '' });
    }
  });
  data.ncs.forEach(function(nc) {
    allNCs.push(nc);
  });
  if (allNCs.length > 0) {
    html += '<div class="section-title" style="color:#dc2626;border-color:#dc2626">Non-conformites detectees (' + allNCs.length + ')</div>';
    html += '<table><tr><th style="background:#dc2626;color:white;width:30px">N</th><th style="background:#dc2626;color:white">Non-conformite</th><th style="background:#dc2626;color:white;width:90px">Date / Heure</th><th style="background:#dc2626;color:white">Action menee</th><th style="background:#dc2626;color:white;width:80px">Auteur</th></tr>';
    allNCs.forEach(function(nc, i) {
      var isObj = nc && typeof nc === 'object';
      var ncTxt = isObj ? (nc.label || nc.desc || nc.nom || nc.constat || JSON.stringify(nc)) : String(nc || '');
      // Action / responsable / heure : priorité aux infos portées par la NC,
      // sinon repli sur data.actions[i] (compat anciennes sessions).
      var fa = data.actions[i] || {};
      var act = (isObj && nc._action) ? nc._action
              : (isObj && nc.action && typeof nc.action === 'string') ? nc.action
              : ((fa.type || '') + (fa.detail ? ' — ' + fa.detail : ''));
      var resp = (isObj && nc._resp) ? nc._resp : (isObj && nc.responsable ? nc.responsable : (fa.responsable || ''));
      var heure = (isObj && nc._heure) ? nc._heure : (isObj && nc.heure ? nc.heure : (fa.heure || ''));
      // Date/Heure : date propre à la NC, sinon heure de l'action, sinon
      // horodatage du contrôle (pour ne jamais laisser « — »).
      var dateHeure = '—';
      if (isObj && nc.date) dateHeure = nc.date + (heure ? ' ' + heure : '');
      else if (heure) dateHeure = heure;
      else if (data.timestamp) dateHeure = data.timestamp;
      html += '<tr class="nc"><td style="text-align:center;padding:5px 8px;border-bottom:1px solid #fee2e2">' + (i+1) + '</td><td style="padding:5px 8px;border-bottom:1px solid #fee2e2;color:#dc2626;font-weight:600">' + ncTxt + '</td><td style="padding:5px 8px;border-bottom:1px solid #fee2e2;font-size:10px">' + dateHeure + '</td><td style="padding:5px 8px;border-bottom:1px solid #fee2e2;font-size:10px;color:#c2410c">' + (act || '—') + '</td><td style="padding:5px 8px;border-bottom:1px solid #fee2e2;font-size:10px">' + (resp || '—') + '</td></tr>';
    });
    html += '</table>';
  }

  // 4. Actions correctives
  if (data.actions.length > 0) {
    html += '<div class="section-title" style="color:#92400e;border-color:#92400e">Actions correctives (' + data.actions.length + ')</div>';
    html += '<table style="table-layout:fixed;width:100%;border-collapse:collapse"><tr>' +
      '<th style="background:#92400e;color:white;padding:6px 8px;width:60%">Action realisee</th>' +
      '<th style="background:#92400e;color:white;padding:6px 8px;width:25%">Responsable</th>' +
      '<th style="background:#92400e;color:white;padding:6px 8px;width:15%">Heure</th></tr>';
    data.actions.forEach(function(a, i) {
      var actionTxt = (a.type||'') + (a.detail ? ' — ' + a.detail : '');
      if (!actionTxt.trim() || actionTxt === '—') return; // Skip actions vides
      if (actionTxt.includes('Autre action') || actionTxt.includes('Selectionner')) return; // Skip valeur par défaut
      html += '<tr>';
      html += '<td style="padding:6px 8px;border:1px solid #fde8c9;color:#c2410c;font-weight:700;font-size:11px;word-wrap:break-word;overflow-wrap:break-word;word-break:break-word">' + actionTxt + '</td>';
      html += '<td style="padding:6px 8px;border:1px solid #fde8c9;font-size:11px">' + (a.responsable||'—') + '</td>';
      html += '<td style="padding:6px 8px;border:1px solid #fde8c9;font-size:11px;text-align:center">' + (a.heure||'—') + '</td></tr>';
    });
    html += '</table>';
  }

  // 5. Observations
  if (data.observations.length > 0) {
    html += '<div class="section-title">Observations</div>';
    html += '<table>';
    data.observations.forEach(function(obs) {
      html += '<tr><td style="width:30%;font-weight:600">' + obs.label + '</td><td>' + obs.valeur + '</td></tr>';
    });
    html += '</table>';
  }

  html += '<div class="footer">HACCP Pro — À conserver par vos soins 3 ans minimum — Preuve légale en cas de contrôle DDPP</div>';
  html += '</div>';

  // Overlay
  var existing = document.getElementById('printOverlay');
  if (existing) existing.remove();
  var overlay = document.createElement('div');
  overlay.id = 'printOverlay';
  overlay.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:white;z-index:99999;overflow:auto;box-sizing:border-box';

  var _tb = document.createElement('div');
  _tb.className = 'no-print';
  _tb.style.cssText = 'background:#1e1b4b;padding:10px 16px;display:flex;justify-content:space-between;align-items:center;position:sticky;top:0;z-index:1';
  var _tbT = document.createElement('div');
  _tbT.style.cssText = 'color:white;font-weight:800;font-size:13px';
  _tbT.textContent = titre || (data ? data.module : '') || pageId;
  var _tbB = document.createElement('div');
  _tbB.style.cssText = 'display:flex;gap:8px';
  var _bI = document.createElement('button');
  _bI.textContent = 'Imprimer';
  _bI.style.cssText = 'background:#10b981;color:white;border:none;border-radius:8px;padding:8px 14px;font-weight:700;cursor:pointer;font-size:12px';
  _bI.onclick = function() { window.print(); };
  var _bF = document.createElement('button');
  _bF.textContent = 'Fermer';
  _bF.style.cssText = 'background:#dc2626;color:white;border:none;border-radius:8px;padding:8px 14px;font-weight:700;cursor:pointer;font-size:12px';
  _bF.onclick = function() { fermerPrintOverlay(); };
  _tbB.appendChild(_bI); _tbB.appendChild(_bF);
  _tb.appendChild(_tbT); _tb.appendChild(_tbB);
  var _ios = document.createElement('div');
  _ios.className = 'no-print';
  _ios.style.cssText = 'background:#fef3c7;border-bottom:2px solid #fcd34d;padding:8px 16px;font-size:11px;color:#92400e;font-weight:600;text-align:center';
  _ios.textContent = 'Sur iPhone/iPad : bouton Partager du navigateur → Imprimer';
  var _ct = document.createElement('div');
  _ct.innerHTML = html;
  overlay.appendChild(_tb);
  overlay.appendChild(_ios);
  overlay.appendChild(_ct);
  document.body.appendChild(overlay);
  overlay.scrollTop = 0;
}

function pdfTxt(str) {
  if (!str) return '';
  // Supprimer emojis et caractères non-latin
  str = str.replace(/[\u{1F000}-\u{1FFFF}]/gu, '').replace(/[\u2600-\u27FF]/g, '').trim();
  // Remplacer caractères accentués français
  var map = {
    'à':'a','â':'a','ä':'a','á':'a','ã':'a',
    'è':'e','é':'e','ê':'e','ë':'e',
    'î':'i','ï':'i','í':'i','ì':'i',
    'ô':'o','ö':'o','ó':'o','ò':'o','õ':'o',
    'ù':'u','û':'u','ü':'u','ú':'u',
    'ç':'c','ñ':'n',
    'À':'A','Â':'A','Á':'A','Ã':'A','Ä':'A',
    'È':'E','É':'E','Ê':'E','Ë':'E',
    'Î':'I','Ï':'I','Í':'I',
    'Ô':'O','Ö':'O','Ó':'O',
    'Ù':'U','Û':'U','Ü':'U',
    'Ç':'C','Ñ':'N',
    '°':'','\u2014':'-','\u2013':'-','\u2019':"'",'«':'"','»':'"',
  };
  return str.replace(/[^\x00-\x7E]/g, function(c){ return map[c] !== undefined ? map[c] : ''; });
}

