// ── DÉMARRAGE ──
(function initApp() {
  try { _trace('initApp — session=' + (!!sessionRead()) + ' marker=' + lsGet('haccp_deconnecte') + ' trialPwd=' + (!!lsGet('haccp_trial_pwd'))); } catch(e){}
  try { if (typeof _pinUiRefresh === 'function') _pinUiRefresh(); } catch(e){} // PIN vocal : afficher/masquer selon l'appareil
  try { _installerFiletSignaturePhotos(); } catch(e){} // SEC-3 — filet de re-signature des photos
  // Reprise de la session ADMIN : si l'admin était connecté, on revient DIRECTEMENT dans
  // son tableau de bord (fini la page d'accueil + re-scroll + re-saisie du mot de passe).
  try {
    try { lsRemove('haccp_admin_ok'); } catch(e){}
    if (sessionStorage.getItem('haccp_admin_ok') === '1' && sessionStorage.getItem('haccp_maj_reprise') !== '1') {
      if (typeof showPage === 'function') showPage('page-admin');
      setTimeout(function(){
        try {
          var _b = document.getElementById('adminLoginBox'); var _d = document.getElementById('adminDashboard');
          if (_b) _b.style.display = 'none';
          if (_d) _d.style.display = 'block';
          var _av = document.getElementById('adminVersion'); if (_av) _av.textContent = (typeof APP_BUILD !== 'undefined' ? APP_BUILD : '?');
          if (typeof adminTab === 'function') adminTab('demandes');
          window.scrollTo(0, 0);
        } catch(e){}
      }, 120);
      return;
    }
  } catch(e){}
  // V89 — Au démarrage, afficher la page de présentation (commerciale).
  // Le bouton "Se connecter" mène vers page-login.
  // Si une session existe, on saute la présentation et on va au login (avec champs pré-remplis).
  // REPRISE APRÈS MISE À JOUR VOLONTAIRE — si l'utilisateur vient de cliquer
  // « Mettre à jour » alors qu'il était connecté, on le ramène DIRECTEMENT dans
  // l'app (pas de renvoi au login), en restaurant l'état depuis le stockage local.
  try {
    if (sessionStorage.getItem('haccp_maj_reprise') === '1') {
      sessionStorage.removeItem('haccp_maj_reprise');
      var _eid = lsGet('haccp_etab_id');
      var _estr = lsGet('haccp_etab');
      if (_eid && _estr && lsGet('haccp_deconnecte') !== '1') {
        // État essentiel (sûr à poser tout de suite) :
        ETAB = JSON.parse(_estr);
        ETAB_ID = _eid;
        SECTEUR_ACTIF = (ETAB && ETAB.secteur) || lsGet('haccp_secteur_actif_' + _eid) || 'resto';
        CLIENT_MODE = (lsGet('haccp_client_mode') === '1'); if (lsGet('haccp_multi_secteur') === '1' || String(_eid).indexOf('local-') === 0) CLIENT_MODE = false;
        SB_READY = true;
        if (typeof MODE_LOCAL !== 'undefined' && String(_eid).indexOf('local-') === 0) MODE_LOCAL = true;
        var _expert = (lsGet('haccp_mode') === 'expert');
        showPage(_expert ? 'page-home' : 'page-guide');
        // Le RESTE dépend de variables/fonctions définies plus loin dans le fichier
        // (INGREDIENTS_*, renderMods, pulls cloud, topbar) : on diffère pour qu'elles
        // soient bien initialisées au moment de l'appel.
        setTimeout(function(){
          try {
            INGREDIENTS_DB = (SECTEUR_ACTIF === 'bp') ? INGREDIENTS_BP : INGREDIENTS_RESTO;
            var _hero = document.getElementById('heroEtab'); if (_hero) _hero.textContent = (ETAB && ETAB.nom) || '';
            if (typeof updateTopbarEtab === 'function') updateTopbarEtab();
            if (_expert && typeof renderMods === 'function') renderMods('quotidien');
            if (typeof pullEquipeCloud === 'function') pullEquipeCloud();
            if (typeof pullEncCfgCloud === 'function') pullEncCfgCloud();
          } catch(e){}
        }, 250);
        return;
      }
    }
  } catch(eMaj) {}
  // RESTAURATION DE L'INSCRIPTION — si l'utilisateur était en train de s'inscrire et
  // que la page a été rechargée (typiquement : changement d'appli sur mobile), on
  // rouvre le formulaire d'inscription au lieu de le renvoyer ailleurs.
  try {
    if (sessionStorage.getItem('haccp_sur_inscription') === '1') {
      showPage('page-inscription');
      return;
    }
  } catch(eInsc) {}
  try {
    var sessionStr = sessionRead();
    if (sessionStr) {
      var session = JSON.parse(sessionStr);
      var age = Date.now() - (session.loginAt || 0);
      // Essais : session maintenue toute la durée (le contrôle d'expiration en base
      // fait foi). Clients payants : 12h, mot de passe à ressaisir ensuite.
      var lastCodeChk = (lsGet('haccp_last_code') || '').toUpperCase();
      var estEssaiChk = (lastCodeChk.indexOf('EU3J-') === 0 || lastCodeChk.indexOf('ESSAI-') === 0) && lsGet('haccp_trial_pwd');
      // MIN-10 — fenêtre de session d'essai dérivée de la durée réelle d'essai
      // (au lieu d'un « 16 j » arbitraire) : durée d'essai + marge, cohérente avec
      // la fenêtre de login hors-ligne (7 j). L'expiration en base reste l'autorité.
      var essaiSessionJours = (typeof ESSAI_UNIVERSEL_JOURS === 'number' ? ESSAI_UNIVERSEL_JOURS : 3) + 4;
      var maxAge = estEssaiChk ? (essaiSessionJours * 24 * 60 * 60 * 1000) : (12 * 60 * 60 * 1000); // essai: durée+marge / payant: 12h
      if (age > maxAge) {
        sessionClear();
        // Session expirée → afficher la présentation
        showPage('page-presentation');
        return;
      }
      // Essai en cours : reconnexion automatique (le client ne connaît pas son
      // mot de passe auto-généré). connexion() repassera par le contrôle
      // d'expiration → à échéance il sera proprement renvoyé au login.
      try {
        var lastCodeAuto = (lsGet('haccp_last_code') || '').toUpperCase();
        var trialPwd = lsGet('haccp_trial_pwd');
        var estEssaiAuto = (lastCodeAuto.indexOf('EU3J-') === 0 || lastCodeAuto.indexOf('ESSAI-') === 0);
        // SÉCURITÉ — ne JAMAIS reconnecter automatiquement si l'utilisateur vient
        // de se déconnecter volontairement (marqueur posé), y compris dans une
        // autre fenêtre/onglet partageant le stockage.
        if (estEssaiAuto && trialPwd && lsGet('haccp_deconnecte') !== '1') {
          try { _trace('initApp -> RECONNEXION AUTO essai (' + lastCodeAuto + ')'); } catch(e){}
          showPage('page-login');
          setTimeout(function(){
            var ce = document.getElementById('login_code');
            var pe = document.getElementById('login_pwd');
            if (ce) ce.value = lastCodeAuto;
            if (pe) pe.value = trialPwd;
            if (typeof connexion === 'function') connexion();
          }, 300);
          return;
        }
      } catch(e) {}
      // Session valide → aller direct au login (utilisateur récurrent)
      showPage('page-login');
      setTimeout(function(){
        var ce = document.getElementById('login_code');
        var pe = document.getElementById('login_pwd');
        // V105 — Sécurité commercialisation : pré-remplir UNIQUEMENT le code,
        // pas le mot de passe (qui doit être ressaisi à chaque session)
        try {
          var lastCode = lsGet('haccp_last_code');
          if (ce && lastCode) ce.value = lastCode;
        } catch(e) {}
        if (pe) pe.value = '';
        // Compte mémorisé → proposer « Changer de compte ».
        try { if (typeof _majLienChangerCompte === 'function') _majLienChangerCompte(); } catch(e){}
        // Focus sur le champ mot de passe pour faciliter la saisie
        if (pe) try { pe.focus(); } catch(e){}
      }, 300);
      return;
    }
  } catch(e) {}
  // Pas de session → afficher la page de présentation
  showPage('page-presentation');
})();

function getNowStr() {
  var d = new Date();
  return d.toLocaleDateString('fr-FR') + ' a ' + String(d.getHours()).padStart(2,'0') + 'h' + String(d.getMinutes()).padStart(2,'0');
}

// Nombre de JOURS CALENDAIRES (locaux) entre deux dates — pour que « aujourd'hui /
// hier » soit cohérent avec la date affichée (et non un compte de 24 h glissantes).
function _joursCalendaire(a, b) {
  var x = new Date(a.getFullYear(), a.getMonth(), a.getDate());
  var y = new Date(b.getFullYear(), b.getMonth(), b.getDate());
  return Math.round((y.getTime() - x.getTime()) / 86400000);
}

// ── ACTION CORRECTIVE IMMÉDIATE ──
var ACTIONS_CORRECTIVES = [
  '-- Sélectionner l\'action --',
  'Produit écarté / jeté — Non consommable',
  'Produit remis en refroidissement — Cellule utilisée',
  'Refroidissement prolongé — Température vérifiée à T+3h',
  'Produit remis en température réglementaire (+63°C)',
  'Produit recuit jusqu\'au seuil requis',
  'Cellule de refroidissement mise en service',
  'Équipement de refroidissement vérifié / réparé',
  'Équipement mis hors service',
  'Équipement réparé / recalibré',
  'Nettoyage et désinfection immédiats effectués',
  'Salarié évincé du poste',
  'Fournisseur contacté / lot bloqué',
  'Huile changée immédiatement',
  'Document mis à jour / renouvelé',
  'Prestataire contacté',
  'Stockage transféré à +4°C immédiatement',
  'Autre action (préciser ci-dessous)',
];

function buildNCAction(ncId) {
  var now = new Date();
  var hh = String(now.getHours()).padStart(2,'0');
  var mm = String(now.getMinutes()).padStart(2,'0');
  var heureNow = hh + ':' + mm;
  var opts = ACTIONS_CORRECTIVES.map(function(a, i) {
    return '<option value="' + (i === 0 ? '' : a) + '">' + a + '</option>';
  }).join('');
  return '<div class="nc-action" id="nc_action_' + ncId + '">' +
    '<div class="nc-action-title">🛠️ Action corrective immédiate — Obligatoire</div>' +
    '<div class="frow"><div class="flabel">Action effectuée</div>' +
      '<select id="nc_act_type_' + ncId + '">' + opts + '</select>' +
    '</div>' +
    '<div class="frow"><div class="flabel">Précisions (si nécessaire)</div>' +
      '<input type="text" id="nc_act_detail_' + ncId + '" placeholder="Décrivez l\'action corrective effectuée..."/>' +
    '</div>' +
    '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">' +
      '<div class="frow"><div class="flabel">Responsable</div>' +
        '<input type="text" id="nc_act_resp_' + ncId + '" placeholder="Nom & prénom"/>' +
      '</div>' +
      '<div class="frow"><div class="flabel">Heure</div>' +
        '<input type="time" id="nc_act_heure_' + ncId + '" value="' + heureNow + '"/>' +
      '</div>' +
    '</div>' +
    '<div style="font-size:10px;color:#92400e;margin-top:6px;font-weight:600">⚠️ Cette action sera enregistrée dans le Registre NC & Actions correctives</div>' +
  '</div>';
}

function showNCAction(ncId) {
  var el = document.getElementById('nc_action_' + ncId);
  if (el) el.classList.add('visible');
}

function hideNCAction(ncId) {
  var el = document.getElementById('nc_action_' + ncId);
  if (el) el.classList.remove('visible');
}

function getNCActionData(ncId) {
  var typeEl = document.getElementById('nc_act_type_' + ncId);
  var detailEl = document.getElementById('nc_act_detail_' + ncId);
  var respEl = document.getElementById('nc_act_resp_' + ncId);
  var heureEl = document.getElementById('nc_act_heure_' + ncId);
  return {
    action: typeEl ? typeEl.value : '',
    detail: detailEl ? detailEl.value : '',
    responsable: respEl ? respEl.value : '',
    heure: heureEl ? heureEl.value : '',
  };
}

