function choisirSecteur(secteur) {
  ETAB.secteur = secteur;
  SECTEUR_ACTIF = secteur;
  // Mémoriser le secteur actif pour qu'il survive aux rechargements/reconnexions
  // (compte de test multi-secteurs). Évite la désynchro titre ↔ secteur enregistré.
  try { if (typeof ETAB_ID !== 'undefined' && ETAB_ID) lsSet('haccp_secteur_actif_' + ETAB_ID, secteur); } catch(eS) {}
  INGREDIENTS_DB = secteur === 'bp' ? INGREDIENTS_BP : INGREDIENTS_RESTO;
  var cfg = SECTEURS_CONFIG[secteur];
  // V80 — Si l'utilisateur est déjà connecté (compte existant), bypass la fiche établissement
  // et aller directement au choix de mode (guidé/expert). msg #88 : "garder l'écran de choix du secteur"
  if (ETAB_ID && ETAB.nom) {
    sauvegarderEtab();
    var heroEl2 = document.getElementById('heroEtab'); if (heroEl2) heroEl2.textContent = ETAB.nom;
    showPage('page-choix');
    return;
  }
  // Sinon (1ère inscription / mode test), enchaîner vers étape 2 (fiche)
  document.getElementById('onb_step1').style.display = 'none';
  document.getElementById('onb_step2').style.display = 'block'; var sa=document.getElementById('scrollArea'); if(sa) sa.scrollTop=0; window.scrollTo(0,0);
  document.getElementById('onb_secteur_label').textContent = cfg.label;
  document.getElementById('onb_specifique').innerHTML = SECTEURS_SPECIFIQUE[secteur];
  // Pre-fill if returning
  if (ETAB.responsable === 'Administrateur Test') {
    // Mode test : pré-remplir nom si vide
    var nomEl = document.getElementById('onb_nom');
    if (nomEl && !nomEl.value) {
      nomEl.placeholder = 'Nom de votre établissement *';
      nomEl.focus();
    }
  }
  if (ETAB.adresse) document.getElementById('onb_adresse').value = ETAB.adresse;
  if (ETAB.cp) document.getElementById('onb_cp').value = ETAB.cp;
  if (ETAB.ville) document.getElementById('onb_ville').value = ETAB.ville;
  if (ETAB.tel) document.getElementById('onb_tel').value = ETAB.tel;
  if (ETAB.email) document.getElementById('onb_email').value = ETAB.email;
  if (ETAB.siret) document.getElementById('onb_siret').value = ETAB.siret;
  if (ETAB.responsable) document.getElementById('onb_responsable').value = ETAB.responsable;
  if (ETAB.fonction) document.getElementById('onb_fonction').value = ETAB.fonction;
}

function validerOnboarding() {
  var errEl = document.getElementById('onb_error');
  if (!ETAB.nom) {
    errEl.style.display = 'block';
    errEl.innerHTML = '⚠️ Le nom de l\'établissement est obligatoire';
    return;
  }
  errEl.style.display = 'none';
  SECTEUR_ACTIF = ETAB.secteur || 'resto';
  INGREDIENTS_DB = SECTEUR_ACTIF === 'bp' ? INGREDIENTS_BP : INGREDIENTS_RESTO;
  sauvegarderEtab();
  var heroEl2 = document.getElementById('heroEtab'); if (heroEl2) heroEl2.textContent = ETAB.nom;
  showPage('page-choix');
}

// V106 — Bouton œil : afficher/masquer le mot de passe sur le login
function togglePwdVisibility() {
  var pwd = document.getElementById('login_pwd');
  var btn = document.getElementById('login_pwd_toggle');
  if (!pwd) return;
  if (pwd.type === 'password') {
    pwd.type = 'text';
    if (btn) btn.textContent = '🙈';
  } else {
    pwd.type = 'password';
    if (btn) btn.textContent = '👁️';
  }
}

function modeTest() {
  // V80 — Mode Test : pré-remplit le formulaire de login pour test rapide
  // Code TEST + mot de passe TEST123 (utilisé par l'app dans sbLogin avec tolérance MODE_LOCAL)
  var codeEl = document.getElementById('login_code');
  var pwdEl = document.getElementById('login_pwd');
  if (codeEl) codeEl.value = 'TEST';
  if (pwdEl) pwdEl.value = 'TEST123';
  // Pré-remplir les coordonnées par défaut pour l'établissement test
  ETAB.nom = ETAB.nom || 'Établissement Test';
  ETAB.adresse = ETAB.adresse || '1 rue de la Cuisine';
  ETAB.cp = ETAB.cp || '75001';
  ETAB.ville = ETAB.ville || 'Paris';
  ETAB.responsable = ETAB.responsable || 'Administrateur Test';
  ETAB.secteur = ETAB.secteur || 'resto';
  // Mode local actif pour bypass Supabase
  if (typeof MODE_LOCAL !== 'undefined') MODE_LOCAL = true;
  ETAB_ID = 'local-test';
  try { lsRemove('haccp_deconnecte'); } catch(e) {} // mode test = connecté
  SB_READY = true;
  SECTEUR_ACTIF = ETAB.secteur;
  // V80 — En mode Test : CLIENT_MODE désactivé, tous les secteurs visibles pour pouvoir basculer
  CLIENT_MODE = false;
  // Aller directement à la page de choix du secteur
  var nomEl = document.getElementById('onb_nom');
  if (nomEl) nomEl.value = ETAB.nom;
  document.getElementById('onb_back_btn').style.display = 'none';
  document.getElementById('onb_step1').style.display = 'block';
  document.getElementById('onb_step2').style.display = 'none';
  // Réafficher tous les boutons secteur (au cas où ils auraient été masqués par un précédent CLIENT_MODE)
  document.querySelectorAll('#onb_step1 .onb-secteur-btn').forEach(function(btn){ btn.style.display = ''; });
  var modeTestBadge = document.getElementById('modeTestBadge');
  if (modeTestBadge) modeTestBadge.style.display = 'block';
  showPage('page-onboarding');
}

function ouvrirReglages() {
  // Afficher infos établissement dans les réglages
  showPage('page-settings');
  // Affiche la version réelle de l'app (au lieu d'un numéro figé).
  try { var _sv = document.getElementById('settingsVersionTxt'); if (_sv) _sv.textContent = (typeof APP_BUILD !== 'undefined' ? APP_BUILD : '—'); } catch(e){}
  // V80 — Rafraîchir l'indicateur de stockage à l'ouverture
  setTimeout(function(){ if (typeof rafraichirIndicateurStockage === 'function') rafraichirIndicateurStockage(); }, 100);
}

function seDeconnecter() {
  // V80 fix — Utiliser confirm() natif (plus fiable que showConfirm modal)
  if (!confirm('Confirmez-vous vouloir vous déconnecter ?')) return;
  deconnecterConfirme();
}

// Affiche/masque le lien « Changer de compte » sur l'écran de connexion selon
// qu'un compte est mémorisé (code pré-rempli) ou non.
function _majLienChangerCompte() {
  try {
    var ce = document.getElementById('login_code');
    var aUnCompte = !!(ce && ce.value && ce.value.trim()) || !!(typeof lsGet === 'function' && lsGet('haccp_last_code'));
    var lnk = document.getElementById('login_changer_compte');
    var sep = document.getElementById('login_changer_compte_sep');
    if (lnk) lnk.style.display = aUnCompte ? 'inline' : 'none';
    if (sep) sep.style.display = aUnCompte ? 'inline' : 'none';
  } catch(e) {}
}

// « Changer de compte » depuis l'écran de connexion : oublie le compte mémorisé
// sur CET appareil (les données restent dans le cloud) et repart sur un login vierge.
function changerDeCompte() {
  if (!confirm('Changer de compte ?\n\nLe compte mémorisé sur cet appareil sera oublié. Vous retrouverez vos données synchronisées en vous reconnectant ; pensez à conserver vos propres exports (PDF).')) return;
  try {
    lsRemove('haccp_last_code');
    lsRemove('haccp_trial_pwd');
    if (typeof OFFLINE_CRED_KEY !== 'undefined') lsRemove(OFFLINE_CRED_KEY);
    lsRemove('haccp_etab');
    lsRemove('haccp_etab_id');
    lsRemove('haccp_etab_data');
    lsRemove('haccp_date_expiration');
    lsRemove(EQUIPE_KEY);
    lsRemove(EQUIPE_MAJ_KEY);
    lsSet('haccp_deconnecte', '1');
    sessionClear();
  } catch(e) {}
  // Fermer aussi la session Auth éventuelle.
  try { if (window._supabase && window._supabase.auth) window._supabase.auth.signOut(); } catch(e) {}
  _SB_ACCESS_TOKEN = null; _SB_AUTH_ETAB = null;
  ETAB_ID = null; SB_READY = false; CLIENT_MODE = false; SECTEUR_ACTIF = '';
  var c = document.getElementById('login_code'); if (c) c.value = '';
  var p = document.getElementById('login_pwd'); if (p) p.value = '';
  var e = document.getElementById('login_error'); if (e) e.style.display = 'none';
  _majLienChangerCompte();
  if (typeof showToast === 'function') showToast('Compte oublié sur cet appareil. Connectez-vous avec un autre code.', 'info', 4000);
  showPage('page-login');
  try { if (c) c.focus(); } catch(eF) {}
}

function deconnecterConfirme() {
  try { _trace('deconnecterConfirme (bouton)'); } catch(e){}
  ETAB_ID = null; SB_READY = false;
  CLIENT_MODE = false;
  // Marqueur de déconnexion (lu en direct → résiste à l'instantané bfcache iOS au
  // retour arrière) + fermeture de la session Auth sécurisée.
  try { lsSet('haccp_deconnecte', '1'); } catch(e) {}
  try { if (window._supabase && window._supabase.auth) window._supabase.auth.signOut(); } catch(e) {}
  _SB_ACCESS_TOKEN = null; _SB_AUTH_ETAB = null;
  try {
    lsRemove('haccp_etab');
    lsRemove('haccp_etab_id');
    lsRemove('haccp_etab_data');
    lsRemove('haccp_mode');
    lsRemove('haccp_trial_pwd'); // ne pas reconnecter auto après une déconnexion volontaire
    // L'équipe est synchronisée dans le cloud : on l'efface en local à la déconnexion
    // pour qu'un autre compte ne récupère pas l'équipe du compte précédent (appareil partagé).
    lsRemove(EQUIPE_KEY);
    lsRemove(EQUIPE_MAJ_KEY);
    sessionClear();
  } catch(e) {}
  ETAB = {nom:'', secteur:'', siret:'', adresse:'', cp:'', ville:'', tel:'', email:'', responsable:'', fonction:'', typeStructure:'', repasJour:'', liaison:''};
  SECTEUR_ACTIF = '';
  showPage('page-login');
  var loginCode = document.getElementById('login_code');
  var loginPwd = document.getElementById('login_pwd');
  var loginErr = document.getElementById('login_error');
  if (loginCode) loginCode.value = '';
  if (loginPwd) loginPwd.value = '';
  if (loginErr) loginErr.style.display = 'none';
}

