// Catalogue produits détaillé par secteur




function onCategorieChange(id) {
  var catSel = document.getElementById('cat_' + id);
  var typeSel = document.getElementById('type_' + id);
  var prodWrap = document.getElementById('produit_wrap_' + id);
  var autreDiv = document.getElementById('autre_' + id);
  if (!catSel || !catSel.value) return;
  var val = catSel.value;
  // V80 fix — Activer le champ T° dès qu'une catégorie est choisie
  var tempField = document.getElementById('temp_' + id);
  if (tempField) {
    tempField.disabled = false;
    tempField.style.opacity = '1';
    tempField.placeholder = 'ex: +3';
  }
  if (val === 'custom') {
    if (prodWrap) prodWrap.style.display = 'none';
    if (autreDiv) autreDiv.style.display = 'block';
    checkConformite(id);
    return;
  }
  // Afficher menu produit
  if (typeSel) {
    typeSel.innerHTML = getProduitOptionsForCat(val);
    typeSel.value = '';
  }
  if (prodWrap) prodWrap.style.display = 'block';
  if (autreDiv) autreDiv.style.display = 'none';
  // Mettre à jour seuil + conformité
  checkConformite(id);
}




