// V80 — Helper de renumérotation : recompte les blocs après suppression et met à jour les titres "Catégorie 2" / "Compartiment 2" / "Produit N°2" / etc.
function renumeroterBlocs(selecteurContainer, prefixeLabel) {
  try {
    var container = document.querySelector(selecteurContainer);
    if (!container) return;
    var enfants = container.children;
    for (var i = 0; i < enfants.length; i++) {
      var newNum = i + 1;
      // Cherche le titre du bloc — soit .fblock-title span, soit un span direct, soit un div font-weight bold en début
      var titreSpan = enfants[i].querySelector('.fblock-title span');
      if (!titreSpan) {
        // Pour les anciens blocs sans .fblock-title (Catégorie/Compartiment) : prendre le 1er div
        var firstDiv = enfants[i].querySelector(':scope > div');
        if (firstDiv && (firstDiv.textContent || '').match(new RegExp('^' + prefixeLabel.replace('°', '°?') + '\\s*N?°?\\s*\\d+'))) {
          firstDiv.textContent = prefixeLabel + ' ' + newNum;
        }
      } else {
        // Mettre à jour : "Produit N°3" -> "Produit N°1"
        var oldText = titreSpan.textContent || '';
        // On garde l'emoji éventuel devant
        titreSpan.textContent = oldText.replace(/(N°)\s*\d+/, '$1' + newNum).replace(/\s+\d+$/, ' ' + newNum);
      }
    }
  } catch(e) {}
}

function supprimerCategorie(id) {
  if (!confirm('Confirmer la suppression ?')) return;
  var el = document.getElementById('tempCat_' + id);
  if (el) el.remove();
  renumeroterBlocs('#tempCategoriesContainer', 'Catégorie');
}

function onCategorieTemp(id) {
  var sel = document.getElementById('tcat_sel_' + id);
  var body = document.getElementById('tcat_body_' + id);
  var seuilEl = document.getElementById('tcat_seuil_' + id);
  var prodSel = document.getElementById('tcat_prod_' + id);
  var rattachesDiv = document.getElementById('tcat_rattaches_' + id);
  var confEl = document.getElementById('tcat_conf_' + id);

  if (!sel || !sel.value) { if (body) body.style.display = 'none'; return; }
  var val = sel.value;

  // Afficher le seuil
  var seuils = {'-18':'≤ -18°C', '2':'≤ +2°C', '4':'≤ +4°C', '8':'≤ +8°C', 'amb':'Ambiant'};
  if (seuilEl) seuilEl.textContent = seuils[val] || '—';

  // Peupler produits témoins
  if (prodSel) prodSel.innerHTML = getProduitOptionsForCat(val);

  // Peupler rattachés
  if (rattachesDiv) {
    var catalogue = getCatalogueActif();
    var groupe = catalogue.find(function(g){ return g.seuil === val; });
    var items = groupe ? groupe.items : [];
    if (val === 'amb') {
      rattachesDiv.innerHTML = '<div style="font-size:11px;color:#6b7280;font-style:italic">Produits ambiants — contrôle visuel uniquement (pas de T°)</div>';
    } else {
      rattachesDiv.innerHTML = items.map(function(item, i) {
        return '<label style="display:flex;align-items:center;gap:8px;padding:4px 0;font-size:12px;cursor:pointer">' +
          '<input type="checkbox" id="ratt_' + id + '_' + i + '" value="' + item + '" style="width:16px;height:16px"/>' +
          '<span>' + item + '</span>' +
        '</label>';
      }).join('');
    }
  }

  // Cas ambiant
  if (val === 'amb') {
    if (confEl) { confEl.className = 'conformite-badge ok'; confEl.textContent = '✅ Ambiant — contrôle visuel uniquement'; }
    var tempRow = document.getElementById('tcat_temp_' + id);
    if (tempRow) tempRow.closest('.frow') && (tempRow.closest('.frow').style.display = 'none');
    body.style.display = 'block';
    return;
  }

  if (confEl) { confEl.className = 'conformite-badge pending'; confEl.textContent = 'Saisissez la température'; }
  body.style.display = 'block';
}

function onProduitTemoin(id) {
  var sel = document.getElementById('tcat_prod_' + id);
  var risqueDiv = document.getElementById('tcat_risque_' + id);
  if (!sel || !risqueDiv) return;
  var nom = sel.options[sel.selectedIndex] ? sel.options[sel.selectedIndex].text : '';
  risqueDiv.style.display = estProduitARisque(nom) ? 'block' : 'none';
  checkTempCat(id);
}

function checkTempCat(id) {
  var catSel = document.getElementById('tcat_sel_' + id);
  var tempEl = document.getElementById('tcat_temp_' + id);
  var statusGrp = document.getElementById('tcat_status_' + id);
  var seuilEl = document.getElementById('tcat_seuilfield_' + id);
  var valEl = document.getElementById('tcat_val_' + id);
  var ncEl = document.getElementById('tcat_nc_' + id);
  var ncAction = document.getElementById('tcat_nc_action_' + id);
  if (!catSel || !tempEl || !statusGrp) return;
  var val = catSel.value;
  if (!val || val === 'amb') return;
  var seuil = parseFloat(val);
  var seuilStr = (seuil < 0 ? '' : '+') + seuil + '°C';
  seuilEl.value = seuilStr;
  if (!tempEl.value) {
    statusGrp.querySelectorAll('.status-btn').forEach(function(btn) {
      btn.classList.remove('active-ok', 'active-bad', 'active-warn');
    });
    if (ncEl) ncEl.style.display = 'none';
    if (ncAction) ncAction.style.display = 'none';
    return;
  }
  var temp = parseFloat(tempEl.value);
  valEl.value = (temp < 0 ? '' : '+') + temp + '°C';
  statusGrp.querySelectorAll('.status-btn').forEach(function(btn) {
    btn.classList.remove('active-ok', 'active-bad', 'active-warn');
  });
  if (temp <= seuil) {
    statusGrp.querySelectorAll('.status-btn')[0].classList.add('active-ok');
    if (ncEl) ncEl.style.display = 'none';
    if (ncAction) ncAction.style.display = 'none';
    tempEl.style.borderColor = '';
  } else {
    statusGrp.querySelectorAll('.status-btn')[1].classList.add('active-bad');
    if (ncEl) ncEl.style.display = 'flex';
    if (ncAction) ncAction.style.display = 'block';
    tempEl.style.borderColor = '#dc2626';
  }
}

function setTcatStatus(id, statut) {
  var statusGrp = document.getElementById('tcat_status_' + id);
  if (!statusGrp) return;
  statusGrp.querySelectorAll('.status-btn').forEach(function(btn) {
    btn.classList.remove('active-ok', 'active-bad', 'active-warn');
  });
  if (statut === 'ok') {
    statusGrp.querySelectorAll('.status-btn')[0].classList.add('active-ok');
  } else if (statut === 'bad') {
    statusGrp.querySelectorAll('.status-btn')[1].classList.add('active-bad');
  }
}

