function filtrerProduits(inputEl, selectEl) {
  // Accepte élément ou id
  var input = typeof inputEl === 'string' ? document.getElementById(inputEl) : inputEl;
  var select = typeof selectEl === 'string' ? document.getElementById(selectEl) : selectEl;
  if (!select && input) select = input.nextElementSibling;
  if (!input || !select) return;
  var query = input.value.toLowerCase().trim();

  // Stocker toutes les options au premier appel dans data-all-options
  if (!select.dataset.allOptions) {
    var allOpts = [];
    select.querySelectorAll('option').forEach(function(o) {
      allOpts.push({val: o.value, txt: o.textContent, grp: o.parentElement && o.parentElement.tagName === 'OPTGROUP' ? o.parentElement.label : ''});
    });
    select.dataset.allOptions = JSON.stringify(allOpts);
  }

  var all = JSON.parse(select.dataset.allOptions);

  // Reconstruire les options selon le filtre
  select.innerHTML = '';
  var firstOpt = document.createElement('option');
  firstOpt.value = '';
  firstOpt.textContent = query ? '-- Résultats : ' + query + ' --' : '-- Sélectionner le produit --';
  select.appendChild(firstOpt);

  var matches = all.filter(function(o) {
    if (!o.val) return false;
    return !query || o.txt.toLowerCase().indexOf(query) > -1;
  });

  matches.forEach(function(o) {
    var opt = document.createElement('option');
    opt.value = o.val;
    opt.textContent = o.txt;
    select.appendChild(opt);
  });

  // Sélection auto si un seul résultat
  if (matches.length === 1) {
    select.value = matches[0].val;
    select.dispatchEvent(new Event('change'));
  }
}
function toutConforme(blockId) {
  var block = document.getElementById(blockId);
  if (!block) return;
  // Trouver tous les boutons "Conforme" / "ok" dans ce bloc
  var btns = block.querySelectorAll('.status-btn');
  btns.forEach(function(btn) {
    var txt = btn.textContent.toLowerCase();
    // Cliquer uniquement les boutons "Conforme" (pas "Abîmé", "NC", etc.)
    if (txt.indexOf('conforme') > -1 && txt.indexOf('non') === -1) {
      btn.click();
    }
  });
  showToast('Tout conforme enregistré ✅', 'ok');
}
