function supprimerCompartiment(id) {
  if (!confirm('Confirmer la suppression ?')) return;
  var el = document.getElementById('compart_' + id);
  if (el) el.remove();
  renumeroterBlocs('#compartimentsContainer', 'Compartiment');
}

function onCompType(id) {
  var sel = document.getElementById('comp_type_' + id);
  var body = document.getElementById('comp_body_' + id);
  var seuilEl = document.getElementById('comp_seuil_' + id);
  var confEl = document.getElementById('comp_conf_' + id);
  if (!sel || !sel.value) { if (body) body.style.display = 'none'; return; }
  var seuils = {'-18':'≤ -18°C', '2':'≤ +2°C', '4':'≤ +4°C', '8':'≤ +8°C', 'amb':'Ambiant'};
  if (seuilEl) seuilEl.textContent = seuils[sel.value] || '—';
  if (sel.value === 'amb') {
    if (confEl) { confEl.className = 'conformite-badge ok'; confEl.textContent = '✅ Ambiant — pas de T° requise'; }
    body.style.display = 'block';
    body.querySelector('#comp_tbord_' + id).closest('.frow').style.display = 'none';
    body.querySelector('#comp_tsonde_' + id).closest('.frow').style.display = 'none';
    // V116 Livraison 5 — pré-afficher Produit N°1 si le compartiment est vide
    var __pcA = document.getElementById('produits_compart_' + id);
    if (__pcA && __pcA.children.length === 0) ajouterProduit(true, id);
    return;
  }
  if (confEl) { confEl.className = 'conformite-badge pending'; confEl.textContent = 'Saisissez la T° sonde'; }
  body.style.display = 'block';
  // V116 Livraison 5 — pré-afficher Produit N°1 si le compartiment est vide
  var __pcN = document.getElementById('produits_compart_' + id);
  if (__pcN && __pcN.children.length === 0) ajouterProduit(true, id);
}

