var MENTIONS_7 = [
  'Dénomination du produit',
  'Liste des ingrédients',
  'Allergènes (en gras ou soulignés)',
  'Poids net / Quantité',
  'DDM / DLC',
  'Coordonnées du fournisseur',
  "Pays d\'origine",
];

function buildMentions(id) {
  var wrapper = document.createDocumentFragment();
  MENTIONS_7.forEach(function(m, mi) {
    var row = document.createElement('div');
    row.style.cssText = 'display:flex;justify-content:space-between;align-items:center;padding:8px 0;border-bottom:1px solid #ede9fe';

    var lbl = document.createElement('span');
    lbl.style.cssText = 'font-size:13px;flex:1';
    lbl.textContent = (mi+1) + '. ' + m;

    var btnOk = document.createElement('button');
    btnOk.id = 'men_ok_' + id + '_' + mi;
    btnOk.style.cssText = 'margin-left:8px;padding:6px 12px;border-radius:8px;border:2px solid #d1d5db;background:#fff;font-size:12px;cursor:pointer;font-weight:600';
    btnOk.textContent = '✅ OK';
    btnOk.onclick = (function(pid, idx){ return function(e){
      e.stopPropagation();
      var ok = document.getElementById('men_ok_'+pid+'_'+idx);
      var bad = document.getElementById('men_bad_'+pid+'_'+idx);
      if (ok) { ok.style.setProperty('background','#dcfce7','important'); ok.style.setProperty('border-color','#16a34a','important'); ok.setAttribute('data-sel','ok'); }
      if (bad) { bad.style.setProperty('background','#fff','important'); bad.style.setProperty('border-color','#d1d5db','important'); bad.setAttribute('data-sel',''); }
      checkMentionsNC(pid);
    }; })(id, mi);

    var btnBad = document.createElement('button');
    btnBad.id = 'men_bad_' + id + '_' + mi;
    btnBad.style.cssText = 'margin-left:6px;padding:6px 12px;border-radius:8px;border:2px solid #d1d5db;background:#fff;font-size:12px;cursor:pointer;font-weight:600';
    btnBad.textContent = '✗ NC';
    btnBad.onclick = (function(pid, idx){ return function(e){
      e.stopPropagation();
      var ok = document.getElementById('men_ok_'+pid+'_'+idx);
      var bad = document.getElementById('men_bad_'+pid+'_'+idx);
      if (bad) { bad.style.setProperty('background','#fee2e2','important'); bad.style.setProperty('border-color','#dc2626','important'); bad.setAttribute('data-sel','nc'); }
      if (ok) { ok.style.setProperty('background','#fff','important'); ok.style.setProperty('border-color','#d1d5db','important'); ok.setAttribute('data-sel',''); }
      checkMentionsNC(pid);
    }; })(id, mi);

    row.appendChild(lbl);
    row.appendChild(btnOk);
    row.appendChild(btnBad);
    wrapper.appendChild(row);
  });
  return wrapper;
}

function checkMentionsNC(prodId) {
  var hasNC = false;
  for (var i = 0; i < 7; i++) {
    var b = document.getElementById('men_bad_' + prodId + '_' + i);
    if (b && b.getAttribute('data-sel') === 'nc') { hasNC = true; break; }
  }
  var ncEl = document.getElementById('men_nc_' + prodId);
  if (ncEl) ncEl.style.display = hasNC ? 'flex' : 'none';
  // Afficher/masquer le menu d'action corrective associé
  if (hasNC) {
    if (typeof showNCAction === 'function') showNCAction('men_nc_' + prodId);
  } else {
    if (typeof hideNCAction === 'function') hideNCAction('men_nc_' + prodId);
  }
}

function selMention(prodId, menIdx, ok) {
  var okBtn = document.getElementById('men_ok_' + prodId + '_' + menIdx);
  var badBtn = document.getElementById('men_bad_' + prodId + '_' + menIdx);
  if (!okBtn || !badBtn) return;
  if (ok) {
    okBtn.style.setProperty('background','#dcfce7','important');
    okBtn.style.setProperty('border-color','#16a34a','important');
    okBtn.setAttribute('data-sel','ok');
    badBtn.style.setProperty('background','#fff','important');
    badBtn.style.setProperty('border-color','#d1d5db','important');
    badBtn.setAttribute('data-sel','');
  } else {
    badBtn.style.setProperty('background','#fee2e2','important');
    badBtn.style.setProperty('border-color','#dc2626','important');
    badBtn.setAttribute('data-sel','nc');
    okBtn.style.setProperty('background','#fff','important');
    okBtn.style.setProperty('border-color','#d1d5db','important');
    okBtn.setAttribute('data-sel','');
    showToast('⚡ NC — Mention manquante sur l\'étiquette', 'warn');
  }
  checkMentionsNC(prodId);
}

function toutConformeBlock(blockId) {
  var parts = blockId.split('_');
  var prodId = parts[parts.length - 1];
  if (!isNaN(parseInt(prodId))) {
    var pid = parseInt(prodId);
    for (var i = 0; i < 7; i++) {
      var btnOk = document.getElementById('men_ok_' + pid + '_' + i);
      var btnBad = document.getElementById('men_bad_' + pid + '_' + i);
      if (btnOk) { btnOk.style.setProperty('background','#dcfce7','important'); btnOk.style.setProperty('border-color','#16a34a','important'); btnOk.setAttribute('data-sel','ok'); }
      if (btnBad) { btnBad.style.setProperty('background','#fff','important'); btnBad.style.setProperty('border-color','#d1d5db','important'); btnBad.setAttribute('data-sel',''); }
    }
    var ncEl = document.getElementById('men_nc_' + pid);
    if (ncEl) ncEl.style.display = 'none';
    showToast('7 mentions — tout conforme ✅', 'ok');
    return;
  }
  // Cas générique autres blocs
  var block = document.getElementById(blockId);
  if (!block) return;
  block.querySelectorAll('.status-btn').forEach(function(btn) {
    var txt = btn.textContent.toLowerCase();
    if ((txt.indexOf('conforme') > -1 || txt.indexOf('présente') > -1 || txt.indexOf('ok') === 0) &&
        txt.indexOf('non') === -1 && txt.indexOf('absente') === -1 && txt.indexOf('nc') === -1) {
      if (btn.onclick) btn.onclick();
    }
  });
  showToast('Tout conforme ✅', 'ok');
}

function filterProduits(id) {
  var searchEl = document.getElementById('search_prod_' + id);
  var sel = document.getElementById('type_' + id);
  if (!searchEl || !sel) return;
  var query = searchEl.value.toLowerCase().trim();
  var opts = sel.options;
  for (var i = 0; i < opts.length; i++) {
    var txt = opts[i].text.toLowerCase();
    opts[i].style.display = (!query || txt.indexOf(query) > -1) ? '' : 'none';
  }
  // Sélectionner automatiquement si un seul résultat visible
  var visible = Array.from(opts).filter(function(o){ return o.style.display !== 'none' && o.value; });
  if (visible.length === 1) {
    sel.value = visible[0].value;
    onTypeChange(id);
  }
}
