function supprimerProduit(id) {
  if (!confirm('Confirmer la suppression ?')) return;
  var el = document.getElementById('produit_' + id);
  if (el) el.remove();
  renumeroterBlocs('#produitsContainer', 'Produit N°');
}

function onTypeChange(id) {
  var catSel = document.getElementById('cat_' + id);
  var val = catSel ? catSel.value : '';
  var seuilVal = document.getElementById('seuil_val_' + id);
  var seuilLbl = document.getElementById('seuil_lbl_' + id);
  if (!val || val === 'custom' || val === '') {
    if (seuilVal) { seuilVal.textContent = '—'; }
    if (seuilLbl) { seuilLbl.textContent = 'Sélectionnez la catégorie'; }
    return;
  }
  if (val === 'amb') {
    if (seuilVal) { seuilVal.textContent = 'Amb.'; seuilVal.style.fontSize = '14px'; }
    if (seuilLbl) { seuilLbl.textContent = 'Température ambiante'; }
  } else {
    var s = parseFloat(val);
    if (seuilVal) { seuilVal.textContent = (s < 0 ? '' : '+') + s + '°C'; seuilVal.style.fontSize = '20px'; }
    if (seuilLbl) { seuilLbl.textContent = 'Maximum réglementaire'; }
  }
  checkConformite(id);
}

function checkConformite(id) {
  var catEl = document.getElementById('cat_' + id);
  var typeVal = catEl ? catEl.value : '';
  var tempEl = document.getElementById('temp_' + id);
  var statusGrp = document.getElementById('conf_status_' + id);
  var seuilEl = document.getElementById('conf_seuil_' + id);
  var valEl = document.getElementById('conf_val_' + id);
  var ncEl = document.getElementById('nc_temp_' + id);
  var ncAction = document.getElementById('nc_temp_action_' + id);
  var seuilVal = document.getElementById('seuil_val_' + id);
  var seuilLbl = document.getElementById('seuil_lbl_' + id);
  if (!tempEl || !statusGrp) return;
  if (typeVal === 'amb') {
    statusGrp.querySelectorAll('.status-btn').forEach(function(btn) { btn.classList.remove('active-ok', 'active-bad'); });
    statusGrp.querySelectorAll('.status-btn')[0].classList.add('active-ok');
    if (ncEl) ncEl.style.display = 'none';
    if (ncAction) ncAction.style.display = 'none';
    if (seuilEl) seuilEl.value = 'Ambiant';
    if (valEl) valEl.value = 'N/A';
    return;
  }
  if (!typeVal || typeVal === '' || typeVal === 'custom') {
    statusGrp.querySelectorAll('.status-btn').forEach(function(btn) { btn.classList.remove('active-ok', 'active-bad'); });
    if (ncEl) ncEl.style.display = 'none';
    if (ncAction) ncAction.style.display = 'none';
    return;
  }
  var seuil = parseFloat(typeVal);
  var seuilStr = (seuil < 0 ? '' : '+') + seuil + '°C';
  if (seuilVal) { seuilVal.textContent = '≤ ' + seuilStr; seuilVal.style.color = '#f97316'; }
  if (seuilEl) seuilEl.value = seuilStr;
  if (!tempEl.value) {
    statusGrp.querySelectorAll('.status-btn').forEach(function(btn) { btn.classList.remove('active-ok', 'active-bad'); });
    if (ncEl) ncEl.style.display = 'none';
    if (ncAction) ncAction.style.display = 'none';
    return;
  }
  var temp = parseFloat(tempEl.value);
  if (valEl) valEl.value = (temp < 0 ? '' : '+') + temp + '°C';
  statusGrp.querySelectorAll('.status-btn').forEach(function(btn) { btn.classList.remove('active-ok', 'active-bad'); });
  if (temp <= seuil) {
    statusGrp.querySelectorAll('.status-btn')[0].classList.add('active-ok');
    if (ncEl) ncEl.style.display = 'none';
    if (ncAction) ncAction.style.display = 'none';
    tempEl.style.borderColor = '';
  } else {
    statusGrp.querySelectorAll('.status-btn')[1].classList.add('active-bad');
    if (ncEl) ncEl.style.display = 'flex';
    if (ncAction) {
      ncAction.style.display = 'block';
      var hEl = document.getElementById('nc_temp_heure_' + id);
      if (hEl && !hEl.value) {
        var now = new Date();
        hEl.value = String(now.getHours()).padStart(2,'0') + ':' + String(now.getMinutes()).padStart(2,'0');
      }
    }
    tempEl.style.borderColor = '#dc2626';
  }
}

function setConfStatus(id, statut) {
  var statusGrp = document.getElementById('conf_status_' + id);
  if (!statusGrp) return;
  statusGrp.querySelectorAll('.status-btn').forEach(function(btn) {
    btn.classList.remove('active-ok', 'active-bad', 'active-warn');
  });
  if (statut === 'ok') {
    statusGrp.querySelectorAll('.status-btn')[0].classList.add('active-ok');
  } else if (statut === 'bad') {
    statusGrp.querySelectorAll('.status-btn')[1].classList.add('active-bad');
  }
}



function selMentionTracaBtn(btn) {
  var prodId = parseInt(btn.getAttribute('data-pid'));
  var mentionIdx = parseInt(btn.getAttribute('data-midx'));
  var type = btn.getAttribute('data-mtype');
  selMention(prodId, mentionIdx, type);
}

