function getCatalogueActif() {
  if (SECTEUR_ACTIF === 'bp') return CATALOGUES_SECTEUR.bp;
  if (SECTEUR_ACTIF === 'rapide') return CATALOGUES_SECTEUR.rapide;
  if (SECTEUR_ACTIF === 'boucherie') return CATALOGUES_SECTEUR.boucherie;
  if (SECTEUR_ACTIF === 'collective') return CATALOGUES_SECTEUR.collective;
  return CATALOGUES_SECTEUR.resto;
}

function getCategorieOptions() {
  var catalogue = getCatalogueActif();
  var opts = '<option value="">-- Sélectionner la catégorie --</option>';
  catalogue.forEach(function(groupe) {
    opts += '<option value="' + groupe.seuil + '">' + groupe.cat + '</option>';
  });
  opts += '<option value="custom">✏️ Autre produit (saisie libre)</option>';
  return opts;
}

function getProduitOptionsForCat(seuil) {
  var catalogue = getCatalogueActif();
  var groupe = catalogue.find(function(g){ return g.seuil === seuil; });
  var items = groupe ? groupe.items : [];
  var opts = '<option value="">-- Sélectionner le produit --</option>';
  items.forEach(function(item) { opts += '<option>' + item + '</option>'; });
  opts += '<option value="custom">+ Autre produit (préciser)</option>';
  return opts;
}

function getVehProduitOptions(seuil) {
  return getProduitOptionsForCat(seuil);
}

function getProduitOptions() {
  return getCategorieOptions();
}

