function initVehTypeSelect() {
  var sel = document.getElementById('veh_type');
  if (!sel) return;
  var cats = VEH_CATEGORIES[SECTEUR_ACTIF] || VEH_CATEGORIES.resto;
  sel.innerHTML = '<option value="">-- Sélectionner la catégorie --</option>';
  cats.forEach(function(cat) {
    var opt = document.createElement('option');
    opt.value = cat.val;
    opt.textContent = cat.label;
    sel.appendChild(opt);
  });
}

