function onVehType() {
  var sel = document.getElementById('veh_type');
  var wrap = document.getElementById('veh_seuil_wrap');
  var seuilDisp = document.getElementById('veh_seuil_display');
  var seuilLbl = document.getElementById('veh_seuil_lbl');
  var conf = document.getElementById('veh_conformite');
  var prodWrap = document.getElementById('veh_produit_wrap');
  var prodSel = document.getElementById('veh_produit');

  if (!sel || !sel.value) {
    if (prodWrap) prodWrap.style.display = 'none';
    return;
  }

  var s = VEH_SEUILS[sel.value];
  if (!s) return;

  // Afficher et peupler le menu produit
  if (prodSel) prodSel.innerHTML = getVehProduitOptions(sel.value);
  if (prodWrap) prodWrap.style.display = 'block';

  // Afficher seuil + T°
  if (wrap) wrap.style.display = 'block';
  if (seuilDisp) {
    seuilDisp.textContent = s.label;
    seuilDisp.style.fontSize = '18px';
    seuilDisp.style.color = '#f97316';
  }
  if (seuilLbl) seuilLbl.textContent = s.txt + ' — Seuil réglementaire';
  if (conf) { conf.textContent = 'Saisissez la température'; conf.className = 'conformite-badge pending'; }

  // Réinitialiser T° et NC
  var tempEl = document.getElementById('veh_temp');
  if (tempEl) tempEl.value = '';
  var ncDiv = document.getElementById('veh_nc_action');
  if (ncDiv) ncDiv.style.display = 'none';

  // Cas ambiant : pas de T° à saisir
  if (sel.value === 'amb') {
    if (conf) { conf.textContent = '✅ Ambiant — pas de T° requise'; conf.className = 'conformite-badge ok'; }
    var tgrid = wrap ? wrap.querySelector('.tgrid') : null;
    if (tgrid) tgrid.style.display = 'none';
  } else {
    var tgrid2 = wrap ? wrap.querySelector('.tgrid') : null;
    if (tgrid2) tgrid2.style.display = '';
  }
}

function checkVehTemp() {
  var sel = document.getElementById('veh_type');
  var tempEl = document.getElementById('veh_temp');
  var conf = document.getElementById('veh_conformite');
  var ncDiv = document.getElementById('veh_nc_action');
  var ncAuto = ncDiv ? ncDiv.querySelector('.nc-auto') : null;
  if (!sel || !sel.value || !tempEl || !conf) return;
  var s = VEH_SEUILS[sel.value];
  if (!s) return;
  conf.style.display = 'block';
  if (s.max === null) {
    conf.textContent = '✅ Ambiant — OK';
    conf.className = 'conformite-badge ok';
    if (ncDiv) ncDiv.style.display = 'none';
    if (ncAuto) ncAuto.style.display = 'none';
    return;
  }
  var temp = parseFloat(tempEl.value);
  if (isNaN(temp)) { conf.textContent = 'Saisissez la température'; conf.className = 'conformite-badge pending'; if (ncDiv) ncDiv.style.display='none'; if (ncAuto) ncAuto.style.display='none'; return; }
  var prodNom = sel.options[sel.selectedIndex].text.split('—')[0].trim();

  if (temp <= s.max) {
    conf.textContent = '✅ Conforme — ' + prodNom + ' : ' + temp + '°C ' + s.label;
    conf.className = 'conformite-badge ok';
    if (ncDiv) ncDiv.style.display = 'none';
    if (ncAuto) ncAuto.style.display = 'none';
  } else {
    conf.textContent = '✗ Non conforme — ' + prodNom + ' : ' + temp + '°C > seuil ' + s.label;
    conf.className = 'conformite-badge bad';
    if (ncDiv) ncDiv.style.display = 'block';
    if (ncAuto) ncAuto.style.display = 'flex';
    // Heure auto
    var heureEl = document.getElementById('veh_nc_heure');
    if (heureEl && !heureEl.value) {
      var now = new Date();
      heureEl.value = String(now.getHours()).padStart(2,'0') + ':' + String(now.getMinutes()).padStart(2,'0');
    }
  }
}
function selMentionBtn(btn) {
  var prodId = parseInt(btn.getAttribute('data-pid'));
  var mentionIdx = parseInt(btn.getAttribute('data-midx'));
  var type = btn.getAttribute('data-mtype');
  selMention2(prodId, mentionIdx, type);
}
function selMention2(prodId, mentionIdx, type) {
  var okBtn = document.getElementById('men_ok_' + prodId + '_' + mentionIdx);
  var badBtn = document.getElementById('men_bad_' + prodId + '_' + mentionIdx);
  if (okBtn) okBtn.classList.remove('active-ok','active-bad');
  if (badBtn) badBtn.classList.remove('active-ok','active-bad');
  if (type === 'ok' && okBtn) okBtn.classList.add('active-ok');
  if (type === 'bad' && badBtn) badBtn.classList.add('active-bad');

  // NC globale
  var ncEl = document.getElementById('nc_mentions_' + prodId);
  var hasBad = false;
  var allMentions = getMentions ? getMentions() : (typeof MENTIONS_OBLIGATOIRES !== 'undefined' ? MENTIONS_OBLIGATOIRES : []);
  for (var i = 0; i < allMentions.length; i++) {
    var b = document.getElementById('men_bad_' + prodId + '_' + i);
    if (b && b.classList.contains('active-bad')) { hasBad = true; break; }
  }
  if (ncEl) ncEl.style.display = hasBad ? 'flex' : 'none';

  // Action corrective spécifique à la mention cochée Non
  var actionId = 'men_action_' + prodId + '_' + mentionIdx;
  var existingAction = document.getElementById(actionId);

  if (type === 'bad') {
    if (!existingAction) {
      // Labels et actions par type de mention (0=dénomination, 1=lot, 2=dlc, 3=origine, 4=allergènes)
      var mentionLabels = [
        'Denomination absente/illisible',
        'N de lot absent/illisible',
        'DLC/DLUO absente ou illisible',
        'Origine non mentionnee',
        'Allergenes non identifies'
      ];
      var mentionOpts = [
        ['Produit refuse — retour fournisseur','Etiquette completee manuellement','Produit mis en quarantaine','Fournisseur contacte'],
        ['Produit refuse — tracabilite impossible','N lot releve manuellement depuis BL','Fournisseur contacte pour info lot','Produit mis en quarantaine'],
        ['Produit refuse — DLC non verifiable','DLC relevee sur emballage secondaire','Fournisseur contacte','Produit mis en quarantaine'],
        ['Produit refuse — origine non tracable','Origine verifiee sur BL/facture','Fournisseur contacte pour justificatif','Information notee sur registre'],
        ['Produit refuse — risque allergene','Fiche technique demandee au fournisseur','Produit isole en attente info','Alerte responsable HACCP']
      ];
      var idx = Math.min(mentionIdx, mentionLabels.length - 1);
      var label = mentionLabels[idx] || ('Mention ' + (mentionIdx+1) + ' non conforme');
      var opts = mentionOpts[idx] || ['Action corrective requise'];

      var actionDiv = document.createElement('div');
      actionDiv.id = actionId;
      actionDiv.className = 'nc-action visible';
      actionDiv.innerHTML =
        '<div class="nc-action-title">Action corrective — ' + label + '</div>' +
        '<div class="frow"><div class="flabel">Action</div>' +
          '<select id="men_act_type_' + prodId + '_' + mentionIdx + '">' +
            '<option value="">-- Selectionner --</option>' +
            opts.map(function(o){ return '<option>' + o + '</option>'; }).join('') +
            '<option>Autre action (preciser)</option>' +
          '</select>' +
        '</div>' +
        '<div class="frow"><div class="flabel">Precisions</div>' +
          '<input type="text" id="men_act_detail_' + prodId + '_' + mentionIdx + '" placeholder="Complement..."/>' +
        '</div>' +
        '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">' +
          '<div class="frow"><div class="flabel">Responsable</div>' +
            '<input type="text" id="men_act_resp_' + prodId + '_' + mentionIdx + '" placeholder="Nom prenom"/>' +
          '</div>' +
          '<div class="frow"><div class="flabel">Heure</div>' +
            '<input type="time" id="men_act_heure_' + prodId + '_' + mentionIdx + '"/>' +
          '</div>' +
        '</div>';

      // Insérer juste après le bouton Non
      var btnRow = badBtn ? badBtn.closest('.frow') : null;
      if (btnRow && btnRow.parentNode) {
        btnRow.parentNode.insertBefore(actionDiv, btnRow.nextSibling);
      }
    } else {
      existingAction.classList.add('visible');
    }
  } else {
    if (existingAction) existingAction.classList.remove('visible');
  }
}

function selStatut(id, type) {
  ['ok','warn','bad'].forEach(function(t) {
    var btn = document.getElementById('emb_' + t + '_' + id);
    if (btn) btn.classList.remove('active-ok','active-warn','active-bad');
  });
  var active = document.getElementById('emb_' + type + '_' + id);
  if (active) active.classList.add('active-' + type);

  var ncEmb = document.getElementById('nc_emb_' + id);
  var obsWrap = document.getElementById('obs_wrap_' + id);
  var ncAction = document.getElementById('nc_action_nc_emb_' + id);

  // Afficher NC si refusé
  if (ncEmb) {
    ncEmb.style.display = type === 'bad' ? 'flex' : 'none';
    if (ncAction) ncAction.classList.toggle('visible', type === 'bad');
    if (ncEmb) showNCAction && type === 'bad' ? showNCAction('nc_emb_' + id) : hideNCAction && hideNCAction('nc_emb_' + id);
  }

  // Afficher action corrective si abîmé (sans NC auto mais action quand même)
  if (type === 'warn') {
    // Bloc action spécifique pour emballage abîmé
    var abimeAction = document.getElementById('emb_abime_action_' + id);
    if (!abimeAction) {
      abimeAction = document.createElement('div');
      abimeAction.id = 'emb_abime_action_' + id;
      abimeAction.className = 'nc-action visible';
      abimeAction.innerHTML =
        '<div class="nc-action-title">🛠️ Action corrective — Emballage abîmé</div>' +
        '<div class="frow"><div class="flabel">Action effectuée</div>' +
          '<select id="emb_abime_type_' + id + '">' +
            '<option value="">-- Sélectionner --</option>' +
            '<option>Produit accepté après vérification intégrité</option>' +
            '<option>Produit transféré dans un contenant propre</option>' +
            '<option>Produit isolé et mis en quarantaine</option>' +
            '<option>Produit refusé et retourné au fournisseur</option>' +
            '<option>Fournisseur contacté et informé</option>' +
            '<option>Autre action (préciser)</option>' +
          '</select>' +
        '</div>' +
        '<div class="frow"><div class="flabel">Précisions</div>' +
          '<input type="text" id="emb_abime_detail_' + id + '" placeholder="Décrivez l\'action effectuée..."/>' +
        '</div>' +
        '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">' +
          '<div class="frow"><div class="flabel">Responsable</div>' +
            '<input type="text" id="emb_abime_resp_' + id + '" placeholder="Nom & prénom"/>' +
          '</div>' +
          '<div class="frow"><div class="flabel">Heure</div>' +
            '<input type="time" id="emb_abime_heure_' + id + '"/>' +
          '</div>' +
        '</div>';
      // Insérer après obsWrap
      if (obsWrap && obsWrap.parentNode) {
        obsWrap.parentNode.insertBefore(abimeAction, obsWrap.nextSibling);
      }
    } else {
      abimeAction.classList.add('visible');
    }
  } else {
    var abimeAction2 = document.getElementById('emb_abime_action_' + id);
    if (abimeAction2) abimeAction2.classList.remove('visible');
  }

  // Afficher observations si abîmé ou refusé
  if (obsWrap) {
    if (type === 'warn' || type === 'bad') {
      obsWrap.classList.add('visible');
    } else {
      obsWrap.classList.remove('visible');
    }
  }
}

// V80 — Compression photos base64 pour économiser le localStorage iPhone (limite ~5 Mo)
// Réduit l'image à 1280px de large max + qualité JPEG 82% → bon compromis
// poids/lisibilité (un n° de lot / une DLC doit rester lisible sur l'étiquette).
function compresserPhoto(dataURL, callback) {
  try {
    var img = new Image();
    img.onload = function() {
      var maxW = 1280;
      var ratio = img.width > maxW ? maxW / img.width : 1;
      var w = Math.round(img.width * ratio);
      var h = Math.round(img.height * ratio);
      var canvas = document.createElement('canvas');
      canvas.width = w;
      canvas.height = h;
      var ctx = canvas.getContext('2d');
      ctx.drawImage(img, 0, 0, w, h);
      // JPEG qualité 82% — lot / DLC lisibles tout en restant raisonnable
      var compressed = canvas.toDataURL('image/jpeg', 0.82);
      callback(compressed);
    };
    img.onerror = function() { callback(dataURL); }; // Fallback non compressé
    img.src = dataURL;
  } catch(e) { callback(dataURL); }
}

function takePhoto(id) {
  var input = document.createElement('input');
  input.type = 'file';
  input.accept = 'image/*';
  input.capture = 'environment';
  // V116 — Fix bug iPhone Safari : input doit être dans le DOM pour que la 1ère prise marche
  input.style.position = 'absolute';
  input.style.left = '-9999px';
  document.body.appendChild(input);
  input.onchange = function(e) {
    var file = e.target.files[0];
    if (!file) { try { document.body.removeChild(input); } catch(_){} return; }
    var reader = new FileReader();
    reader.onload = function(ev) {
      // V80 — Compression avant affichage
      compresserPhoto(ev.target.result, function(compressed) {
        var img = document.getElementById('photo_' + id);
        var wrapper = document.getElementById('photo_wrapper_' + id);
        if (img) img.src = compressed;
        if (wrapper) wrapper.style.display = 'block';
        // Réinitialiser les cases (nouvelle photo = à re-vérifier)
        var lotOk = document.getElementById('ph_lot_ok_' + id);
        var dlcOk = document.getElementById('ph_dlc_ok_' + id);
        if (lotOk) lotOk.checked = false;
        if (dlcOk) dlcOk.checked = false;
        // Vérifier (overlay rouge affiché car cases non cochées)
        verifierPhotoLotDLC(id);
        // V116 — Range la photo dans la boîte d'attente (cloud)
        apresLaCapturePhoto(compressed, id, 'etiquette_reception');
        // V116 — Nettoyage : retirer l'input du DOM
        try { document.body.removeChild(input); } catch(_){}
      });
    };
    reader.readAsDataURL(file);
  };
  input.click();
}

// V80 — Photo conservée UNIQUEMENT si lot ET DLC sont cochés comme lisibles.
// Tant que les 2 cases ne sont pas cochées : bandeau rouge AU-DESSUS + cadre rouge autour (photo reste lisible).
// La photo est définitivement supprimée à la validation finale (cf. validerReception).
function verifierPhotoLotDLC(id) {
  var lotOk = document.getElementById('ph_lot_ok_' + id);
  var dlcOk = document.getElementById('ph_dlc_ok_' + id);
  var img = document.getElementById('photo_' + id);
  var wrapper = document.getElementById('photo_wrapper_' + id);
  var banner = document.getElementById('photo_banner_' + id);
  var status = document.getElementById('photo_status_' + id);
  if (!img) return;
  // Pas de photo prise → tout masqué
  if (!img.src) {
    if (wrapper) wrapper.style.display = 'none';
    if (status) status.style.display = 'none';
    return;
  }
  var deuxCochees = lotOk && lotOk.checked && dlcOk && dlcOk.checked;
  if (deuxCochees) {
    // Photo valide : bandeau caché, cadre vert, status vert
    if (banner) banner.style.display = 'none';
    img.style.border = '3px solid #16a34a';
    img.style.borderRadius = '10px';
    if (status) {
      status.style.display = 'block';
      status.style.background = '#dcfce7';
      status.style.color = '#15803d';
      status.style.border = '1px solid #86efac';
      status.innerHTML = '✓ Photo acceptée comme preuve (lot + DLC visibles)';
    }
  } else {
    // Photo non valide : bandeau rouge visible, cadre rouge, status rouge
    if (banner) banner.style.display = 'block';
    img.style.border = '3px solid #dc2626';
    img.style.borderTop = 'none';
    img.style.borderRadius = '0 0 10px 10px';
    if (status) {
      status.style.display = 'block';
      status.style.background = '#fef2f2';
      status.style.color = '#dc2626';
      status.style.border = '1px solid #fecaca';
      status.innerHTML = '⚠️ Photo NON valide — sera supprimée à la validation si vous ne cochez pas les <strong>2 cases</strong>';
    }
  }
}

// SIGNATURE
var sigCanvas, sigCtx;
var isDrawing = false, hasSig = false;
var hasSigTemp = false, isDrawingTemp = false;
var hasSigHyg = false, isDrawingHyg = false;
var hasSigOuv = false, isDrawingOuv = false;
var hasSigCuis = false, isDrawingCuis = false;
var hasSigRefroi = false, isDrawingRefroi = false;
var hasSigHuile = false, isDrawingHuile = false;
var hasSigEtiq = false, isDrawingEtiq = false;
var hasSigFerm = false, hasSigDechets = false;
var hasSigPertes = false, hasSigNuis = false;
var hasSigDocs = false, hasSigAff = false;
var hasSigNC = false, hasSigAudit = false, hasSigTraca = false;

function initSignature() {
  sigCanvas = document.getElementById('sigCanvas');
  if (!sigCanvas) return;
  sigCtx = sigCanvas.getContext('2d');
  hasSig = false;
  isDrawing = false;

  var dpr = window.devicePixelRatio || 1;
  var w = sigCanvas.parentElement.clientWidth || 340;
  var h = 140;
  sigCanvas.width = Math.round(w * dpr);
  sigCanvas.height = Math.round(h * dpr);
  sigCanvas.style.width = w + 'px';
  sigCanvas.style.height = h + 'px';
  sigCtx.scale(dpr, dpr);
  sigCtx.strokeStyle = '#1a1a2e';
  sigCtx.lineWidth = 2.5;
  sigCtx.lineCap = 'round';
  sigCtx.lineJoin = 'round';

  function pos(e) {
    var r = sigCanvas.getBoundingClientRect();
    var s = e.touches ? e.touches[0] : e;
    return { x: s.clientX - r.left, y: s.clientY - r.top };
  }
  function start(e) { e.preventDefault(); isDrawing = true; var p = pos(e); sigCtx.beginPath(); sigCtx.moveTo(p.x, p.y); }
  function move(e)  { e.preventDefault(); if (!isDrawing) return; var p = pos(e); sigCtx.lineTo(p.x, p.y); sigCtx.stroke(); hasSig = true; }
  function stop(e)  { e.preventDefault(); isDrawing = false; }

  sigCanvas.removeEventListener('mousedown', sigCanvas._start);
  sigCanvas.removeEventListener('mousemove', sigCanvas._move);
  sigCanvas.removeEventListener('mouseup', sigCanvas._stop);
  sigCanvas.removeEventListener('touchstart', sigCanvas._tstart);
  sigCanvas.removeEventListener('touchmove', sigCanvas._tmove);
  sigCanvas.removeEventListener('touchend', sigCanvas._tstop);

  sigCanvas._start = start; sigCanvas._move = move; sigCanvas._stop = stop;
  sigCanvas._tstart = start; sigCanvas._tmove = move; sigCanvas._tstop = stop;

  sigCanvas.addEventListener('mousedown', start);
  sigCanvas.addEventListener('mousemove', move);
  sigCanvas.addEventListener('mouseup', stop);
  sigCanvas.addEventListener('mouseleave', stop);
  sigCanvas.addEventListener('touchstart', start, {passive:false});
  sigCanvas.addEventListener('touchmove', move, {passive:false});
  sigCanvas.addEventListener('touchend', stop, {passive:false});
}

function clearSignature() {
  if (!sigCtx || !sigCanvas) return;
  sigCtx.clearRect(0, 0, sigCanvas.width, sigCanvas.height);
  hasSig = false;
}

// COLLECTE DONNÉES
function collecterDonnees() {
  var data = {
    timestamp: getNowStr(),
    fournisseur: (document.getElementById('r_fournisseur') || {}).value || 'Non renseigné',
    transporteur: document.getElementById('r_transporteur') ? document.getElementById('r_transporteur').value || '' : '',
    bl: (document.getElementById('r_bl') || {}).value || 'Non renseigné',
    obs: (document.getElementById('r_obs') || {}).value || '',
    signataire: (((document.getElementById('sig_prenom') || {}).value || '') + ' ' + ((document.getElementById('sig_nom') || {}).value || '')).trim(),
    produits: []
  };
  // V83 — Chercher TOUS les produits, peu importe leur conteneur
  // (anciens : produitsContainer ; nouveaux : produits_compart_X dans chaque compartiment)
  var pageReception = document.getElementById('page-reception');
  var allBlocks = pageReception ? pageReception.querySelectorAll('[id^="produit_"]') : [];
  var blocks = Array.from(allBlocks).filter(function(el) {
    return /^produit_\d+$/.test(el.id);
  });
  // Données véhicule V20
  var hygOk = document.getElementById('veh_hyg_ok');
  var hygBad = document.getElementById('veh_hyg_bad');
  data.vehicule = {
    hygiene: hygOk && hygOk.classList.contains('active-ok') ? 'Conforme' :
             hygBad && hygBad.classList.contains('active-bad') ? 'Non conforme' : 'Non renseigné',
    hygieneObs: (document.getElementById('veh_hyg_obs') || {value:''}).value,
    hygieneAction: (document.getElementById('veh_hyg_action') || {value:''}).value,
    compartiments: []
  };
  // Collecter chaque compartiment
  var compDivs = document.querySelectorAll('[id^="compart_"]');
  compDivs.forEach(function(div) {
    var cid = div.id.replace('compart_', '');
    var typeSel = document.getElementById('comp_type_' + cid);
    var tbord = document.getElementById('comp_tbord_' + cid);
    var tsonde = document.getElementById('comp_tsonde_' + cid);
    var statusGrp = document.getElementById('comp_status_' + cid);
    var seuilReg = document.getElementById('comp_seuil_reg_' + cid);
    var action = document.getElementById('comp_action_' + cid);
    var compNC = statusGrp ? !!statusGrp.querySelector('.status-btn.active-bad') : false;
    data.vehicule.compartiments.push({
      cid: cid,
      type: typeSel && typeSel.options[typeSel.selectedIndex] ? typeSel.options[typeSel.selectedIndex].text : '',
      tbord: tbord ? tbord.value : '',
      tsonde: tsonde ? tsonde.value : '',
      seuil: seuilReg ? (seuilReg.value || '') : '',
      conformite: compNC ? 'Non conforme' : 'Conforme',
      nc: compNC,
      action: action ? action.value : ''
    });
  });

  blocks.forEach(function(block) {
    var id = block.id.replace('produit_', '');
    // V83 — Rattacher chaque produit à son compartiment d'origine (dataset.compart)
    var compartId = block.dataset && block.dataset.compart ? block.dataset.compart : '';
    var typeEl = document.getElementById('type_' + id);
    var typeTxt = typeEl ? typeEl.options[typeEl.selectedIndex].text : 'Non renseigné';
    var tempEl = document.getElementById('temp_' + id);
    var confEl = document.getElementById('conf_status_' + id);
    var embBtn = block.querySelector('.status-btn.active-ok') ? 'Intact' :
                 block.querySelector('.status-btn.active-warn') ? 'Abîmé' :
                 block.querySelector('.status-btn.active-bad') ? 'Refusé' : 'Non renseigné';
    // V80 — Action corrective T° produit : 4 champs séparés (nc_temp_type / detail / resp / heure)
    var ncTempTypeEl = document.getElementById('nc_temp_type_' + id);
    var ncTempDetailEl = document.getElementById('nc_temp_detail_' + id);
    var ncTempRespEl = document.getElementById('nc_temp_resp_' + id);
    var ncTempHeureEl = document.getElementById('nc_temp_heure_' + id);
    var ncTempType = ncTempTypeEl && ncTempTypeEl.value ? ncTempTypeEl.value : '';
    var ncTempDetail = ncTempDetailEl ? ncTempDetailEl.value || '' : '';
    var ncTempResp = ncTempRespEl ? ncTempRespEl.value || '' : '';
    var ncTempHeure = ncTempHeureEl ? ncTempHeureEl.value || '' : '';
    // Reconstruction lisible : "Action — Précisions (Responsable, HH:MM)"
    var ncTempTxt = ncTempType;
    if (ncTempDetail) ncTempTxt += (ncTempTxt ? ' — ' : '') + ncTempDetail;
    if (ncTempResp) ncTempTxt += ' (' + ncTempResp + (ncTempHeure ? ', ' + ncTempHeure : '') + ')';
    else if (ncTempHeure) ncTempTxt += ' (à ' + ncTempHeure + ')';
    // Action corrective emballage (buildNCAction sur nc_emb_ + id)
    var ncEmbTypeEl = document.getElementById('nc_act_type_nc_emb_' + id);
    var ncEmbDetailEl = document.getElementById('nc_act_detail_nc_emb_' + id);
    var ncEmbTxt = ncEmbTypeEl ? ncEmbTypeEl.value || '' : '';
    if (!ncEmbTxt && ncEmbDetailEl) ncEmbTxt = ncEmbDetailEl.value || '';
    // Action emballage abîmé
    var embAbimeTypeEl = document.getElementById('emb_abime_type_' + id);
    var embAbimeDetailEl = document.getElementById('emb_abime_detail_' + id);
    if (!ncEmbTxt && embAbimeTypeEl) ncEmbTxt = embAbimeTypeEl.value || '';
    if (!ncEmbTxt && embAbimeDetailEl) ncEmbTxt = embAbimeDetailEl.value || '';
    var isNC = confEl && confEl.querySelector('.status-btn.active-bad') ? true : false;
    var ncActionTxt = ncTempTxt || '';
    data.produits.push({
      num: id,
      compartId: compartId,
      lot: document.getElementById('lot_' + id) ? document.getElementById('lot_' + id).value || 'Non renseigné' : '',
      dlc: document.getElementById('dlc_' + id) ? document.getElementById('dlc_' + id).value || 'Non renseigné' : '',
      type: typeTxt,
      temp: tempEl ? tempEl.value || '—' : '—',
      conformite: confEl && confEl.querySelector('.status-btn.active-bad') ? '❌ Non conforme' : (confEl && confEl.querySelector('.status-btn.active-ok') ? '✅ Conforme' : '—'),
      nc: isNC,
      actionCorrective: ncActionTxt,
      // V117 — champs séparés pour le tableau récap (Réception)
      actionPropre: (ncTempType + (ncTempDetail ? ' — ' + ncTempDetail : '')) || ncEmbTxt,
      responsable: ncTempResp,
      heure: ncTempHeure,
      seuil: document.getElementById('conf_seuil_' + id) ? (document.getElementById('conf_seuil_' + id).value || '') : '',
      valeurRelevee: tempEl ? (tempEl.value || '') : '',
      actionEmballage: ncEmbTxt,
      emballage: embBtn,
      obs: document.getElementById('obs_emb_' + id) ? document.getElementById('obs_emb_' + id).value || '' : ''
    });
  });
  return data;
}

// GÉNÉRATION PDF

// ══════════════════════════════════════════════════
// PDF RÉCEPTION — Format produit par produit
// ══════════════════════════════════════════════════
function genererPDFReception() {
  imprimerReception();
}

// Impression réception — format produit par produit

function fermerOverlayReception() {
  var el = document.getElementById('printOverlay');
  if (el) el.remove();
  // Ne pas réinitialiser ici — l'utilisateur peut vouloir réimprimer
  // Le reset se fait au clic "Retour au module" dans le modal
}

function previewPhotoBL(input) {
  var prev = document.getElementById('preview_bl');
  if (!prev || !input.files || !input.files[0]) return;
  var reader = new FileReader();
  reader.onload = function(e) {
    // V80 — Compression
    compresserPhoto(e.target.result, function(compressed) {
      prev.innerHTML = '<img src="' + compressed + '" alt="Photo bon de livraison" style="max-width:100%;max-height:150px;border-radius:8px;margin-top:6px"/>';
      // V116 — Range la photo dans la boîte d'attente (cloud)
      apresLaCapturePhoto(compressed, 'bl', 'bon_livraison');
    });
  };
  reader.readAsDataURL(input.files[0]);
}
function imprimerReception(dataOverride, photosOverride) {
  var data = dataOverride || collecterDonnees();
  // Photo d'un produit (clé = numéro) ou du bon de livraison (clé = 'bl').
  // À la réouverture, on prend l'URL rangée dans le cloud ; sinon, la photo affichée à l'écran.
  function _photoDe(ref) {
    if (photosOverride && photosOverride[ref]) return photosOverride[ref];
    if (String(ref) === 'bl') {
      var b = document.querySelector('#preview_bl img');
      return (b && b.src && b.src.indexOf('data:image') > -1) ? b.src : '';
    }
    var el = document.getElementById('photo_' + ref);
    var s = (el && el.src && el.src.indexOf('data:image') > -1) ? el.src : '';
    // Anti-doublon : si la photo de ce produit est en réalité celle du bon de livraison,
    // ne pas la réafficher (le BL a déjà son propre cadre dédié plus haut)
    if (s) {
      var blS = (photosOverride && photosOverride['bl']) ? photosOverride['bl'] : (function(){ var bb = document.querySelector('#preview_bl img'); return (bb && bb.src && bb.src.indexOf('data:image') > -1) ? bb.src : ''; })();
      if (blS && s === blS) return '';
    }
    return s;
  }
  var existing = document.getElementById('printOverlay');
  if (existing) existing.remove();

  var html = '<style>' +
    'body{font-family:Arial,sans-serif;font-size:11pt;color:#111;margin:0;padding:16px}' +
    '.header{background:#f97316;color:white;padding:14px 20px;border-radius:8px;margin-bottom:16px}' +
    '.header h2{margin:0 0 4px;font-size:15px}' +
    '.produit-bloc{border:2px solid #f97316;border-radius:10px;margin-bottom:16px;overflow:hidden;break-inside:avoid}' +
    '.produit-header{background:#fff7ed;border-bottom:2px solid #f97316;padding:8px 14px;display:flex;justify-content:space-between;align-items:center}' +
    '.produit-header h3{margin:0;color:#c2410c;font-size:13px}' +
    '.produit-body{padding:12px 14px;display:grid;grid-template-columns:1fr auto;gap:16px}' +
    '.produit-data table{width:100%;border-collapse:collapse;font-size:10pt}' +
    '.produit-data td{padding:4px 6px;border-bottom:1px solid #f3f4f6}' +
    '.produit-data td:first-child{font-weight:700;color:#555;width:120px}' +
    '.photo-box{width:110px;text-align:center}' +
    '.photo-box img{max-width:100px;max-height:80px;border:1px solid #e5e7eb;border-radius:4px}' +
    '.photo-box .no-photo{width:100px;height:70px;background:#f9fafb;border:1px dashed #d1d5db;border-radius:4px;display:flex;align-items:center;justify-content:center;font-size:10px;color:#9ca3af}' +
    '.nc-band{background:#fff8f8;border:1px solid #fecaca;border-radius:6px;padding:6px 10px;margin-top:8px;color:#dc2626;font-weight:700;font-size:11px}' +
    '@media print{.no-print{display:none!important}}' +
  '</style>';

  html += '<div class="header"><h2>Réception & Traçabilité</h2>';
  html += '<div style="font-size:11px;opacity:.85">Fournisseur : ' + (data.fournisseur||'—') + ' | BL : ' + (data.bl||'—') + '</div>';
  if (data.transporteur) html += '<div style="font-size:11px;opacity:.85">Transporteur : ' + data.transporteur + '</div>';
  html += '<div style="font-size:11px;opacity:.85">Date : ' + (data.timestamp||'—') + ' | Émargement : ' + (data.signataire||'—') + '</div>';
  html += '<div style="font-size:11px;opacity:.85">Secteur : ' + (((typeof SECTEURS_CONFIG!=='undefined' && SECTEURS_CONFIG[SECTEUR_ACTIF] && SECTEURS_CONFIG[SECTEUR_ACTIF].label)) || SECTEUR_ACTIF || '—') + '</div>';
  html += '</div>';

  // ── Photo du bon de livraison ──
  var _blSrc = _photoDe('bl');
  if (_blSrc) {
    html += '<div style="border:1px solid #bfdbfe;border-radius:8px;margin-bottom:14px;overflow:hidden">';
    html += '<div style="background:#eff6ff;padding:6px 12px;font-weight:700;color:#1d4ed8;font-size:11px">📄 Photo du bon de livraison</div>';
    html += '<div style="padding:10px 12px;text-align:center"><img src="' + _blSrc + '" alt="Bon de livraison" style="max-width:100%;max-height:220px;border:1px solid #e5e7eb;border-radius:6px"/></div>';
    html += '</div>';
  }

  // ── Infos camion ──
  if (data.vehicule) {
    html += '<div style="border:1.5px solid #f97316;border-radius:8px;margin-bottom:14px;overflow:hidden">';
    html += '<div style="background:#fff7ed;padding:6px 12px;font-weight:700;color:#c2410c;font-size:11px">🚛 Contrôle du véhicule</div>';
    html += '<div style="padding:8px 12px;font-size:10pt">';
    html += '<div><strong>Hygiène :</strong> <span style="color:' + (data.vehicule.hygiene==='Conforme'?'#16a34a':'#dc2626') + '">' + (data.vehicule.hygiene||'—') + '</span></div>';
    if (data.vehicule.hygieneAction) html += '<div><strong>Action :</strong> <span style="color:#dc2626">' + data.vehicule.hygieneAction + '</span></div>';
    (data.vehicule.compartiments||[]).forEach(function(comp, ci) {
      html += '<div style="margin-top:6px;padding-top:6px;border-top:1px solid #fed7aa">';
      html += '<strong>Compartiment ' + (ci+1) + '</strong> — ' + (comp.type||'—');
      if (comp.tbord) html += ' | T° bord : ' + comp.tbord + '°C';
      if (comp.tsonde) html += ' | T° sonde : <span style="color:' + (comp.nc?'#dc2626':'#16a34a') + '">' + comp.tsonde + '°C</span>';
      if (comp.conformite) html += '<br><em>' + comp.conformite + '</em>';
      if (comp.nc && comp.action) html += '<br><span style="color:#dc2626;font-weight:700">→ Action : ' + comp.action + '</span>';
      html += '</div>';
    });
    html += '</div></div>';
  }

  // V83 — Affichage par compartiment, avec ses produits regroupés dessous
  var compartiments = (data.vehicule && data.vehicule.compartiments) ? data.vehicule.compartiments : [];
  var produits = data.produits || [];

  if (compartiments.length > 0) {
    // Mode compartiments : pour chaque compartiment, on liste ses produits
    compartiments.forEach(function(comp, ci) {
      var compNum = ci + 1;
      var produitsDuCompart = produits.filter(function(p) { return p.compartId === comp.cid; });

      // Bandeau compartiment
      html += '<div style="background:#fff7ed;border:2px solid #f97316;border-radius:10px;padding:10px 14px;margin-top:14px;margin-bottom:10px">';
      html += '<div style="font-size:13px;font-weight:800;color:#c2410c">📦 Compartiment ' + compNum + ' — ' + (comp.type || '—') + '</div>';
      var compInfos = [];
      if (comp.tbord) compInfos.push('T° bord : ' + comp.tbord + '°C');
      if (comp.tsonde) compInfos.push('T° sonde : ' + comp.tsonde + '°C');
      if (compInfos.length > 0) html += '<div style="font-size:10pt;color:#92400e;margin-top:4px">' + compInfos.join(' | ') + '</div>';
      if (comp.conformite) html += '<div style="font-size:10pt;color:' + (comp.nc?'#dc2626':'#16a34a') + ';font-weight:700;margin-top:2px">' + comp.conformite + '</div>';
      if (comp.nc && comp.action) html += '<div style="font-size:10pt;color:#dc2626;font-weight:700;margin-top:2px">→ Action : ' + comp.action + '</div>';
      html += '<div style="font-size:11px;color:#9a3412;margin-top:6px">' + produitsDuCompart.length + ' produit(s) reçu(s) dans ce compartiment</div>';
      html += '</div>';

      // Produits de ce compartiment
      produitsDuCompart.forEach(function(p, i) {
        var photoEl = { src: _photoDe(p.num) };
        var hasPhoto = !!photoEl.src;
        var confColor = (p.conformite||'').indexOf('Non') > -1 ? '#dc2626' : '#16a34a';
        var embColor = (p.emballage === 'Abîmé' || p.emballage === 'Refusé') ? '#dc2626' : '#16a34a';

        html += '<div class="produit-bloc" style="margin-left:16px">';
        html += '<div class="produit-header"><h3>Compartiment ' + compNum + ' · Produit N°' + (i+1) + ' — ' + p.type + '</h3>';
        html += '<span style="font-size:11px;color:#9a3412">' + data.timestamp + '</span></div>';
        html += '<div class="produit-body">';
        html += '<div class="produit-data"><table>';
        html += '<tr><td>N° de lot</td><td><strong>' + (p.lot||'—') + '</strong></td></tr>';
        html += '<tr><td>DLC / DLUO</td><td>' + (p.dlc||'—') + '</td></tr>';
        html += '<tr><td>T° relevée</td><td>' + (p.temp !== '—' ? p.temp + '°C' : '—') + (p.seuil ? ' <span style="color:#0891b2;font-weight:600;font-size:9px">(seuil : ' + p.seuil + ')</span>' : '') + '</td></tr>';
        html += '<tr><td>Conformité T°</td><td style="color:' + confColor + ';font-weight:700">' + (p.conformite||'—') + '</td></tr>';
        if (p.nc && p.actionCorrective) {
          html += '<tr><td style="color:#dc2626;font-weight:700">Action corrective</td><td style="color:#dc2626;font-weight:700">' + p.actionCorrective + '</td></tr>';
        }
        html += '<tr><td>Emballage</td><td style="color:' + embColor + ';font-weight:700">' + (p.emballage||'—') + '</td></tr>';
        if (p.actionEmballage) {
          html += '<tr><td style="color:#dc2626;font-weight:700">Action emballage</td><td style="color:#dc2626;font-weight:700">' + p.actionEmballage + '</td></tr>';
        }
        if (p.obs) html += '<tr><td>Observations</td><td>' + p.obs + '</td></tr>';
        html += '</table>';
        if (p.emballage === 'Abîmé' || p.emballage === 'Refusé') {
          html += '<div class="nc-band">⚡ NC — Emballage ' + p.emballage + ' — Action corrective requise</div>';
        }
        html += '</div>';
        html += '<div class="photo-box">';
        if (hasPhoto) {
          html += '<img src="' + photoEl.src + '" alt="Photo etiquette"/><div style="font-size:9px;color:#6b7280;margin-top:4px">Photo étiquette</div>';
        } else {
          html += '<div class="no-photo">Pas de<br>photo</div>';
        }
        html += '</div></div></div>';
      });

      // Produits non rattachés (au cas où)
    });

    // Produits sans compartiment associé (si jamais)
    var orphelins = produits.filter(function(p) { return !p.compartId || !compartiments.find(function(c){return c.cid===p.compartId;}); });
    if (orphelins.length > 0) {
      html += '<div style="background:#fef2f2;border:1.5px solid #fecaca;border-radius:8px;padding:8px 12px;margin-top:14px;color:#991b1b;font-size:11px;font-weight:700">⚠️ Produits non rattachés à un compartiment</div>';
      orphelins.forEach(function(p, i) {
        var photoEl = { src: _photoDe(p.num) };
        var hasPhoto = !!photoEl.src;
        var confColor = (p.conformite||'').indexOf('Non') > -1 ? '#dc2626' : '#16a34a';
        var embColor = (p.emballage === 'Abîmé' || p.emballage === 'Refusé') ? '#dc2626' : '#16a34a';
        html += '<div class="produit-bloc">';
        html += '<div class="produit-header"><h3>Produit N°' + (i+1) + ' — ' + p.type + '</h3>';
        html += '<span style="font-size:11px;color:#9a3412">' + data.timestamp + '</span></div>';
        html += '<div class="produit-body"><div class="produit-data"><table>';
        html += '<tr><td>N° de lot</td><td><strong>' + (p.lot||'—') + '</strong></td></tr>';
        html += '<tr><td>DLC / DLUO</td><td>' + (p.dlc||'—') + '</td></tr>';
        html += '<tr><td>T° relevée</td><td>' + (p.temp !== '—' ? p.temp + '°C' : '—') + (p.seuil ? ' <span style="color:#0891b2;font-weight:600;font-size:9px">(seuil : ' + p.seuil + ')</span>' : '') + '</td></tr>';
        html += '<tr><td>Conformité T°</td><td style="color:' + confColor + ';font-weight:700">' + (p.conformite||'—') + '</td></tr>';
        html += '<tr><td>Emballage</td><td style="color:' + embColor + ';font-weight:700">' + (p.emballage||'—') + '</td></tr>';
        html += '</table></div>';
        html += '<div class="photo-box">' + (hasPhoto ? '<img src="' + photoEl.src + '"/>' : '<div class="no-photo">Pas de<br>photo</div>') + '</div>';
        html += '</div></div>';
      });
    }
  } else {
    // Pas de compartiments : ancien comportement (liste plate)
    produits.forEach(function(p, i) {
      var photoEl = { src: _photoDe(p.num) };
      var hasPhoto = !!photoEl.src;
      var confColor = (p.conformite||'').indexOf('Non') > -1 ? '#dc2626' : '#16a34a';
      var embColor = (p.emballage === 'Abîmé' || p.emballage === 'Refusé') ? '#dc2626' : '#16a34a';

      html += '<div class="produit-bloc">';
      html += '<div class="produit-header"><h3>Produit N°' + (i+1) + ' — ' + p.type + '</h3>';
      html += '<span style="font-size:11px;color:#9a3412">' + data.timestamp + '</span></div>';
      html += '<div class="produit-body">';
      html += '<div class="produit-data"><table>';
      html += '<tr><td>N° de lot</td><td><strong>' + (p.lot||'—') + '</strong></td></tr>';
      html += '<tr><td>DLC / DLUO</td><td>' + (p.dlc||'—') + '</td></tr>';
      html += '<tr><td>T° relevée</td><td>' + (p.temp !== '—' ? p.temp + '°C' : '—') + (p.seuil ? ' <span style="color:#0891b2;font-weight:600;font-size:9px">(seuil : ' + p.seuil + ')</span>' : '') + '</td></tr>';
      html += '<tr><td>Conformité T°</td><td style="color:' + confColor + ';font-weight:700">' + (p.conformite||'—') + '</td></tr>';
      if (p.nc && p.actionCorrective) {
        html += '<tr><td style="color:#dc2626;font-weight:700">Action corrective</td><td style="color:#dc2626;font-weight:700">' + p.actionCorrective + '</td></tr>';
      }
      html += '<tr><td>Emballage</td><td style="color:' + embColor + ';font-weight:700">' + (p.emballage||'—') + '</td></tr>';
      if (p.actionEmballage) {
        html += '<tr><td style="color:#dc2626;font-weight:700">Action emballage</td><td style="color:#dc2626;font-weight:700">' + p.actionEmballage + '</td></tr>';
      }
      if (p.obs) html += '<tr><td>Observations</td><td>' + p.obs + '</td></tr>';
      html += '</table>';
      if (p.emballage === 'Abîmé' || p.emballage === 'Refusé') {
        html += '<div class="nc-band">⚡ NC — Emballage ' + p.emballage + ' — Action corrective requise</div>';
      }
      html += '</div>';
      html += '<div class="photo-box">';
      if (hasPhoto) {
        html += '<img src="' + photoEl.src + '" alt="Photo etiquette"/><div style="font-size:9px;color:#6b7280;margin-top:4px">Photo étiquette</div>';
      } else {
        html += '<div class="no-photo">Pas de<br>photo</div>';
      }
      html += '</div></div></div>';
    });
  }

  html += '<div style="font-size:8pt;color:#9ca3af;text-align:center;margin-top:16px">HACCP Pro — À conserver par vos soins 3 ans minimum — Preuve légale en cas de contrôle DDPP</div>';

  var overlay = document.createElement('div');
  overlay.id = 'printOverlay';
  overlay.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:white;z-index:99999;overflow-y:scroll;-webkit-overflow-scrolling:touch';
    // Toolbar createElement — iOS/GitHub compatible
  var _tb = document.createElement('div');
  _tb.className = 'no-print';
  _tb.style.cssText = 'background:#f97316;padding:10px 16px;display:flex;justify-content:space-between;align-items:center;position:sticky;top:0;z-index:1';
  var _tbTitle = document.createElement('div');
  _tbTitle.style.cssText = 'color:white;font-weight:800;font-size:13px';
  _tbTitle.textContent = 'Reception — ' + (data.produits ? data.produits.length : 0) + ' produit(s)';
  var _tbBtns = document.createElement('div');
  _tbBtns.style.cssText = 'display:flex;gap:8px';
  var _btnImpr = document.createElement('button');
  _btnImpr.textContent = '🖨️ Imprimer';
  _btnImpr.style.cssText = 'background:white;color:#f97316;border:none;border-radius:8px;padding:8px 14px;font-weight:700;cursor:pointer;font-size:12px';
  _btnImpr.onclick = function() { window.print(); };
  var _btnFerm = document.createElement('button');
  _btnFerm.textContent = '✕ Fermer';
  _btnFerm.style.cssText = 'background:#dc2626;color:white;border:none;border-radius:8px;padding:8px 14px;font-weight:700;cursor:pointer;font-size:12px';
  _btnFerm.onclick = function() { fermerOverlayReception(); };
  _tbBtns.appendChild(_btnImpr); _tbBtns.appendChild(_btnFerm);
  _tb.appendChild(_tbTitle); _tb.appendChild(_tbBtns);
  var _ct = document.createElement('div');
  _ct.innerHTML = html;
  overlay.appendChild(_tb);
  overlay.appendChild(_ct);
  document.body.appendChild(overlay);
}

