async function validerReception() {
  // V80 — Seul blocage : signature + nom + prénom (responsabilité client pour le reste, rappelé via bandeau permanent)
  var prenom = document.getElementById('sig_prenom').value.trim();
  var nom = document.getElementById('sig_nom').value.trim();
  var reqEl = document.getElementById('sig_required');

  if (!hasSig || !prenom || !nom) {
    reqEl.style.display = 'flex';
    reqEl.scrollIntoView({behavior:'smooth', block:'center'});
    return;
  }
  reqEl.style.display = 'none';

  // ── Anti-contrôle-vide (réception) ──
  // Une réception peut légitimement contenir des produits SANS température (produits
  // secs/ambiants) : on n'exclut donc aucun bloc ici. On refuse seulement une
  // réception TOTALEMENT vide (rien saisi du tout) — autocontrôle fictif.
  var _recInfo = ((document.getElementById('r_fournisseur') || {value:''}).value.trim()
               || (document.getElementById('r_bl') || {value:''}).value.trim());
  var _recProduits = 0;
  document.querySelectorAll('#page-reception [id^="produit_"]').forEach(function(block){
    if (!/^produit_\d+$/.test(block.id)) return;
    var id = block.id.replace('produit_','');
    var typeEl = document.getElementById('type_' + id);
    var tempEl = document.getElementById('temp_' + id);
    var typeOk = typeEl && typeEl.value && typeEl.selectedIndex > 0;
    var tempOk = tempEl && String(tempEl.value).trim() !== '';
    var statusOk = !!block.querySelector('.status-btn.active-ok, .status-btn.active-warn, .status-btn.active-bad');
    if (typeOk || tempOk || statusOk) _recProduits++;
  });
  var _recCat = 0;
  document.querySelectorAll('[id^="tempCat_"]').forEach(function(block){
    if (!/^tempCat_\d+$/.test(block.id)) return;
    var id = block.id.replace('tempCat_','');
    var sel = document.getElementById('tcat_sel_' + id);
    var t = document.getElementById('tcat_temp_' + id);
    var ambiant = sel && sel.value === 'amb';
    var tOk = t && String(t.value).trim() !== '';
    if (ambiant || tOk) _recCat++;
  });
  var _recPhoto = false;
  try { _recPhoto = !!document.querySelector('#page-reception img.photo-preview[src]:not([src=""])'); } catch(_) {}
  if (!_recInfo && _recProduits === 0 && _recCat === 0 && !_recPhoto) {
    if (typeof showToast === 'function') showToast('Contrôle vide : aucune information saisie. Renseignez au moins le fournisseur, un produit ou une température avant de valider.', 'err', 6000);
    return;
  }
  // V113 — D : Sauvegarde Supabase AVANT PDF (awaited, après check signature)
  if (SB_READY && ETAB_ID) {
    try {
      await sbSauvegarderModule('reception', {secteur: SECTEUR_ACTIF, etab: ETAB.nom, timestamp: new Date().toISOString()}, prenom + ' ' + nom);
    } catch(eSB) { console.warn('Supabase save error (reception):', eSB); }
  }
  // V80 — Nettoyer les photos d'étiquette qui n'ont pas les 2 cases cochées (lot ET DLC lisibles)
  // Ces photos ne sont pas valides comme preuve → on les supprime du DOM avant collecte
  // V83 — Scanner toute la page (pour produits dans compartiments aussi)
  document.querySelectorAll('#page-reception img.photo-preview').forEach(function(img) {
    if (!img.src) return;
    var idMatch = img.id.match(/^photo_(\d+)$/);
    if (!idMatch) return;
    var pid = idMatch[1];
    var lotOk = document.getElementById('ph_lot_ok_' + pid);
    var dlcOk = document.getElementById('ph_dlc_ok_' + pid);
    var deuxCochees = lotOk && lotOk.checked && dlcOk && dlcOk.checked;
    if (!deuxCochees) {
      img.src = '';
      var wrapper = document.getElementById('photo_wrapper_' + pid);
      if (wrapper) wrapper.style.display = 'none';
      var status = document.getElementById('photo_status_' + pid);
      if (status) status.style.display = 'none';
      if (lotOk) lotOk.checked = false;
      if (dlcOk) dlcOk.checked = false;
    }
  });
  pdfData = collecterDonnees();
  // Mémoriser le fournisseur pour l'autocomplétion des prochaines réceptions.
  try { memoFournisseur((document.getElementById('r_fournisseur') || {value:''}).value); } catch(e) {}
  // Mémoriser les produits reçus (catégorie + nom) pour les boutons « déjà reçus ».
  try { memoProduitsReceptionDepuisEcran(); } catch(e) {}
  document.getElementById('modalPdf').classList.add('visible');
  sauvegarderHistorique('Réception & Traçabilité', prenom);
  sauvegarderDonnesModule('page-reception');
  stopBrouillonAuto(); effacerBrouillon('page-reception');
}

