function renderMods(cat) {
  var grid = document.getElementById('modsGrid');
  // V122 — Filtrage par secteur : un module portant une étiquette `secteurs` n'est affiché
  // que si le secteur actif y figure (ex. Plat témoin 72h, Liaison chaude/froide, Registre
  // des convives, Analyses microbio → restauration collective uniquement ; Huiles de friture
  // → tous sauf boucherie). Les modules sans `secteurs` restent visibles partout.
  var sect = (typeof SECTEUR_ACTIF !== 'undefined' && SECTEUR_ACTIF) ? SECTEUR_ACTIF : '';
  var mods = MODULES.filter(function(m) {
    if (m.cat !== cat) return false;
    if (m.secteurs && m.secteurs.indexOf(sect) === -1) return false;
    return true;
  });
  // Statut RÉEL « fait / à faire aujourd'hui » (remplace les anciens badges statiques
  // « Auj. 3 / OK » qui étaient trompeurs). Seuls les contrôles quotidiens suivis ont
  // un statut ; les autres modules n'affichent plus de badge factice.
  var _statut = (typeof _tdbStatutMap === 'function') ? _tdbStatutMap() : {};
  grid.innerHTML = mods.map(function(m, i) {
    var st = _statut[m.id];
    var badge = st ? ('<div class="mod-badge' + (st === 'afaire' ? ' alert' : '') + '" style="background:' + (st === 'fait' ? '#dcfce7' : '#fee2e2') + ';color:' + (st === 'fait' ? '#15803d' : '#dc2626') + '">' + (st === 'fait' ? '✅ Fait' : '⬜ À faire') + '</div>') : '';
    return '<button class="mod ' + m.color + '" onclick="openModule(\'' + m.id + '\')" style="animation-delay:' + (i*0.04) + 's">' +
      '<div class="mod-ico">' + m.ico + '</div>' +
      '<div class="mod-name">' + m.name + '</div>' +
      (m.fn ? '<div class="mod-fn">' + m.fn + '</div>' : '') +
      badge +
      (m.ddpp ? '<div class="mod-ddpp">🔴 DDPP</div>' : '') +
      '<div class="mod-freq">' + m.freq + '</div>' +
      '</button>';
  }).join('');
}

// V122 — Masque, dans les listes « Export par module » (Guide + Expert), les boutons
// des modules non pertinents pour le secteur actif (même source de vérité que renderMods :
// l'étiquette `secteurs` de MODULES). Ex. la friteuse disparaît de l'export en boucherie.
function filtrerExportsParSecteur() {
  var sect = (typeof SECTEUR_ACTIF !== 'undefined' && SECTEUR_ACTIF) ? SECTEUR_ACTIF : '';
  if (!sect) return;
  MODULES.forEach(function(m) {
    if (!m.secteurs) return; // module universel : toujours proposé
    var visible = m.secteurs.indexOf(sect) > -1;
    ['chk-guide-' + m.id, 'chk-exp-' + m.id].forEach(function(chkId) {
      var chk = document.getElementById(chkId);
      if (!chk) return;
      // La ligne = le conteneur direct (case + bouton). On masque toute la ligne.
      var ligne = chk.parentElement;
      if (ligne) ligne.style.display = visible ? '' : 'none';
      if (!visible) chk.checked = false; // évite d'exporter un module masqué
    });
    // V123 — Mode guidé : masque aussi le raccourci d'accueil « Que voulez-vous faire ? »
    // du module non pertinent (ex. carte « Je contrôle mon huile de friture » en boucherie).
    var carte = document.getElementById('guidecard-' + m.id);
    if (carte) carte.style.display = visible ? '' : 'none';
  });
  // V124 — Mode guidé : bloc « Restauration collective » (plat témoin, liaison, convives,
  // analyses micro) affiché uniquement pour ce secteur, pour parité avec le mode Expert.
  var blocColl = document.getElementById('guideblock-collective');
  if (blocColl) blocColl.style.display = (sect === 'collective') ? '' : 'none';
}

function switchCat(cat, tab) {
  currentCat = cat;
  document.querySelectorAll('.ctab').forEach(function(t) { t.classList.remove('active'); });
  tab.classList.add('active');
  var cfg = CAT_CONFIG[cat];
  var band = document.getElementById('catBand');
  band.className = 'cat-band ' + cfg.cls;
  band.innerHTML = '<div class="cat-band-ico">' + cfg.ico + '</div><div><div class="cat-band-title">' + cfg.title + '</div><div class="cat-band-sub">' + cfg.sub + '</div></div>';
  renderMods(cat);
}

