function updateModuleHeader(pageId, moduleId) {
  var page = document.getElementById(pageId);
  if (!page) return;
  var titleEl = page.querySelector('.mod-header-title');
  var introEl = page.querySelector('.mod-header-intro');
  // Mémoriser une fois les libellés d'origine (= secteur resto, dans le HTML)
  // pour pouvoir les restaurer quand on revient sur resto.
  if (titleEl && titleEl.dataset.defaultTitle == null) titleEl.dataset.defaultTitle = titleEl.textContent;
  if (introEl && introEl.dataset.defaultIntro == null) introEl.dataset.defaultIntro = introEl.textContent;
  var cfg = null;
  if (SECTEUR_ACTIF === 'bp') cfg = BP_HEADERS[moduleId];
  else if (SECTEUR_ACTIF === 'rapide') cfg = RAPIDE_HEADERS[moduleId];
  else if (SECTEUR_ACTIF === 'boucherie') cfg = BOUCHERIE_HEADERS[moduleId];
  else if (SECTEUR_ACTIF === 'collective') cfg = COLLECTIVE_HEADERS[moduleId];
  // Secteur resto / par défaut : restaurer le titre d'origine au lieu de laisser
  // figé celui d'un autre secteur (sinon titre « Boulangerie » alors qu'on est en
  // resto → contrôle mal étiqueté).
  if (!cfg) {
    if (titleEl && titleEl.dataset.defaultTitle != null) titleEl.textContent = titleEl.dataset.defaultTitle;
    if (introEl && introEl.dataset.defaultIntro != null) introEl.textContent = introEl.dataset.defaultIntro;
    return;
  }
  if (titleEl) titleEl.textContent = cfg.title;
  if (introEl) introEl.textContent = cfg.intro;

  // Hygiène — adapter la ligne viande
  if (moduleId === 'hygiene') {
    var viEl = document.getElementById('hyg_viande_row');
    if (viEl) {
      if (SECTEUR_ACTIF === 'bp') viEl.querySelector('.flabel').textContent = 'Après manipulation de matières premières crues (oeufs, crèmes...)';
      else if (SECTEUR_ACTIF === 'rapide') viEl.querySelector('.flabel').textContent = 'Après manipulation de viande crue / préparation de burgers';
      else if (SECTEUR_ACTIF === 'boucherie') viEl.querySelector('.flabel').textContent = 'Après toute manipulation de viande crue ou abats — Obligatoire';
      else if (SECTEUR_ACTIF === 'collective') viEl.querySelector('.flabel').textContent = 'Après manipulation de viandes crues, légumes non lavés ou déchets';
    }
  }

  // Zones nettoyage ouverture
  if (moduleId === 'ouverture') {
    var zonesEl = document.getElementById('ouverture_zones');
    if (zonesEl) {
      var zones = [];
      if (SECTEUR_ACTIF === 'bp') zones = ['Four(s) & sole','Pétrin(s)','Laminoir / Façonneuse','Plans de travail fournil','Tours réfrigérées & moules','Chambres froides beurre & crèmes','Plonge & ustensiles','Sol du fournil','Vestiaires & sanitaires'];
      else if (SECTEUR_ACTIF === 'rapide') zones = ['Friteuse(s)','Grill / Plancha','Bain-marie / Vitrine chaude','Comptoir de service','Écrans de commande','Zone préparation / assemblage','Plans de travail','Plonge & ustensiles','Sol cuisine & salle','Vestiaires & sanitaires'];
      else if (SECTEUR_ACTIF === 'boucherie') zones = ['Billot(s)','Couteaux & affûteurs','Scie à os / Scie à ruban','Hachoir','Salle de découpe (sol, murs, tables)','Crochets & rails','Chambre froide (portes, étagères)','Vitrine réfrigérée vente','Plonge & bacs','Vestiaires & sanitaires'];
      else if (SECTEUR_ACTIF === 'collective') zones = ['Plans de travail froid & chaud','Zone de préparation froide','Zone de cuisson (fours, plaques)','Bain-marie & équipements de maintien','Légumerie / Zone épluchage','Plonge & batterie de cuisine','Chambres froides (portes, étagères)','Cellule de refroidissement','Sol cuisine & office','Vestiaires & sanitaires'];
      if (zones.length) zonesEl.innerHTML = zones.map(function(z) {
        return '<div class="frow"><div class="flabel">' + z + '</div><div class="status-group"><button class="status-btn" onclick="selHyg(this,\'ok\')">✅ Propre et conforme</button><button class="status-btn" onclick="selHyg(this,\'bad\')">✗ Non conforme</button></div></div>';
      }).join('');
    }
  }

  // Zones nettoyage fermeture
  if (moduleId === 'fermeture') {
    var ptBlock = document.getElementById('plans_travail_block');
    if (ptBlock) {
      if (SECTEUR_ACTIF === 'bp') {
        ptBlock.querySelector('.fblock-title').textContent = '⚠️ Plans de travail — Séparation matières premières';
        ptBlock.querySelector('div[style*="fff8f8"]').textContent = 'En boulangerie, les plans de travail doivent être séparés par type de production. Si partagé : nettoyage + désinfection complets obligatoires.';
      } else if (SECTEUR_ACTIF === 'rapide' || SECTEUR_ACTIF === 'boucherie' || SECTEUR_ACTIF === 'collective') {
        ptBlock.querySelector('.fblock-title').textContent = '⚠️ Zones de préparation — Séparation cru / cuit';
        ptBlock.querySelector('div[style*="fff8f8"]').textContent = 'Séparez les zones cru / cuit / assemblage. Si zone partagée : nettoyage et désinfection complets obligatoires entre chaque utilisation.';
      } else if (SECTEUR_ACTIF === 'boucherie') {
        ptBlock.querySelector('.fblock-title').textContent = '⚠️ Salle de découpe — Hygiène des surfaces en contact';
        ptBlock.querySelector('div[style*="fff8f8"]').textContent = 'En boucherie, toute surface en contact avec la viande doit être nettoyée et désinfectée entre chaque espèce animale. Billot, couteaux et scies : désinfection complète après chaque usage.';
      } else if (SECTEUR_ACTIF === 'collective') {
        ptBlock.querySelector('.fblock-title').textContent = '⚠️ Plans de travail — Séparation cru / cuit / allergen';
        ptBlock.querySelector('div[style*="fff8f8"]').textContent = 'En restauration collective, séparez les zones par type de préparation (légumerie, viandes crues, poissons, préparations froides, cuisines chaudes). Nettoyage et désinfection complets entre chaque utilisation.';
      }
    }
    var zonesF = document.getElementById('fermeture_zones');
    if (zonesF) {
      var zonesFF = [];
      if (SECTEUR_ACTIF === 'bp') zonesFF = ['Four(s) & sole','Pétrin(s)','Laminoir / Façonneuse','Plans de travail fournil','Tours réfrigérées & moules','Chambres froides beurre & crèmes','Vitrine réfrigérée','Moules & plaques','Plonge & ustensiles','Sol du fournil','Zone stockage déchets'];
      else if (SECTEUR_ACTIF === 'rapide') zonesFF = ['Friteuse(s)','Grill / Plancha','Bain-marie / Vitrine chaude','Comptoir & zone caisse','Écrans de commande','Zone préparation / assemblage','Réfrigérateurs garnitures','Plans de travail','Plonge & ustensiles','Sol cuisine & salle','Zone stockage déchets'];
      else if (SECTEUR_ACTIF === 'boucherie') zonesFF = ['Billot(s)','Couteaux & affûteurs','Scie à os','Hachoir','Salle de découpe complète','Crochets & rails','Chambre froide viandes','Vitrine réfrigérée vente','Plonge & bacs','Sol & murs salle de découpe','Zone stockage déchets'];
      else if (SECTEUR_ACTIF === 'collective') zonesFF = ['Plans de travail froid & chaud','Zone de cuisson','Bain-marie & maintien chaud','Légumerie','Cellule de refroidissement','Chambres froides','Matériel de distribution','Vaissellerie & couverts','Plonge & batterie','Sol & murs cuisine','Zone stockage déchets'];
      if (zonesFF.length) zonesF.innerHTML = zonesFF.map(function(z) {
        return '<div class="frow"><div class="flabel">' + z + '</div><div class="status-group"><button class="status-btn" onclick="selHyg(this,\'ok\')">✅ Conforme</button><button class="status-btn" onclick="selHyg(this,\'bad\')">✗ Non nettoyé → NC</button></div></div>';
      }).join('');
    }
  }
}

