function takePhotoTraca(id) {
  var input = document.createElement('input');
  input.type = 'file'; input.accept = 'image/*'; input.capture = 'environment';
  // V116 — Fix bug iPhone Safari : input doit être dans le DOM
  input.style.position = 'absolute';
  input.style.left = '-9999px';
  document.body.appendChild(input);
  input.onchange = function(e) {
    var file = e.target.files[0];
    if (!file) { try { document.body.removeChild(input); } catch(_){} return; }
    var reader = new FileReader();
    reader.onload = function(ev) {
      // V80 — Compression
      compresserPhoto(ev.target.result, function(compressed) {
        var img = document.getElementById('t_photo_' + id);
        if (img) { img.src = compressed; img.style.display = 'block'; }
        // V116 — Range la photo dans la boîte d'attente (cloud)
        apresLaCapturePhoto(compressed, id, 'etiquette_tracabilite');
        // V116 — Nettoyage
        try { document.body.removeChild(input); } catch(_){}
      });
    };
    reader.readAsDataURL(file);
  };
  input.click();
}

function initSigTraca() {
  sigCanvasTraca = document.getElementById('sigCanvasTraca');
  if (!sigCanvasTraca) return;
  sigCtxTraca = sigCanvasTraca.getContext('2d');
  hasSigTraca = false; isDrawingTraca = false;

  var dpr = window.devicePixelRatio || 1;
  var w = sigCanvasTraca.parentElement.clientWidth || 340;
  sigCanvasTraca.width = Math.round(w * dpr);
  sigCanvasTraca.height = Math.round(140 * dpr);
  sigCanvasTraca.style.width = w + 'px';
  sigCanvasTraca.style.height = '140px';
  sigCtxTraca.scale(dpr, dpr);
  sigCtxTraca.strokeStyle = '#1a1a2e';
  sigCtxTraca.lineWidth = 2.5;
  sigCtxTraca.lineCap = 'round';
  sigCtxTraca.lineJoin = 'round';

  function pos(e) { var r = sigCanvasTraca.getBoundingClientRect(); var s = e.touches ? e.touches[0] : e; return {x:s.clientX-r.left,y:s.clientY-r.top}; }
  function start(e) { e.preventDefault(); isDrawingTraca=true; var p=pos(e); sigCtxTraca.beginPath(); sigCtxTraca.moveTo(p.x,p.y); }
  function move(e)  { e.preventDefault(); if(!isDrawingTraca)return; var p=pos(e); sigCtxTraca.lineTo(p.x,p.y); sigCtxTraca.stroke(); hasSigTraca=true; }
  function stop(e)  { e.preventDefault(); isDrawingTraca=false; }

  sigCanvasTraca.addEventListener('mousedown',start);
  sigCanvasTraca.addEventListener('mousemove',move);
  sigCanvasTraca.addEventListener('mouseup',stop);
  sigCanvasTraca.addEventListener('mouseleave',stop);
  sigCanvasTraca.addEventListener('touchstart',start,{passive:false});
  sigCanvasTraca.addEventListener('touchmove',move,{passive:false});
  sigCanvasTraca.addEventListener('touchend',stop,{passive:false});
}

function clearSigTraca() {
  if (!sigCtxTraca || !sigCanvasTraca) return;
  sigCtxTraca.clearRect(0,0,sigCanvasTraca.width,sigCanvasTraca.height);
  hasSigTraca = false;
}

async function validerTracabilite() {
  var prenom = document.getElementById('sig_prenom').value.trim();
  var nom = document.getElementById('sig_nom').value.trim();
  var reqEl = document.getElementById('sig_required');
  if (!hasSigTraca || !prenom || !nom) {
    reqEl.style.display = 'flex';
    reqEl.scrollIntoView({behavior:'smooth',block:'center'});
    return;
  }
  reqEl.style.display = 'none';
  // V113 — D : Sauvegarde Supabase AVANT PDF (awaited, après check signature)
  if (SB_READY && ETAB_ID) {
    try {
      await sbSauvegarderModule('tracabilite', {secteur: SECTEUR_ACTIF, etab: ETAB.nom, timestamp: new Date().toISOString()}, prenom + ' ' + nom);
    } catch(eSB) { console.warn('Supabase save error (tracabilite):', eSB); }
  }

  // Collect data for PDF
  var blocks = document.querySelectorAll('[id^="traca_"]');
  var produits = [];
  blocks.forEach(function(block) {
    var id = block.id.replace('traca_','');
    var typeEl = document.getElementById('t_type_' + id);
    produits.push({
      num: id,
      type: typeEl ? typeEl.options[typeEl.selectedIndex].text : '—',
      lot: document.getElementById('t_lot_' + id) ? document.getElementById('t_lot_' + id).value || 'Non renseigné' : '—',
      fournisseur: document.getElementById('t_fourn_' + id) ? document.getElementById('t_fourn_' + id).value || '—' : '—',
      contact: document.getElementById('t_contact_' + id) ? document.getElementById('t_contact_' + id).value || '—' : '—',
      origine: document.getElementById('t_origine_' + id) ? document.getElementById('t_origine_' + id).value || '—' : '—',
      dlc: document.getElementById('t_dlc_' + id) ? document.getElementById('t_dlc_' + id).value || '—' : '—',
      stockage: document.getElementById('t_stockage_' + id) ? document.getElementById('t_stockage_' + id).value || '—' : '—',
    });
  });
  tracaPdfData = {
    timestamp: getNowStr(),
    signataire: prenom + ' ' + nom,
    produits: produits,
  };
  // Synchro cloud : la traçabilité est un sous-flux de la réception (pas de page
  // dédiée) et n'appelait pas sauvegarderDonnesModule → elle n'arrivait JAMAIS
  // dans controles_haccp (la table lue par les rapports), et son contenu réel
  // (lots, fournisseurs) n'était sauvegardé nulle part. On pousse donc le
  // contrôle complet directement vers le cloud.
  try {
    if (typeof enregistrerControleHACCP === 'function' && (typeof ETAB_ID !== 'undefined' && ETAB_ID)) {
      enregistrerControleHACCP('Traçabilité produits reçus', {
        pageId: 'page-tracabilite',
        module: 'Traçabilité produits reçus',
        secteur: (typeof SECTEUR_ACTIF !== 'undefined' ? SECTEUR_ACTIF : ''),
        etab: (ETAB && ETAB.nom) || '',
        timestamp: tracaPdfData.timestamp,
        signe: tracaPdfData.signataire,
        signataire: tracaPdfData.signataire,
        produits: produits
      });
    }
  } catch(eTraca) { console.warn('sync traçabilité:', eTraca && eTraca.message); }
  document.getElementById('modalTracaPdf').classList.add('visible');
  sauvegarderHistorique('Traçabilité produits', document.getElementById('sig_prenom') ? document.getElementById('sig_prenom').value : '');
}

function downloadTracaPDF() {
  imprimerModule('page-reception', 'Tracabilite Produits Recus');
}

