// Formate une température pour l'affichage, sans double signe. Accepte une
// valeur brute (« 5 », « +5 », « -12 », « +6°C ») et renvoie « +5°C », « -12°C ».
// Renvoie '' si la valeur est vide/non numérique.
function fmtTemp(v) {
  if (v === null || v === undefined) return '';
  var s = String(v).trim();
  if (s === '') return '';
  // Retirer °C/°c et espaces, garder le signe et les chiffres. Virgule FR → point
  // (sinon parseFloat("3,5") = 3 → décimale perdue dans les PDF).
  s = s.replace(/°\s*c/ig, '').replace(/\s+/g, '').replace(',', '.');
  if (s === '' || isNaN(parseFloat(s))) return String(v); // non numérique → tel quel
  var n = parseFloat(s);
  return (n >= 0 ? '+' : '') + n + '°C';
}

function getTypesEnceintesActif() {
  var base = TYPES_ENCEINTES.base;
  var spec = TYPES_ENCEINTES[SECTEUR_ACTIF] || [];
  return base.concat(spec);
}

// SOURCE DE VÉRITÉ UNIQUE — Seuil réglementaire d'une enceinte à partir de son
// libellé. Utilisée par le Récap NC (et ailleurs) pour ne plus dépendre de
// listes de mots-clés incomplètes. Renvoie une chaîne formatée (« +2°C max »,
// « -18°C max », « +63°C min ») ou '' si indéterminable.
function seuilEnceinteDepuisLabel(label) {
  if (!label) return '';
  var L = String(label).toLowerCase();
  // 1) Correspondance exacte avec le catalogue TYPES_ENCEINTES (tous secteurs)
  try {
    var tous = TYPES_ENCEINTES.base.slice();
    Object.keys(TYPES_ENCEINTES).forEach(function(k){ if (k !== 'base') tous = tous.concat(TYPES_ENCEINTES[k]); });
    for (var i = 0; i < tous.length; i++) {
      var t = tous[i];
      if (t.label && L.indexOf(t.label.toLowerCase()) > -1 && t.seuil != null) {
        return (t.seuil >= 0 ? '+' : '') + t.seuil + '°C max';
      }
    }
  } catch(e) {}
  // 2) Seuil écrit dans le libellé : « (<=+2C) », « ≤ +2 °C », « (>=+63C) »
  var mMax = L.match(/<=?\s*([+-]?\d+)\s*°?\s*c/) || L.match(/≤\s*([+-]?\d+)\s*°?\s*c/);
  var mMin = L.match(/>=?\s*([+-]?\d+)\s*°?\s*c/) || L.match(/≥\s*([+-]?\d+)\s*°?\s*c/);
  var fmt = function(x){ return (x.charAt(0)==='-'||x.charAt(0)==='+' ? '' : '+') + x + '°C'; };
  if (mMax) return fmt(mMax[1]) + ' max';
  if (mMin) return fmt(mMin[1]) + ' min';
  // 3) Dernier recours : mots-clés génériques.
  // On retire les accents pour reconnaître aussi « congélateur », « réfrigérée »,
  // « négatif », « fraîche »… (sinon un nom personnalisé accentué n'était pas reconnu).
  var Ln = L.normalize('NFD').replace(/[̀-ͯ]/g, '');
  if (Ln.indexOf('congel')>-1||Ln.indexOf('surgel')>-1||Ln.indexOf('nega')>-1) return '-18°C max';
  if (Ln.indexOf('chaud')>-1) return '+63°C min';
  if (Ln.indexOf('cellule')>-1) return '+10°C en 2h max';
  if (Ln.indexOf('ultra')>-1) return '+2°C max';
  if (Ln.indexOf('frigo')>-1||Ln.indexOf('refrig')>-1||Ln.indexOf('frais')>-1||Ln.indexOf('posit')>-1||Ln.indexOf('froide')>-1) return '+4°C max';
  return '';
}

