var _CATALOGUE_NC = null;
function _nrmNC(s){ return String(s||'').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g,'').replace(/\([^)]*\)/g,'').replace(/[^a-z0-9]+/g,' ').trim(); }
function _buildCatalogueNC(){ _CATALOGUE_NC = {}; CATALOGUE_NC_DEFS.forEach(function(d){ d.labels.forEach(function(l){ _CATALOGUE_NC[_nrmNC(l)] = d; }); }); }
function getCatalogueNC(label){
  if (!_CATALOGUE_NC) _buildCatalogueNC();
  var k = _nrmNC(label);
  if (!k) return null;
  if (_CATALOGUE_NC[k]) return _CATALOGUE_NC[k];
  for (var key in _CATALOGUE_NC){ if (key.length > 5 && (k.indexOf(key) >= 0 || key.indexOf(k) >= 0)) return _CATALOGUE_NC[key]; }
  return null;
}
// Affiche/masque le champ texte "Autre" sous le menu déroulant des NC constatées
window.inspToggleAutreConstat = function(sel){
  var row = sel.closest('.frow'); var next = row ? row.nextElementSibling : null;
  var txt = (sel.options[sel.selectedIndex] ? sel.options[sel.selectedIndex].text : '');
  var isAutre = /autre/i.test(txt);
  if (next && next.querySelector && next.querySelector('.nc-constat-autre')) next.style.display = isAutre ? '' : 'none';
};

function selHyg(btn, type) {
  var grp = btn.closest('.status-group');
  grp.querySelectorAll('.status-btn').forEach(function(b) {
    b.classList.remove('active-ok','active-warn','active-bad');
  });
  btn.classList.add(type === 'ok' ? 'active-ok' : type === 'warn' ? 'active-warn' : type === 'na' ? 'active-warn' : 'active-bad');

  // ── ACTION CORRECTIVE GÉNÉRIQUE (tous modules, tous secteurs) ──
  var frow = grp.closest('.frow') || grp.parentElement;
  if (!frow) return;

  // Chercher action existante après ce frow
  // Au passage on collecte aussi le bandeau nc-auto qui doit être affiché
  var sibling = frow.nextElementSibling;
  var existingAction = null;
  var existingNcAuto = null;
  while (sibling) {
    if (sibling.classList.contains('nc-action')) { existingAction = sibling; break; }
    if (sibling.classList.contains('nc-auto')) { existingNcAuto = sibling; sibling = sibling.nextElementSibling; continue; }
    break;
  }

  if (type === 'bad') {
    if (existingAction) {
      existingAction.classList.add('visible');
      // CRITIQUE : afficher aussi le bandeau nc-auto pour que la NC soit comptée dans le rapport DDPP
      if (existingNcAuto) {
        existingNcAuto.style.display = 'flex';
      }
      // V-NC16 — Bloc pré-écrit : injecter en TÊTE le menu "Non-conformité
      // constatée" (catalogue) pour garder l'ordre logique NC → action partout.
      // On tague d'abord le select/input d'action existant pour que les
      // fonctions de lecture ne confondent pas le constat avec l'action.
      try {
        var _lblX = frow.querySelector('.flabel');
        var _fullX = _lblX ? _lblX.textContent.trim().replace(/[⚠️🔴⚡*]/g,'').trim() : '';
        var _catX = (typeof getCatalogueNC === 'function') ? getCatalogueNC(_fullX) : null;
        var _actSelX = existingAction.querySelector('select');
        if (_catX && _actSelX && !existingAction.querySelector('.nc-constat-select')) {
          if (!_actSelX.classList.contains('nc-act-select')) _actSelX.classList.add('nc-act-select');
          var _detX = existingAction.querySelector('input[type="text"]');
          if (_detX && !_detX.classList.contains('nc-act-detail')) _detX.classList.add('nc-act-detail');
          window._haccp_ga_counter = (window._haccp_ga_counter || 0) + 1;
          var _cidX = 'gax_' + Date.now() + '_' + window._haccp_ga_counter;
          var _coptsX = _catX.ncs.map(function(n){ return '<option>' + n + '</option>'; }).join('');
          var _wrapX = document.createElement('div');
          _wrapX.innerHTML =
            '<div style="font-size:11px;color:#15803d;font-weight:700;margin:0 0 8px">✔ Attendu : ' + _catX.norme + '</div>' +
            '<div class="frow"><div class="flabel">Non-conformité constatée</div>' +
              '<select class="nc-constat-select" id="c_' + _cidX + '" onchange="inspToggleAutreConstat(this)">' +
                '<option value="">-- Sélectionner --</option>' + _coptsX + '<option>Autre (préciser)</option>' +
              '</select></div>' +
            '<div class="frow" style="display:none"><div class="flabel">Préciser la non-conformité</div>' +
              '<input type="text" class="nc-constat-autre" id="ca_' + _cidX + '" placeholder="Décrivez la non-conformité constatée"/></div>';
          var _titleX = existingAction.querySelector('.nc-action-title');
          if (_titleX && _titleX.nextSibling) {
            while (_wrapX.firstChild) existingAction.insertBefore(_wrapX.firstChild, _titleX.nextSibling);
          } else {
            while (_wrapX.firstChild) existingAction.insertBefore(_wrapX.firstChild, existingAction.firstChild);
          }
        }
      } catch(eInjX) {}
    } else {
      // Créer action générique
      // Compteur incrémental pour garantir l'unicité (Date.now() pouvait collisionner sur clics rapides)
      window._haccp_ga_counter = (window._haccp_ga_counter || 0) + 1;
      var aId = 'ga_' + Date.now() + '_' + window._haccp_ga_counter;
      var lbl = frow.querySelector('.flabel');
      var fullLabel = lbl ? lbl.textContent.trim().replace(/[⚠️🔴⚡*]/g,'').trim() : 'Non-conformité';
      var labelTxt = fullLabel.substring(0,50);
      // V-NC16 — Catalogue adapté au point de contrôle (norme + NC + actions)
      var _cat = (typeof getCatalogueNC === 'function') ? getCatalogueNC(fullLabel) : null;
      var _constatOpts = _cat ? _cat.ncs.map(function(n){ return '<option>' + n + '</option>'; }).join('') : '';
      var _genActions = ['Correction immédiate effectuée','Mesure provisoire en place','Responsable informé','Prestataire/fournisseur contacté','Procédure de remédiation engagée','Document mis à jour','Affichage remplacé/mis à jour','Zone nettoyée et désinfectée'];
      var _actList = (_cat && _cat.actions && _cat.actions.length) ? _cat.actions : _genActions;
      var _actOpts = _actList.map(function(a){ return '<option>' + a + '</option>'; }).join('');
      var actionDiv = document.createElement('div');
      actionDiv.className = 'nc-action visible';
      actionDiv.setAttribute('data-generic','1');
      actionDiv.innerHTML =
        '<div class="nc-action-title">⚠️ Non-conformité — ' + labelTxt + '</div>' +
        (_cat ? '<div style="font-size:11px;color:#15803d;font-weight:700;margin:-2px 0 8px">✔ Attendu : ' + _cat.norme + '</div>' : '') +
        // Ordre logique : on déclare d'abord CE QUI ne va pas (non-conformité
        // constatée), puis l'action corrective. Les fonctions de lecture ciblent
        // explicitement .nc-act-select / .nc-act-detail, donc l'ordre du DOM est libre.
        (_cat ?
          '<div class="frow"><div class="flabel">Non-conformité constatée</div>' +
            '<select class="nc-constat-select" id="c_' + aId + '" onchange="inspToggleAutreConstat(this)">' +
              '<option value="">-- Sélectionner --</option>' +
              _constatOpts +
              '<option>Autre (préciser)</option>' +
            '</select>' +
          '</div>' +
          '<div class="frow" style="display:none"><div class="flabel">Préciser la non-conformité</div>' +
            '<input type="text" class="nc-constat-autre" id="ca_' + aId + '" placeholder="Décrivez la non-conformité constatée"/>' +
          '</div>'
        : '') +
        '<div class="frow"><div class="flabel">Action corrective</div>' +
          '<select class="nc-act-select" id="s_' + aId + '">' +
            '<option value="">-- Sélectionner --</option>' +
            _actOpts +
            '<option>Autre action (préciser ci-dessous)</option>' +
          '</select>' +
        '</div>' +
        '<div class="frow"><div class="flabel">Précisions</div>' +
          '<input type="text" class="nc-act-detail" id="d_' + aId + '" placeholder="Précisez si besoin..."/>' +
        '</div>' +
        '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">' +
          '<div class="frow"><div class="flabel">Responsable</div>' +
            '<input type="text" id="r_' + aId + '" placeholder="Nom & prénom"/>' +
          '</div>' +
          '<div class="frow"><div class="flabel">Heure</div>' +
            '<input type="time" id="h_' + aId + '"/>' +
          '</div>' +
        '</div>';
      frow.parentNode.insertBefore(actionDiv, frow.nextSibling);
    }
  } else {
    // Masquer l'action existante
    if (existingAction) existingAction.classList.remove('visible');
    // Masquer aussi le bandeau nc-auto associé
    if (existingNcAuto) existingNcAuto.style.display = 'none';
    // Masquer les actions génériques créées dynamiquement
    var nextEl = frow.nextElementSibling;
    if (nextEl && nextEl.classList.contains('nc-action') && nextEl.getAttribute('data-generic')) {
      nextEl.classList.remove('visible');
    }
  }
}

function toggleGastro(show, btn) {
  var gastroBtn = document.getElementById('gastro_aucun');
  var casBtn = document.getElementById('gastro_cas');
  if (gastroBtn) gastroBtn.classList.remove('active-ok','active-bad');
  if (casBtn) casBtn.classList.remove('active-ok','active-bad');
  if (show) {
    if (casBtn) casBtn.classList.add('active-bad');
    document.getElementById('gastroZone').style.display = 'block';
    if (salariesCount === 0) ajouterSalarie();
  } else {
    if (gastroBtn) gastroBtn.classList.add('active-ok');
    document.getElementById('gastroZone').style.display = 'none';
  }
}

function ajouterSalarie() {
  salariesCount++;
  var id = salariesCount; // Variable locale pour utilisation dans les templates
  var list = document.getElementById('salariesList');
  var div = document.createElement('div');
  div.className = 'fblock rb';
  div.style.marginBottom = '10px';
  div.innerHTML =
    '<div class="fblock-title"><span>🤒 Salarié évincé N°' + salariesCount + '</span></div>' +
    '<div class="frow"><div class="flabel">Nom & prénom</div><input class="finput" placeholder="Nom & prénom du salarié évincé"/></div>' +
    '<div class="frow"><div class="flabel">Éviction confirmée</div>' +
      '<div class="status-group">' +
        '<button class="status-btn active-bad" onclick="selHyg(this,\'bad\')">🔴 Évincé — Ne peut pas travailler</button>' +
      '</div>' +
    '</div>' +
    '<div class="nc-auto" id="nc_sal_' + id + '">⚡ NC automatique générée pour ce salarié</div>' +
    buildNCAction('nc_sal_' + id);
  list.appendChild(div);
}

function initSigHyg() {
  sigCanvasHyg = document.getElementById('sigCanvasHyg');
  if (!sigCanvasHyg) return;
  sigCtxHyg = sigCanvasHyg.getContext('2d');
  hasSigHyg = false; isDrawingHyg = false;
  var dpr = window.devicePixelRatio || 1;
  var w = sigCanvasHyg.parentElement.clientWidth || 340;
  sigCanvasHyg.width = Math.round(w * dpr);
  sigCanvasHyg.height = Math.round(140 * dpr);
  sigCanvasHyg.style.width = w + 'px';
  sigCanvasHyg.style.height = '140px';
  sigCtxHyg.scale(dpr, dpr);
  sigCtxHyg.strokeStyle = '#1a1a2e'; sigCtxHyg.lineWidth = 2.5;
  sigCtxHyg.lineCap = 'round'; sigCtxHyg.lineJoin = 'round';
  function pos(e){var r=sigCanvasHyg.getBoundingClientRect();var s=e.touches?e.touches[0]:e;return{x:s.clientX-r.left,y:s.clientY-r.top};}
  function start(e){e.preventDefault();isDrawingHyg=true;var p=pos(e);sigCtxHyg.beginPath();sigCtxHyg.moveTo(p.x,p.y);}
  function move(e){e.preventDefault();if(!isDrawingHyg)return;var p=pos(e);sigCtxHyg.lineTo(p.x,p.y);sigCtxHyg.stroke();hasSigHyg=true;}
  function stop(e){e.preventDefault();isDrawingHyg=false;}
  sigCanvasHyg.addEventListener('mousedown',start);
  sigCanvasHyg.addEventListener('mousemove',move);
  sigCanvasHyg.addEventListener('mouseup',stop);
  sigCanvasHyg.addEventListener('mouseleave',stop);
  sigCanvasHyg.addEventListener('touchstart',start,{passive:false});
  sigCanvasHyg.addEventListener('touchmove',move,{passive:false});
  sigCanvasHyg.addEventListener('touchend',stop,{passive:false});
}

function clearSigHyg() {
  if (!sigCtxHyg||!sigCanvasHyg) return;
  sigCtxHyg.clearRect(0,0,sigCanvasHyg.width,sigCanvasHyg.height);
  hasSigHyg = false;
}

async function validerHygiene() {
  var prenom = document.getElementById('hyg_sig_prenom').value.trim();
  var nom = document.getElementById('hyg_sig_nom').value.trim();
  var reqEl = document.getElementById('hyg_sig_required');
  if (!hasSigHyg || !prenom || !nom) {
    reqEl.style.display = 'flex';
    reqEl.scrollIntoView({behavior:'smooth',block:'center'});
    return;
  }
  reqEl.style.display = 'none';
  // V113 — D : Sauvegarde Supabase AVANT PDF (awaited, après check signature)
  if (SB_READY && ETAB_ID) {
    try {
      await sbSauvegarderModule('hygiene', {secteur: SECTEUR_ACTIF, etab: ETAB.nom, timestamp: new Date().toISOString()}, prenom + ' ' + nom);
    } catch(eSB) { console.warn('Supabase save error (hygiene):', eSB); }
  }
  document.getElementById('modalHygPdf').classList.add('visible');
  sauvegarderHistorique('Hygiène & Tenue', prenom);
  sauvegarderDonnesModule('page-hygiene');
  stopBrouillonAuto(); effacerBrouillon('page-hygiene');
}

function downloadHygPDF() {
  imprimerModule('page-hygiene', 'Hygiene & Tenue Personnel');
}

function confirmerSansHygPDF() {
  showConfirm('🖐️', 'Hygiène — sans PDF', 'Sans PDF vous n\'avez pas de preuve legale. Continuez seulement si vous imprimez ce document.', 'Continuer quand même', '', function(ok){ if(ok) fermerModalHyg(); });
}
function fermerModalHyg() {
  document.getElementById('modalHygPdf').classList.remove('visible');
  showPage('page-guide');
}

