function showOuvNC(actif) {
  var block = document.getElementById('ouv_nc_block');
  var oui = document.getElementById('ouv_nc_oui');
  var non = document.getElementById('ouv_nc_non');
  if (block) block.style.display = actif ? 'block' : 'none';
  if (oui) oui.classList.toggle('active-bad', actif);
  if (non) non.classList.toggle('active-ok', !actif);
  if (actif) {
    var now = new Date();
    var heureEl = document.getElementById('ouv_nc_heure');
    if (heureEl && !heureEl.value) heureEl.value = String(now.getHours()).padStart(2,'0') + ':' + String(now.getMinutes()).padStart(2,'0');
  }
}

