function getViandOptions() {
  var opts = '<option value="">-- Sélectionner le type --</option>';
  var types = getBySection(TYPES_VIANDE, TYPES_CUISSON_BP, TYPES_CUISSON_RAPIDE, TYPES_CUISSON_BOUCHERIE, TYPES_CUISSON_COLLECTIVE);
  if (SECTEUR_ACTIF === 'bp') {
    types.forEach(function(v) {
      var seuilLabel = v.seuil ? v.seuil + (v.seuilMax ? '-' + v.seuilMax : '') + ' ' + v.unite : 'T° à définir';
      opts += '<option value="' + (v.seuil || 'custom') + '">' + v.label + ' → ' + seuilLabel + '</option>';
    });
  } else if (SECTEUR_ACTIF === 'rapide' || SECTEUR_ACTIF === 'boucherie' || SECTEUR_ACTIF === 'collective') {
    types.forEach(function(v) {
      var seuilLabel = v.seuil ? v.seuil + ' ' + v.unite : 'T° à définir';
      opts += '<option value="' + (v.seuil || 'custom') + '">' + v.label + ' → ' + seuilLabel + '</option>';
    });
  } else {
    types.forEach(function(v) {
      opts += '<option value="' + v.seuil + '">' + v.label + ' → +' + v.seuil + '°C min cœur</option>';
    });
  }
  opts += '<option value="custom">➕ Autre (saisie libre)</option>';
  return opts;
}

