function ajouterEtiquette() {
  // V80 — Numérotation DOM réel
  var container = document.getElementById('etiqContainer');
  if (container) etiqCount = container.children.length + 1;
  else etiqCount++;
  var id = etiqCount;
  var div = document.createElement('div');
  div.className = 'fblock';
  div.id = 'etiq_' + id;
  div.style.borderLeft = '4px solid #0f766e';
  var delBtn = '<button class="btn-delete" onclick="supprimerEtiq(' + id + ')">✕</button>';
  var types = getBySection(TYPES_ETIQ, TYPES_ETIQ_BP, TYPES_ETIQ_RAPIDE, TYPES_ETIQ_BOUCHERIE, TYPES_ETIQ_COLLECTIVE);
  var typeOpts = types.map(function(t){ return '<option value="' + t.label + '">' + t.label + '</option>'; }).join('');
  div.innerHTML =
    '<div class="fblock-title"><span>🏷️ Produit N°' + id + '</span>' + delBtn + '</div>' +
    '<div class="frow"><div class="flabel">Type de produit</div>' +
      '<select class="fselect" id="etiq_type_' + id + '" onchange="onEtiqType(' + id + ')">' +
        '<option value="">-- Sélectionner --</option>' + typeOpts +
        '<option value="autre">➕ Autre (préciser)</option>' +
      '</select>' +
    '</div>' +
    '<div id="etiq_autre_wrap_' + id + '" style="display:none">' +
      '<div class="frow no-adv"><div class="flabel">Précisez le type</div>' +
        '<input class="finput" id="etiq_autre_' + id + '" placeholder="' + getBySection('Ex : Mousse au chocolat, Terrine...', 'Ex : Financier pistache, Bûche praliné...', 'Ex : Sauce barbecue maison, Garniture...', 'Ex : Farce maison, Préparation traiteur...', 'Ex : Sauce maison, Dessert préparé...') + '"/>' +
      '</div>' +
    '</div>' +
    '<div id="etiq_dlc_suggest_' + id + '" style="display:none;background:#f0fdf4;border:1px solid #bbf7d0;border-radius:10px;padding:10px 14px;margin-bottom:10px">' +
      '<div style="font-size:11px;font-weight:700;color:#15803d;margin-bottom:4px">📋 DLC réglementaire recommandée</div>' +
      '<div id="etiq_dlc_note_' + id + '" style="font-size:13px;font-weight:800;color:#15803d"></div>' +
      '<div id="etiq_dlc_conservation_' + id + '" style="font-size:11px;color:#374151;margin-top:2px"></div>' +
      '<div style="font-size:10px;color:#6b7280;margin-top:4px">⚠️ Référence HACCP FR — Arrêté 21/12/2009 — Règl. CE 852/2004</div>' +
    '</div>' +
    '<div class="frow no-adv"><div class="flabel">Nom du produit</div><input class="finput" id="etiq_nom_' + id + '" placeholder="' + getBySection('Ex : Crème brûlée, Sauce tomate...', 'Ex : Tarte fraises, Croissant, Entremets...', 'Ex : Burger préparé, Sauce maison, Wrap...', 'Ex : Viande hachée, Saucisse fraîche, Côte...', 'Ex : Plat cuisiné, Gratin, Sauce...') + '"/></div>' +
    '<div class="frow"><div class="flabel">Date de fabrication / ouverture</div><input class="finput" type="date" id="etiq_date_' + id + '" onchange="calcDLC(' + id + ')"/></div>' +
    '<div class="frow no-adv"><div class="flabel">DLC attribuée</div>' +
      '<div style="display:flex;gap:8px;align-items:center">' +
        '<input class="finput" type="date" id="etiq_dlc_' + id + '" style="flex:1"/>' +
        '<button onclick="calcDLC(' + id + ')" style="padding:8px 12px;background:#0f766e;color:white;border:none;border-radius:10px;font-size:12px;font-weight:700;cursor:pointer;white-space:nowrap">📅 Auto</button>' +
      '</div>' +
    '</div>' +
    '<div class="frow"><div class="flabel">Zone de stockage</div><input class="finput" id="etiq_zone_' + id + '" placeholder="Ex : Chambre froide 1 / Rayon A"/></div>' +
    (SECTEUR_ACTIF === 'collective' ? '<div class="frow"><div class="flabel" style="color:#0891b2;font-weight:700">⚖️ Grammage portion (Gemrcn)</div>' +
      '<div style="display:flex;gap:8px;align-items:center">' +
        '<input class="finput" type="number" id="etiq_grammage_' + id + '" placeholder="Ex : 150" style="flex:1"/><span style="font-size:13px;color:var(--mid)">g</span>' +
      '</div>' +
      '<div style="font-size:10px;color:#0891b2;margin-top:3px">Recommandations Gemrcn : viande 100-150g · poisson 100g · légumes 150g · féculents 150g</div>' +
    '</div>' : '') +
    '<div class="frow no-adv"><div class="flabel" style="color:#0f766e;font-weight:800">🖨️ Nombre d\'etiquettes a imprimer</div>' +
      '<div style="display:flex;align-items:center;gap:10px;margin-top:4px">' +
        '<button onclick="changeNbEtiq(' + id + ',-1)" style="width:38px;height:38px;border-radius:50%;border:2px solid #0f766e;background:white;color:#0f766e;font-size:20px;font-weight:700;cursor:pointer;flex-shrink:0">−</button>' +
        '<input type="number" id="etiq_nb_' + id + '" value="1" min="1" max="50" style="flex:1;padding:9px;border:1.5px solid #0f766e;border-radius:11px;font-size:18px;font-weight:800;text-align:center;color:#0f766e;font-family:JetBrains Mono,monospace"/>' +
        '<button onclick="changeNbEtiq(' + id + ',1)" style="width:38px;height:38px;border-radius:50%;border:2px solid #0f766e;background:#0f766e;color:white;font-size:20px;font-weight:700;cursor:pointer;flex-shrink:0">+</button>' +
      '</div>' +
    '</div>' +
    '<div class="frow"><div class="flabel">Étiquette apposée sur le contenant</div>' +
      '<div class="status-group">' +
        '<button class="status-btn" onclick="selHyg(this,\'ok\')">✅ Oui</button>' +
        '<button class="status-btn" onclick="selHyg(this,\'bad\')">✗ Non → NC</button>' +
      '</div>' +
    '</div>';
  container.appendChild(div);
}

function supprimerEtiq(id) {
  if (!confirm('Confirmer la suppression ?')) return;
  var el = document.getElementById('etiq_' + id);
  if (el) el.remove();
  renumeroterBlocs('#etiqContainer', 'Produit N°');
}

function onEtiqType(id) {
  var sel = document.getElementById('etiq_type_' + id);
  var wrap = document.getElementById('etiq_autre_wrap_' + id);
  var suggestDiv = document.getElementById('etiq_dlc_suggest_' + id);
  var noteEl = document.getElementById('etiq_dlc_note_' + id);
  var consEl = document.getElementById('etiq_dlc_conservation_' + id);
  if (wrap) wrap.style.display = sel.value === 'autre' ? 'block' : 'none';
  var types = getBySection(TYPES_ETIQ, TYPES_ETIQ_BP, TYPES_ETIQ_RAPIDE, TYPES_ETIQ_BOUCHERIE, TYPES_ETIQ_COLLECTIVE);
  var found = types.find(function(t){ return t.label === sel.value; });
  if (found && suggestDiv) {
    noteEl.textContent = found.dlcNote;
    consEl.textContent = '🌡️ ' + found.conservation;
    suggestDiv.style.display = 'block';
    var zoneEl = document.getElementById('etiq_zone_' + id);
    if (zoneEl && !zoneEl.value) zoneEl.placeholder = found.conservation;
    calcDLC(id);
  } else if (suggestDiv) {
    suggestDiv.style.display = 'none';
  }
}

function calcDLC(id) {
  var sel = document.getElementById('etiq_type_' + id);
  var dateEl = document.getElementById('etiq_date_' + id);
  var dlcEl = document.getElementById('etiq_dlc_' + id);
  if (!sel || !dateEl || !dlcEl || !dateEl.value) return;
  var types = getBySection(TYPES_ETIQ, TYPES_ETIQ_BP, TYPES_ETIQ_RAPIDE, TYPES_ETIQ_BOUCHERIE, TYPES_ETIQ_COLLECTIVE);
  var found = types.find(function(t){ return t.label === sel.value; });
  if (!found || found.dlcJours === 0) return;
  var fab = new Date(dateEl.value);
  fab.setDate(fab.getDate() + found.dlcJours);
  dlcEl.value = fab.toISOString().split('T')[0];
}

function changeNbEtiq(id, delta) {
  var input = document.getElementById('etiq_nb_' + id);
  if (!input) return;
  var val = parseInt(input.value) || 1;
  val = Math.max(1, Math.min(50, val + delta));
  input.value = val;
}

function imprimerEtiquettes() {
  // Format Avery L7160 — 63,5mm x 38,1mm — 3 colonnes x 7 lignes = 21 étiquettes/feuille A4
  var labels = '';
  var labelHtml = function(nom, date, dlc, zone) {
    return '<div style="border:1px solid #0f766e;border-radius:3px;padding:4mm 3mm;display:inline-block;width:63.5mm;height:38.1mm;vertical-align:top;font-family:Arial,sans-serif;page-break-inside:avoid;box-sizing:border-box;overflow:hidden">' +
      '<div style="font-size:6pt;color:#0f766e;font-weight:bold;border-bottom:0.5px solid #0f766e;padding-bottom:1mm;margin-bottom:1.5mm">🏷️ HACCP Pro — Étiquetage interne</div>' +
      '<div style="font-size:10pt;font-weight:bold;margin-bottom:1mm">' + nom + '</div>' +
      '<div style="font-size:8pt;color:#374151"><b>Fabrication :</b> ' + date + '</div>' +
      '<div style="font-size:9pt;color:#dc2626;font-weight:700"><b>DLC :</b> ' + dlc + '</div>' +
      '<div style="font-size:8pt;color:#374151"><b>Stockage :</b> ' + zone + '</div>' +
      '<div style="font-size:6pt;color:#9ca3af;margin-top:1.5mm">' + getNowStr() + '</div>' +
      '</div>';
  };
  document.querySelectorAll('[id^="etiq_type_"]').forEach(function(el) {
    var id = el.id.replace('etiq_type_','');
    var typeVal = el.value;
    var nomType = typeVal === 'autre'
      ? (document.getElementById('etiq_autre_' + id) ? document.getElementById('etiq_autre_' + id).value : '') 
      : typeVal;
    var nom  = document.getElementById('etiq_nom_'  + id) ? document.getElementById('etiq_nom_'  + id).value || nomType || '—' : '—';
    var date = document.getElementById('etiq_date_' + id) ? document.getElementById('etiq_date_' + id).value || '—' : '—';
    var dlc  = document.getElementById('etiq_dlc_'  + id) ? document.getElementById('etiq_dlc_'  + id).value || '—' : '—';
    var zone = document.getElementById('etiq_zone_' + id) ? document.getElementById('etiq_zone_' + id).value || '—' : '—';
    var nb   = parseInt(document.getElementById('etiq_nb_' + id) ? document.getElementById('etiq_nb_' + id).value : 1) || 1;
    for (var i = 0; i < nb; i++) { labels += labelHtml(nom, date, dlc, zone); }
  });
  if (!labels) { showToast('Aucun produit à imprimer.', 'warn'); return; }
  var etabNom = (ETAB && ETAB.nom) ? ETAB.nom : 'HACCP Pro';
  // Créer un overlay imprimable dans la page courante
  var existing = document.getElementById('printOverlay');
  if (existing) existing.remove();
  var overlay = document.createElement('div');
  overlay.id = 'printOverlay';
  overlay.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:white;z-index:99999;overflow:auto;padding:16px;box-sizing:border-box';
    var _tb = document.createElement('div');
  _tb.className = 'no-print';
  _tb.style.cssText = 'background:#1e1b4b;padding:10px 16px;display:flex;justify-content:space-between;align-items:center;position:sticky;top:0;z-index:1';
  var _tbTitle = document.createElement('div');
  _tbTitle.style.cssText = 'color:white;font-weight:800;font-size:13px';
  _tbTitle.textContent = 'imprimerEtiquettes';
  var _tbBtns = document.createElement('div');
  _tbBtns.style.cssText = 'display:flex;gap:8px';
  var _btnImpr = document.createElement('button');
  _btnImpr.textContent = 'Imprimer';
  _btnImpr.style.cssText = 'background:#10b981;color:white;border:none;border-radius:8px;padding:8px 14px;font-weight:700;cursor:pointer;font-size:12px';
  _btnImpr.onclick = function() { window.print(); };
  var _btnFerm = document.createElement('button');
  _btnFerm.textContent = 'Fermer';
  _btnFerm.style.cssText = 'background:#dc2626;color:white;border:none;border-radius:8px;padding:8px 14px;font-weight:700;cursor:pointer;font-size:12px';
  _btnFerm.onclick = function() { var el = document.getElementById('printOverlay'); if(el) el.remove(); };
  _tbBtns.appendChild(_btnImpr); _tbBtns.appendChild(_btnFerm);
  _tb.appendChild(_tbTitle); _tb.appendChild(_tbBtns);
  var _ct = document.createElement('div');
  // Entête format L7160
  var headerDiv = document.createElement('div');
  headerDiv.className = 'no-print';
  headerDiv.style.cssText = 'background:#f0fdf4;border:1px solid #0f766e;border-radius:8px;padding:8px 12px;margin:12px 0;font-size:11px;color:#065f46;font-weight:600';
  headerDiv.textContent = '📋 Format Avery L7160 — 63,5mm x 38,1mm — 21 étiquettes/feuille A4 — Restauration';
  _ct.innerHTML = labels;
  overlay.appendChild(_tb);
  overlay.appendChild(headerDiv);
  overlay.appendChild(_ct);
  document.body.appendChild(overlay);
  // CSS impression : cacher tout sauf l'overlay
  var styleEl = document.getElementById('printStyle');
  if (!styleEl) {
    styleEl = document.createElement('style');
    styleEl.id = 'printStyle';
    styleEl.textContent = '@media print { body > *:not(#printOverlay) { display:none !important; } #printOverlay { position:static !important; padding:10.7mm 4.67mm !important; } #printOverlay button, #printOverlay .no-print { display:none !important; } #printOverlay div[style*="63.5mm"] { margin:0 1.27mm 0 1.27mm !important; } }';
    document.head.appendChild(styleEl);
  }
}

function initSigEtiq() {
  sigCanvasEtiq = document.getElementById('sigCanvasEtiq');
  if (!sigCanvasEtiq) return;
  sigCtxEtiq = sigCanvasEtiq.getContext('2d');
  hasSigEtiq = false; isDrawingEtiq = false;
  var dpr = window.devicePixelRatio || 1, w = sigCanvasEtiq.parentElement.clientWidth || 340;
  sigCanvasEtiq.width = Math.round(w * dpr); sigCanvasEtiq.height = Math.round(140 * dpr);
  sigCanvasEtiq.style.width = w + 'px'; sigCanvasEtiq.style.height = '140px';
  sigCtxEtiq.scale(dpr, dpr);
  sigCtxEtiq.strokeStyle = '#0f172a'; sigCtxEtiq.lineWidth = 2.5; sigCtxEtiq.lineCap = 'round';
  function getPos(e) {
    var r = sigCanvasEtiq.getBoundingClientRect();
    var src = e.touches ? e.touches[0] : e;
    return { x: src.clientX - r.left, y: src.clientY - r.top };
  }
  sigCanvasEtiq.addEventListener('mousedown', function(e) { isDrawingEtiq = true; hasSigEtiq = true; var p = getPos(e); sigCtxEtiq.beginPath(); sigCtxEtiq.moveTo(p.x, p.y); });
  sigCanvasEtiq.addEventListener('mousemove', function(e) { if (!isDrawingEtiq) return; var p = getPos(e); sigCtxEtiq.lineTo(p.x, p.y); sigCtxEtiq.stroke(); });
  sigCanvasEtiq.addEventListener('mouseup', function() { isDrawingEtiq = false; });
  sigCanvasEtiq.addEventListener('touchstart', function(e) { e.preventDefault(); isDrawingEtiq = true; hasSigEtiq = true; var p = getPos(e); sigCtxEtiq.beginPath(); sigCtxEtiq.moveTo(p.x, p.y); }, {passive:false});
  sigCanvasEtiq.addEventListener('touchmove', function(e) { e.preventDefault(); if (!isDrawingEtiq) return; var p = getPos(e); sigCtxEtiq.lineTo(p.x, p.y); sigCtxEtiq.stroke(); }, {passive:false});
  sigCanvasEtiq.addEventListener('touchend', function() { isDrawingEtiq = false; });
}

function clearSigEtiq() {
  if (sigCtxEtiq && sigCanvasEtiq) { sigCtxEtiq.clearRect(0, 0, sigCanvasEtiq.width, sigCanvasEtiq.height); hasSigEtiq = false; }
}

async function validerEtiquetage() {
  var prenom = document.getElementById('etiq_sig_prenom').value.trim();
  var nom = document.getElementById('etiq_sig_nom').value.trim();
  var reqEl = document.getElementById('etiq_sig_required');
  if (!hasSigEtiq || !prenom || !nom) { reqEl.style.display = 'flex'; reqEl.scrollIntoView({behavior:'smooth', block:'center'}); return; }
  reqEl.style.display = 'none';
  // V113 — D : Sauvegarde Supabase AVANT PDF (awaited)
  if (SB_READY && ETAB_ID) {
    try {
      await sbSauvegarderModule('etiquetage', {secteur: SECTEUR_ACTIF, etab: ETAB.nom, timestamp: new Date().toISOString()}, prenom + ' ' + nom);
    } catch(eSB) { console.warn('Supabase save error (etiquetage):', eSB); }
  }
  document.getElementById('modalEtiqPdf').classList.add('visible');
  try { var _fr = document.getElementById('etiq_format_resume'); if (_fr) _fr.textContent = _etiqFormatActif().label; } catch (eFmt) {}
  sauvegarderHistorique('Étiquetage interne', prenom);
  sauvegarderDonnesModule('page-etiquetage');
  stopBrouillonAuto(); effacerBrouillon('page-etiquetage');
}


