function onDechetBordereau(id, nc) {
  var ncEl = document.getElementById('dechet_nc_' + id);
  if (ncEl) {
    ncEl.style.display = nc ? 'flex' : 'none';
    if (nc) showNCAction(ncEl.id); else hideNCAction(ncEl.id);
  }
}

function onDechetType(id) {
  var val = document.getElementById('dechet_type_' + id).value;
  var autreWrap = document.getElementById('dechet_autre_wrap_' + id);
  var infoEl = document.getElementById('dechet_info_' + id);
  if (autreWrap) autreWrap.style.display = val === 'autre' ? 'block' : 'none';
  var found = getTypesDechets().find(function(t){ return t.val === val; });
  if (infoEl && found && found.seuil) {
    infoEl.style.display = 'flex';
    infoEl.textContent = '⚠️ ' + found.seuil;
  } else if (infoEl) {
    infoEl.style.display = 'none';
  }
}

function supprimerDechet(id) {
  if (!confirm('Confirmer la suppression ?')) return;
  var el = document.getElementById('dechet_' + id);
  if (el) el.remove();
  renumeroterBlocs('#dechetsContainer', 'Déchet N°');
}

function initSigDechets() {
  sigCanvasDechets = document.getElementById('sigCanvasDechets');
  if (!sigCanvasDechets) return;
  sigCtxDechets = sigCanvasDechets.getContext('2d');
  hasSigDechets=false; isDrawingDechets=false;
  var dpr=window.devicePixelRatio||1, w=sigCanvasDechets.parentElement.clientWidth||340;
  sigCanvasDechets.width=Math.round(w*dpr); sigCanvasDechets.height=Math.round(140*dpr);
  sigCanvasDechets.style.width=w+'px'; sigCanvasDechets.style.height='140px';
  sigCtxDechets.scale(dpr,dpr); sigCtxDechets.strokeStyle='#1a1a2e';
  sigCtxDechets.lineWidth=2.5; sigCtxDechets.lineCap='round'; sigCtxDechets.lineJoin='round';
  function pos(e){var r=sigCanvasDechets.getBoundingClientRect();var s=e.touches?e.touches[0]:e;return{x:s.clientX-r.left,y:s.clientY-r.top};}
  function start(e){e.preventDefault();isDrawingDechets=true;var p=pos(e);sigCtxDechets.beginPath();sigCtxDechets.moveTo(p.x,p.y);}
  function move(e){e.preventDefault();if(!isDrawingDechets)return;var p=pos(e);sigCtxDechets.lineTo(p.x,p.y);sigCtxDechets.stroke();hasSigDechets=true;}
  function stop(e){e.preventDefault();isDrawingDechets=false;}
  sigCanvasDechets.addEventListener('mousedown',start); sigCanvasDechets.addEventListener('mousemove',move);
  sigCanvasDechets.addEventListener('mouseup',stop); sigCanvasDechets.addEventListener('mouseleave',stop);
  sigCanvasDechets.addEventListener('touchstart',start,{passive:false}); sigCanvasDechets.addEventListener('touchmove',move,{passive:false});
  sigCanvasDechets.addEventListener('touchend',stop,{passive:false});
}

function clearSigDechets() {
  if (!sigCtxDechets||!sigCanvasDechets) return;
  sigCtxDechets.clearRect(0,0,sigCanvasDechets.width,sigCanvasDechets.height); hasSigDechets=false;
}

async function validerDechets() {
  var prenom=document.getElementById('dechets_sig_prenom').value.trim();
  var nom=document.getElementById('dechets_sig_nom').value.trim();
  var reqEl=document.getElementById('dechets_sig_required');
  if (!hasSigDechets||!prenom||!nom) { reqEl.style.display='flex'; reqEl.scrollIntoView({behavior:'smooth',block:'center'}); return; }
  reqEl.style.display='none';
  // V113 — D : Sauvegarde Supabase AVANT PDF (awaited, après check signature)
  if (SB_READY && ETAB_ID) {
    try {
      await sbSauvegarderModule('dechets', {secteur: SECTEUR_ACTIF, etab: ETAB.nom, timestamp: new Date().toISOString()}, prenom + ' ' + nom);
    } catch(eSB) { console.warn('Supabase save error (dechets):', eSB); }
  }
  document.getElementById('modalDechetsPdf').classList.add('visible');
  sauvegarderHistorique('Déchets & Biodéchets', prenom);
  sauvegarderDonnesModule('page-dechets');
  stopBrouillonAuto(); effacerBrouillon('page-dechets');
}

function downloadDechetsPDF() {
  imprimerModule('page-dechets', 'Dechets & Biodechets');
}
function confirmerSansDechetsPDF() { showConfirm('♻️', 'Déchets — sans PDF', 'Sans PDF vous n\'avez pas de preuve legale. Continuez seulement si vous imprimez ce document.', 'Continuer quand même', '', function(ok){ if(ok) fermerModalDechets(); }); }
function fermerModalDechets() { document.getElementById('modalDechetsPdf').classList.remove('visible'); showPage('page-guide'); }

// selPlan — affiche action corrective si non respecté
function selPlan(num, type, btn) {
  var grp = btn.closest('.status-group');
  grp.querySelectorAll('.status-btn').forEach(function(b){ b.classList.remove('active-ok','active-warn','active-bad'); });
  btn.classList.add(type === 'ok' ? 'active-ok' : type === 'warn' ? 'active-warn' : 'active-bad');
  var actionDiv = document.getElementById('pt_action_' + num);
  if (actionDiv) actionDiv.classList.toggle('visible', type === 'bad');

  // Ajouter question propreté — indépendante du type de plan
  var frow = grp.closest('.frow') || grp.parentElement;
  var propDiv = document.getElementById('pt_proprete_' + num);
  if (!propDiv && frow) {
    propDiv = document.createElement('div');
    propDiv.id = 'pt_proprete_' + num;
    propDiv.className = 'frow';
    propDiv.style.marginTop = '8px';
    propDiv.innerHTML =
      '<div class="flabel" style="color:#0891b2;font-weight:700">Etat de proprete</div>' +
      '<div class="status-group">' +
        '<button class="status-btn" data-pnum="' + num + '" data-ptype="ok" onclick="selPropreteBtn(this)">OK Propre</button>' +
        '<button class="status-btn" data-pnum="' + num + '" data-ptype="bad" onclick="selPropreteBtn(this)">Sale NC</button>' +
      '</div>';
    // Insérer après le frow du plan
    frow.parentNode.insertBefore(propDiv, frow.nextSibling);
  }
  if (propDiv) propDiv.style.display = 'flex';
}


function selPropreteBtn(btn) {
  var num = btn.getAttribute('data-pnum');
  var type = btn.getAttribute('data-ptype');
  selProprete(parseInt(num), type, btn);
}
function selProprete(num, type, btn) {
  var grp = btn.closest('.status-group');
  grp.querySelectorAll('.status-btn').forEach(function(b){ b.classList.remove('active-ok','active-bad'); });
  btn.classList.add(type === 'ok' ? 'active-ok' : 'active-bad');
  // NC auto si sale
  var ncId = 'pt_nc_sale_' + num;
  var existing = document.getElementById(ncId);
  if (type === 'bad') {
    if (!existing) {
      var ncDiv = document.createElement('div');
      ncDiv.id = ncId;
      ncDiv.className = 'nc-auto';
      ncDiv.style.display = 'flex';
      ncDiv.textContent = '⚡ NC automatique — plan de travail sale';
      var propRow = btn.closest('.frow');
      // Action corrective générique via selHyg system
      var actionDiv = document.createElement('div');
      actionDiv.className = 'nc-action visible';
      actionDiv.setAttribute('data-generic','1');
      actionDiv.innerHTML =
        '<div class="nc-action-title">🛠️ Action corrective — Plan sale</div>' +
        '<div class="frow"><div class="flabel">Action</div>' +
          '<select id="pt_act_' + num + '">' +
            '<option value="">-- Selectionner --</option>' +
            '<option>Nettoyage et desinfection immediats</option>' +
            '<option>Production suspendue jusqu\'a remise en etat</option>' +
            '<option>Plan remplace par un plan propre</option>' +
            '<option>Responsable contacte</option>' +
          '</select>' +
        '</div>' +
        '<div class="frow"><div class="flabel">Responsable</div>' +
          '<input type="text" id="pt_act_resp_' + num + '" placeholder="Nom & prenom"/>' +
        '</div>' +
        '<div class="frow"><div class="flabel">Heure</div>' +
          '<input type="time" id="pt_act_heure_' + num + '"/>' +
        '</div>';
      if (propRow && propRow.parentNode) {
        propRow.parentNode.insertBefore(ncDiv, propRow.nextSibling);
        propRow.parentNode.insertBefore(actionDiv, ncDiv.nextSibling);
      }
    } else {
      existing.style.display = 'flex';
      var actDiv = existing.nextElementSibling;
      if (actDiv && actDiv.classList.contains('nc-action')) actDiv.classList.add('visible');
    }
  } else {
    if (existing) {
      existing.style.display = 'none';
      var actDiv = existing.nextElementSibling;
      if (actDiv && actDiv.classList.contains('nc-action')) actDiv.classList.remove('visible');
    }
  }
}

