function checkPertesRecurrentes() {
  var count = document.querySelectorAll('[id^="perte_"]:not([id*="_prod_"]):not([id*="_lot_"]):not([id*="_dlc_"]):not([id*="_motif_"]):not([id*="_cout_"]):not([id*="_qte_"]):not([id*="_autre"])').length;
  var ncEl = document.getElementById('pertes_nc_recurrentes');
  if (!ncEl) {
    ncEl = document.createElement('div');
    ncEl.id = 'pertes_nc_recurrentes';
    ncEl.className = 'nc-auto';
    ncEl.style.display = 'none';
    ncEl.style.margin = '8px 0';
    var container = document.getElementById('pertesContainer');
    if (container) container.parentElement.insertBefore(ncEl, container.nextSibling);
  }
  var realCount = document.querySelectorAll('[id^="perte_prod_"]').length;
  if (realCount >= 4) {
    ncEl.style.display = 'flex';
    ncEl.textContent = '⚡ NC automatique — Pertes récurrentes détectées (' + realCount + ' enregistrements) — Analyse des causes requise';
  } else {
    ncEl.style.display = 'none';
  }
}

