var sigCanvasFerm, sigCtxFerm, isDrawingFerm = false, hasSigFerm = false;

function initSigFerm() {
  sigCanvasFerm = document.getElementById('sigCanvasFerm');
  if (!sigCanvasFerm) return;
  sigCtxFerm = sigCanvasFerm.getContext('2d');
  hasSigFerm=false; isDrawingFerm=false;
  var dpr=window.devicePixelRatio||1, w=sigCanvasFerm.parentElement.clientWidth||340;
  sigCanvasFerm.width=Math.round(w*dpr); sigCanvasFerm.height=Math.round(140*dpr);
  sigCanvasFerm.style.width=w+'px'; sigCanvasFerm.style.height='140px';
  sigCtxFerm.scale(dpr,dpr); sigCtxFerm.strokeStyle='#1a1a2e';
  sigCtxFerm.lineWidth=2.5; sigCtxFerm.lineCap='round'; sigCtxFerm.lineJoin='round';
  function pos(e){var r=sigCanvasFerm.getBoundingClientRect();var s=e.touches?e.touches[0]:e;return{x:s.clientX-r.left,y:s.clientY-r.top};}
  function start(e){e.preventDefault();isDrawingFerm=true;var p=pos(e);sigCtxFerm.beginPath();sigCtxFerm.moveTo(p.x,p.y);}
  function move(e){e.preventDefault();if(!isDrawingFerm)return;var p=pos(e);sigCtxFerm.lineTo(p.x,p.y);sigCtxFerm.stroke();hasSigFerm=true;}
  function stop(e){e.preventDefault();isDrawingFerm=false;}
  sigCanvasFerm.addEventListener('mousedown',start); sigCanvasFerm.addEventListener('mousemove',move);
  sigCanvasFerm.addEventListener('mouseup',stop); sigCanvasFerm.addEventListener('mouseleave',stop);
  sigCanvasFerm.addEventListener('touchstart',start,{passive:false}); sigCanvasFerm.addEventListener('touchmove',move,{passive:false});
  sigCanvasFerm.addEventListener('touchend',stop,{passive:false});
}

function clearSigFerm() {
  if (!sigCtxFerm||!sigCanvasFerm) return;
  sigCtxFerm.clearRect(0,0,sigCanvasFerm.width,sigCanvasFerm.height); hasSigFerm=false;
}

