function takeDocPhoto(previewId) {
  var input = document.createElement('input');
  input.type='file'; input.accept='image/*'; input.capture='environment';
  // V116 — Fix bug iPhone Safari : input doit être dans le DOM
  input.style.position = 'absolute';
  input.style.left = '-9999px';
  document.body.appendChild(input);
  input.onchange = function(e) {
    var file = e.target.files[0];
    if (!file) { try { document.body.removeChild(input); } catch(_){} return; }
    var reader = new FileReader();
    reader.onload = function(ev) {
      // V80 — Compression
      compresserPhoto(ev.target.result, function(compressed) {
        var prev = document.getElementById(previewId + '_preview');
        if (prev) prev.innerHTML = '<img src="' + compressed + '" alt="Document photographié" style="width:100%;border-radius:8px;margin-top:6px;max-height:120px;object-fit:cover"/><div style="font-size:11px;color:var(--green);font-weight:600;margin-top:4px">✅ Document photographié</div>';
        // V116 — Range la photo dans la boîte d'attente (cloud)
        apresLaCapturePhoto(compressed, previewId, 'document');
        // V116 — Nettoyage
        try { document.body.removeChild(input); } catch(_){}
      });
    };
    reader.readAsDataURL(file);
  };
  input.click();
}

function uploadDoc(previewId) {
  var input = document.createElement('input');
  input.type='file'; input.accept='image/*,application/pdf';
  input.onchange = function(e) {
    var file = e.target.files[0]; if (!file) return;
    var prev = document.getElementById(previewId + '_preview');
    if (prev) {
      if (file.type.startsWith('image/')) {
        var reader = new FileReader();
        reader.onload = function(ev) {
          prev.innerHTML = '<img src="' + ev.target.result + '" alt="' + (file.name||'Document') + '" style="width:100%;border-radius:8px;margin-top:6px;max-height:120px;object-fit:cover"/><div style="font-size:11px;color:var(--green);font-weight:600;margin-top:4px">✅ ' + file.name + '</div>';
        };
        reader.readAsDataURL(file);
      } else {
        prev.innerHTML = '<div style="font-size:11px;color:var(--green);font-weight:600;margin-top:6px;padding:8px;background:#f0fdf4;border-radius:8px">✅ PDF joint : ' + file.name + '</div>';
      }
    }
  };
  input.click();
}

// ══════════════════════════════════════════════════════════════
// COFFRE-FORT DOCUMENTS — stockage local durable (IndexedDB)
// Les documents (PDF/images) sont conservés sur l'appareil, hors-ligne.
// ══════════════════════════════════════════════════════════════
var coffreDB = null;
try {
  if (typeof Dexie !== 'undefined') {
    coffreDB = new Dexie('HACCPCoffreDB');
    coffreDB.version(1).stores({ docs: '++id, cle, createdAt' });
  }
} catch(e) { console.error('[Coffre-fort] Erreur init:', e); }

// Liste des documents obligatoires proposés dans le coffre-fort
// Ordre = obligatoires d'abord, puis pièces autonomes.
// Les pièces incluses dans le PMS (plan HACCP, plan de flux, plan de
// nettoyage, fiches techniques) ne sont PAS listées à part pour éviter
// les doublons : elles font partie du PMS.
var COFFRE_DOCS = [
  { cle:'cerfa',              label:"Déclaration d'activité (Cerfa 13984)",       icon:'🏛️' },
  { cle:'formation',          label:'Attestation Formation HACCP',                icon:'🎓' },
  { cle:'medical',            label:'Aptitudes médicales du personnel',           icon:'🩺' },
  { cle:'pms',                label:'Plan de Maîtrise Sanitaire (PMS) — inclut plan HACCP, plan de flux, plan de nettoyage, fiches techniques', icon:'📄' },
  { cle:'contrat_nuisibles',  label:'Contrat prestataire nuisibles',              icon:'🐭' },
  { cle:'contrat_huiles',     label:'Contrat collecte huiles usagées',            icon:'🛢️' },
  { cle:'agrement',           label:'Agrément sanitaire',                         icon:'✅' },
  { cle:'micro',              label:'Analyses microbiologiques',                  icon:'🧪' },
  { cle:'contrat_biodechets', label:'Contrat collecte biodéchets',                icon:'♻️' },
  { cle:'autre',              label:'Autres documents',                           icon:'📎' }
];

// Affiche le coffre-fort (appelé à l'ouverture du module Documents)
async function renderCoffre() {
  var cont = document.getElementById('coffreContainer');
  if (!cont) return;
  if (!coffreDB) {
    cont.innerHTML = '<div style="font-size:12px;color:#dc2626">Stockage indisponible sur ce navigateur.</div>';
    return;
  }
  var tous = [];
  try { tous = await coffreDB.docs.toArray(); } catch(e) { tous = []; }
  var html = '';
  COFFRE_DOCS.forEach(function(d) {
    var fichiers = tous.filter(function(f){ return f.cle === d.cle; });
    html += '<div style="border:1px solid #e5e7eb;border-radius:10px;padding:10px 12px;margin-bottom:8px">';
    html += '<div style="display:flex;align-items:center;gap:8px">';
    html += '<span style="font-size:18px">' + d.icon + '</span>';
    html += '<span style="flex:1;font-size:12.5px;font-weight:700;color:#1f2937">' + d.label + '</span>';
    if (d.cle === 'pms' && typeof window.genererPMS === 'function') {
      html += '<button onclick="genererPMS()" style="background:#4338ca;color:white;border:none;border-radius:8px;font-size:11px;font-weight:700;padding:6px 12px;cursor:pointer;white-space:nowrap;margin-right:6px">✨ Générer mon PMS</button>';
    }
    html += '<button onclick="coffreUpload(\'' + d.cle + '\')" style="background:#16a34a;color:white;border:none;border-radius:8px;font-size:11px;font-weight:700;padding:6px 12px;cursor:pointer;white-space:nowrap">📎 Téléverser</button>';
    html += '</div>';
    if (d.cle === 'pms') {
      html += '<div style="font-size:10.5px;color:#6b7280;margin-top:6px;line-height:1.45">✨ Génère un PMS complet pré-rempli (BPH, plan HACCP, CCP, traçabilité) adapté à votre secteur, à relire et compléter. Modèle — vous restez responsable de sa mise à jour.</div>';
    }
    if (fichiers.length === 0) {
      html += '<div style="font-size:11px;color:#9ca3af;margin-top:6px">Aucun document</div>';
    } else {
      fichiers.forEach(function(f) {
        var d2 = f.createdAt ? new Date(f.createdAt).toLocaleDateString('fr-FR') : '';
        html += '<div style="display:flex;align-items:center;gap:8px;margin-top:6px;background:#f9fafb;border-radius:8px;padding:6px 8px">';
        html += '<span style="font-size:14px">' + (String(f.mime||'').indexOf('pdf') > -1 ? '📄' : '🖼️') + '</span>';
        html += '<span style="flex:1;font-size:11px;color:#374151;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + (f.nom || 'Document') + (d2 ? ' · ' + d2 : '') + '</span>';
        html += '<button onclick="coffreView(' + f.id + ')" style="background:#eef2ff;color:#4338ca;border:none;border-radius:6px;font-size:11px;font-weight:700;padding:4px 9px;cursor:pointer">👁️ Voir</button>';
        html += '<button onclick="coffreDelete(' + f.id + ')" style="background:#fef2f2;color:#dc2626;border:none;border-radius:6px;font-size:11px;font-weight:700;padding:4px 9px;cursor:pointer">✕</button>';
        html += '</div>';
      });
    }
    html += '</div>';
  });
  cont.innerHTML = html;
}

// Téléverse un document dans une catégorie du coffre-fort
function coffreUpload(cle) {
  if (!coffreDB) { if (typeof showToast === 'function') showToast('Stockage indisponible', 'warn'); return; }
  var input = document.createElement('input');
  input.type = 'file';
  input.accept = 'image/*,application/pdf';
  input.style.position = 'absolute';
  input.style.left = '-9999px';
  document.body.appendChild(input);
  input.onchange = function(e) {
    var file = e.target.files[0];
    if (!file) { try { document.body.removeChild(input); } catch(_){} return; }
    // Limite de sécurité : 50 Mo par fichier (le PMS complet peut être lourd)
    if (file.size > 50 * 1024 * 1024) {
      if (typeof showToast === 'function') showToast('Fichier trop lourd (max 50 Mo)', 'warn');
      else alert('Fichier trop lourd (max 50 Mo).');
      try { document.body.removeChild(input); } catch(_){}
      return;
    }
    var reader = new FileReader();
    reader.onload = async function(ev) {
      try {
        await coffreDB.docs.add({
          cle: cle,
          nom: file.name || 'Document',
          mime: file.type || 'application/octet-stream',
          base64: ev.target.result,
          createdAt: new Date().toISOString()
        });
        if (typeof showToast === 'function') showToast('Document enregistré ✓', 'ok');
        await renderCoffre();
        // Rafraîchir aussi la liste du Mode Inspecteur si elle est affichée
        if (typeof renderInspDocs === 'function' && document.getElementById('inspDocsContainer')) {
          try { await renderInspDocs(); } catch(eR){}
        }
      } catch(err) {
        console.error('[Coffre-fort] Erreur enregistrement:', err);
        if (typeof showToast === 'function') showToast('Erreur d\'enregistrement', 'warn');
        else alert('Erreur lors de l\'enregistrement du document.');
      }
      try { document.body.removeChild(input); } catch(_){}
    };
    reader.readAsDataURL(file);
  };
  input.click();
}

// Ouvre un document du coffre-fort
async function coffreView(id) {
  if (!coffreDB) return;
  // Ouvrir la fenêtre PENDANT le clic (sinon bloquée par le navigateur mobile après l'attente DB)
  var win = window.open('', '_blank');
  try {
    var rec = await coffreDB.docs.get(id);
    if (!rec || !rec.base64) { if (win) win.close(); return; }
    var blob = base64VersBlob(rec.base64);
    if (!blob) { if (win) win.close(); return; }
    var url = URL.createObjectURL(blob);
    if (win) win.location = url; else window.location.href = url;
    setTimeout(function(){ URL.revokeObjectURL(url); }, 60000);
  } catch(e) {
    if (win) try { win.close(); } catch(_){}
    console.error('[Coffre-fort] Erreur ouverture:', e);
  }
}

// Supprime un document du coffre-fort
function coffreDelete(id) {
  if (!coffreDB) return;
  if (!confirm('Supprimer ce document du coffre-fort ?')) return;
  coffreDB.docs.delete(id).then(function(){
    if (typeof showToast === 'function') showToast('Document supprimé', 'ok');
    renderCoffre();
  }).catch(function(e){ console.error('[Coffre-fort] Erreur suppression:', e); });
}

// ════════════════════════════════════════════════════════════════
// V124 — DOCUMENTS À LA DEMANDE (page Contrôle DDPP)
// Liste cochable des documents du coffre-fort : le restaurateur coche
// le(s) document(s) que l'inspecteur réclame, puis les présente à
// l'écran ET/OU les imprime (PDF) depuis le même écran.
// ════════════════════════════════════════════════════════════════

// Construit le HTML de la liste des documents (fichiers existants = tableau).
function _inspDocsHTML(tous) {
  tous = tous || [];
  var html = '';
  COFFRE_DOCS.forEach(function(d, i) {
    var fichiers = tous.filter(function(f){ return f.cle === d.cle; });
    var aFichier = fichiers.length > 0;
    html += '<div style="display:flex;align-items:center;gap:11px;background:#fff;border:1.5px solid ' + (aFichier ? '#86efac' : '#e5e7eb') + ';border-radius:12px;padding:13px 12px;margin-bottom:9px">';
    // Pastille numéro / coche
    if (aFichier) {
      html += '<input type="checkbox" class="insp-doc-chk" value="' + d.cle + '" title="Cocher pour présenter au contrôleur" style="width:24px;height:24px;flex-shrink:0;cursor:pointer;accent-color:#0f766e">';
    } else {
      html += '<span style="width:24px;height:24px;flex-shrink:0;border-radius:50%;background:#f1f5f9;color:#94a3b8;font-size:12px;font-weight:800;display:flex;align-items:center;justify-content:center">' + (i+1) + '</span>';
    }
    html += '<span style="font-size:22px;flex-shrink:0">' + d.icon + '</span>';
    html += '<span style="flex:1;min-width:0;font-size:13.5px;font-weight:800;color:#0f172a;line-height:1.25">' + d.label
         + '<span style="display:block;font-size:11.5px;font-weight:600;margin-top:2px;color:' + (aFichier ? '#15803d' : '#dc2626') + '">'
         + (aFichier ? ('✓ ' + fichiers.length + ' fichier' + (fichiers.length>1?'s':'') + ' — coché = à présenter') : '⚠ Manquant — à téléverser') + '</span></span>';
    html += '<button onclick="coffreUpload(\'' + d.cle + '\')" style="flex-shrink:0;background:' + (aFichier ? '#eef2ff' : '#16a34a') + ';color:' + (aFichier ? '#4338ca' : '#fff') + ';border:none;border-radius:10px;font-size:12px;font-weight:800;padding:10px 14px;cursor:pointer;white-space:nowrap;box-shadow:0 2px 6px rgba(0,0,0,.08)">' + (aFichier ? '＋' : '📎 Ajouter') + '</button>';
    html += '</div>';
  });
  return html;
}

// Affiche la liste des documents (rendu immédiat, puis enrichi avec les
// fichiers réellement présents dès que la base répond — pas de "Chargement…"
// bloqué).
function renderInspDocs() {
  // Cibler TOUS les conteneurs documents (l'écran DDPP utilise #inspDocsBox,
  // l'ancienne page page-pack-ddpp utilise #inspDocsContainer).
  var conts = [];
  var a = document.getElementById('inspDocsBox'); if (a) conts.push(a);
  var b = document.getElementById('inspDocsContainer'); if (b) conts.push(b);
  if (!conts.length) return;
  // 1) Rendu IMMÉDIAT de la liste complète (tout est "à téléverser" par défaut)
  var htmlVide = _inspDocsHTML([]);
  conts.forEach(function(c){ c.innerHTML = htmlVide; });
  // 2) Enrichissement async : marquer les documents déjà présents
  try {
    if (typeof coffreDB !== 'undefined' && coffreDB && coffreDB.docs) {
      Promise.resolve(coffreDB.docs.toArray()).then(function(tous){
        var h = _inspDocsHTML(tous || []);
        ['inspDocsBox','inspDocsContainer'].forEach(function(id){ var c = document.getElementById(id); if (c) c.innerHTML = h; });
      }).catch(function(){});
    }
  } catch(e) {}
}

// Coche / décoche tous les documents de la liste.
function inspDocsToutCocher(val) {
  document.querySelectorAll('.insp-doc-chk').forEach(function(c){ c.checked = !!val; });
}

// Récupère les fichiers appartenant aux catégories cochées.
async function _inspDocsFichiersCoches() {
  var cles = [];
  document.querySelectorAll('.insp-doc-chk:checked').forEach(function(c){ cles.push(c.value); });
  if (!cles.length) return [];
  var tous = [];
  try { tous = await coffreDB.docs.toArray(); } catch(e) { tous = []; }
  return tous.filter(function(f){ return cles.indexOf(f.cle) > -1; });
}

// Présente les documents cochés dans un écran propre, montrable à
// l'inspecteur ET imprimable / exportable en PDF (bouton Imprimer).
async function presenterDocsCoches() {
  if (typeof coffreDB === 'undefined' || !coffreDB) {
    if (typeof showToast==='function') showToast('Stockage indisponible','warn',3000); return;
  }
  var fichiers = await _inspDocsFichiersCoches();
  if (!fichiers.length) {
    if (typeof showToast==='function') showToast('Cochez au moins un document à présenter','warn',3000); return;
  }
  var labelParCle = {};
  COFFRE_DOCS.forEach(function(d){ labelParCle[d.cle] = d.label; });

  var w = window.open('', '_blank');
  if (!w) { if (typeof showToast==='function') showToast('Autorisez les fenêtres pop-up pour afficher les documents','warn',4000); return; }

  var etab = '';
  try { if (typeof _ls==='function') etab = _ls('haccp_etab_nom') || ''; } catch(e){}
  var dateStr = new Date().toLocaleDateString('fr-FR');

  var body = '';
  for (var i=0;i<fichiers.length;i++) {
    var f = fichiers[i];
    // Les documents du coffre sont stockés en base64 (cf. coffreView)
    var blob = (typeof base64VersBlob==='function' && f.base64) ? base64VersBlob(f.base64) : null;
    if (!blob) continue;
    var url = URL.createObjectURL(blob);
    var mime = String(f.mime || blob.type || '');
    var titre = (labelParCle[f.cle]||'Document') + (f.nom ? ' — ' + f.nom : '');
    body += '<section style="page-break-after:always;margin-bottom:24px">';
    body += '<h2 style="font:700 15px/1.3 Arial,sans-serif;color:#1e1b4b;border-bottom:2px solid #4338ca;padding-bottom:6px;margin:0 0 12px">' + titre + '</h2>';
    if (mime.indexOf('pdf') > -1) {
      body += '<embed src="' + url + '" type="application/pdf" style="width:100%;height:80vh;border:1px solid #ccc"/>';
    } else if (mime.indexOf('image') > -1) {
      body += '<img src="' + url + '" style="max-width:100%;height:auto;border:1px solid #ccc"/>';
    } else {
      body += '<p style="font:13px Arial"><a href="' + url + '" target="_blank">Ouvrir le fichier (' + (f.nom||'document') + ')</a></p>';
    }
    body += '</section>';
  }
  if (!body) { try{ w.close(); }catch(_){ } if (typeof showToast==='function') showToast('Documents illisibles','warn',3000); return; }

  var docHtml = '<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><title>Documents — Contrôle DDPP</title>'
    + '<style>@media print{.noprint{display:none!important}}body{margin:0;background:#f3f4f6}</style></head><body>'
    + '<div class="noprint" style="position:sticky;top:0;background:#1e1b4b;color:#fff;padding:12px 16px;display:flex;justify-content:space-between;align-items:center;gap:12px">'
    +   '<div style="font:700 14px Arial">📁 Documents à présenter' + (etab?' — '+etab:'') + ' · ' + dateStr + '</div>'
    +   '<button onclick="window.print()" style="background:#fff;color:#1e1b4b;border:none;border-radius:8px;font:700 13px Arial;padding:8px 16px;cursor:pointer">🖨️ Imprimer / PDF</button>'
    + '</div>'
    + '<div style="padding:16px;max-width:900px;margin:0 auto">' + body + '</div>'
    + '</body></html>';

  w.document.open();
  w.document.write(docHtml);
  w.document.close();
}

