function makeSig(canvasId, drawingVar, ctxVar, hasSigVar) {
  var canvas = document.getElementById(canvasId);
  if (!canvas) return {clear:function(){}};
  var ctx = canvas.getContext('2d');
  var drawing=false, hasSig=false;
  var dpr=window.devicePixelRatio||1, w=canvas.parentElement.clientWidth||340;
  canvas.width=Math.round(w*dpr); canvas.height=Math.round(140*dpr);
  canvas.style.width=w+'px'; canvas.style.height='140px';
  ctx.scale(dpr,dpr); ctx.strokeStyle='#1a1a2e'; ctx.lineWidth=2.5; ctx.lineCap='round'; ctx.lineJoin='round';
  function pos(e){var r=canvas.getBoundingClientRect();var s=e.touches?e.touches[0]:e;return{x:s.clientX-r.left,y:s.clientY-r.top};}
  function start(e){e.preventDefault();drawing=true;var p=pos(e);ctx.beginPath();ctx.moveTo(p.x,p.y);}
  function move(e){e.preventDefault();if(!drawing)return;var p=pos(e);ctx.lineTo(p.x,p.y);ctx.stroke();hasSig=true;if(hasSigVar)hasSigVar.v=true;}
  function stop(e){e.preventDefault();drawing=false;}
  canvas.addEventListener('mousedown',start); canvas.addEventListener('mousemove',move);
  canvas.addEventListener('mouseup',stop); canvas.addEventListener('mouseleave',stop);
  canvas.addEventListener('touchstart',start,{passive:false}); canvas.addEventListener('touchmove',move,{passive:false});
  canvas.addEventListener('touchend',stop,{passive:false});
  return {clear:function(){ctx.clearRect(0,0,canvas.width,canvas.height);hasSig=false;if(hasSigVar)hasSigVar.v=false;}, getHasSig:function(){return hasSig;}};
}

