function genererPackDDPP() {
  // Afficher le sélecteur de période
  var existing = document.getElementById('ddppPeriodeModal');
  if (existing) { existing.classList.add('visible'); return; }

  var modal = document.createElement('div');
  modal.id = 'ddppPeriodeModal';
  modal.className = 'modal-overlay visible';
  modal.style.zIndex = '99997';
  // Dates LOCALES (pas UTC) : toISOString() décalait d'un jour en soirée/nuit
  // (ex. 01:00 du 2 juin en UTC+2 = encore le 1er juin en UTC) → mauvaise période.
  var _dLoc = function(ms){ var d = new Date(ms); return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+String(d.getDate()).padStart(2,'0'); };
  var today = _dLoc(Date.now());
  var yesterday = _dLoc(Date.now()-86400000);
  var weekAgo = _dLoc(Date.now()-7*86400000);
  var monthAgo = _dLoc(Date.now()-30*86400000);

  modal.innerHTML =
    '<div class="modal-box" style="max-width:380px">' +
      '<div class="modal-ico">🔴</div>' +
      '<div class="modal-title">Pack Contrôle DDPP</div>' +
      '<div class="modal-desc">Sélectionnez la période des contrôles à inclure dans le Pack DDPP</div>' +
      '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin:16px 0">' +
        '<button class="status-btn" data-dfrom="' + today + '" data-dto="' + today + '" onclick="selPeriodeDDPP(this)">Aujourd\u0027hui</button>' +
        '<button class="status-btn" data-dfrom="' + yesterday + '" data-dto="' + yesterday + '" onclick="selPeriodeDDPP(this)">Hier</button>' +
        '<button class="status-btn" data-dfrom="' + weekAgo + '" data-dto="' + today + '" onclick="selPeriodeDDPP(this)">7 derniers jours</button>' +
        '<button class="status-btn" data-dfrom="' + monthAgo + '" data-dto="' + today + '" onclick="selPeriodeDDPP(this)">30 derniers jours</button>' +
      '</div>' +
'<div style="background:#f0f9ff;border-radius:12px;padding:12px;margin-bottom:12px">' +
        '<div style="font-size:12px;font-weight:700;color:#0369a1;margin-bottom:8px">Période personnalisée</div>' +
        '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">' +
          '<div class="frow"><div class="flabel">Du</div><input type="date" id="ddpp_from" class="finput" value="' + monthAgo + '"/></div>' +
          '<div class="frow"><div class="flabel">Au</div><input type="date" id="ddpp_to" class="finput" value="' + today + '"/></div>' +
        '</div>' +
        '<button class="btn-p" style="width:100%;margin-top:10px" onclick="lancerPackDDPPCustom()">Generer la periode</button>' +
      '</div>' +
      '<button class="modal-btn-skip" onclick="fermerDDPPModal()">Annuler</button>' +
    '</div>';
  document.body.appendChild(modal);
}




