// Secteur actif — modifié par setSecteur()
var SECTEUR_ACTIF = 'resto';
var INGREDIENTS_DB = INGREDIENTS_RESTO;

function setSecteur(secteur) {
  SECTEUR_ACTIF = secteur;
  INGREDIENTS_DB = secteur === 'bp' ? INGREDIENTS_BP : INGREDIENTS_RESTO;
  // Update UI buttons
  document.querySelectorAll('[id^="btn_secteur_"]').forEach(function(btn) {
    btn.classList.remove('active-ok');
  });
  var activeBtn = document.getElementById('btn_secteur_' + secteur);
  if (activeBtn) activeBtn.classList.add('active-ok');
  // Reset all plats containers to use new DB
  document.querySelectorAll('[id^="allerg_sel_"]').forEach(function(sel) {
    var id = sel.id.replace('allerg_sel_','');
    var catOpts = Object.keys(INGREDIENTS_DB).map(function(cat) {
      return '<optgroup label="' + cat + '">' +
        INGREDIENTS_DB[cat].map(function(item) {
          return '<option value="' + item[1].join(',') + '" data-nom="' + item[0].replace(/'/g,'&#39;') + '">' + item[0] + '</option>';
        }).join('') +
      '</optgroup>';
    }).join('');
    sel.innerHTML = '<option value="">-- Sélectionner dans la liste --</option>' + catOpts;
  });
}

function setSecteurAllerg(secteur) {
  // Dans le module allergènes, on peut choisir indépendamment du secteur principal
  INGREDIENTS_DB = secteur === 'bp' ? INGREDIENTS_BP : INGREDIENTS_RESTO;
  // Update buttons
  ['resto','bp','rapide','boucherie','collective'].forEach(function(s) {
    var btn = document.getElementById('btn_secteur_' + s);
    if (btn) btn.classList.toggle('active-ok', s === secteur);
  });
  // Refresh ingredient dropdowns
  document.querySelectorAll('[id^="allerg_sel_"]').forEach(function(sel) {
    var catOpts = Object.keys(INGREDIENTS_DB).map(function(cat) {
      return '<optgroup label="' + cat + '">' +
        INGREDIENTS_DB[cat].map(function(item) {
          return '<option value="' + item[1].join(',') + '" data-nom="' + item[0].replace(/'/g,'&#39;') + '">' + item[0] + '</option>';
        }).join('') +
      '</optgroup>';
    }).join('');
    sel.innerHTML = '<option value="">-- Sélectionner dans la liste --</option>' + catOpts;
  });
}



var allergCount = 0;

function ajouterPlatAllerg() {
  // V80 — Numérotation DOM réel
  var container = document.getElementById('allergContainer');
  if (container) allergCount = container.children.length + 1;
  else allergCount++;
  var id = allergCount;
  var div = document.createElement('div');
  div.className = 'fblock';
  div.id = 'allerg_' + id;
  div.style.borderLeft = '4px solid #b45309';
  var delBtn = id > 1 ? '<button class="btn-delete" onclick="supprimerPlatAllerg(' + id + ')">✕</button>' : '';

  var catOpts = Object.keys(INGREDIENTS_DB).map(function(cat) {
    return '<optgroup label="' + cat + '">' +
      INGREDIENTS_DB[cat].map(function(item) {
        return '<option value="' + item[1].join(',') + '" data-nom="' + item[0].replace(/'/g,'&#39;') + '">' + item[0] + '</option>';
      }).join('') +
    '</optgroup>';
  }).join('');

  div.innerHTML =
    '<div class="fblock-title"><span>🍽️ Plat N°' + id + '</span>' + delBtn + '</div>' +
    '<div class="frow"><div class="flabel req">Nom du plat</div>' +
      '<input class="finput" id="allerg_nom_' + id + '" placeholder="' + getBySection('Ex : Quiche lorraine, Pad thaï, Moules frites...', 'Ex : Croissant au beurre, Tarte aux fraises, Éclair chocolat...', 'Ex : Burger bœuf, Wrap poulet, Menu kebab...', 'Ex : Merguez, Côte de porc, Pâté maison...', 'Ex : Poulet rôti, Gratin dauphinois, Tarte...') + '"/>' +
    '</div>' +
    '<div style="background:#fff7ed;border-radius:10px;padding:12px 14px;margin-top:8px">' +
      '<div style="font-size:12px;font-weight:800;color:#b45309;margin-bottom:10px">🥦 Ingrédients du plat</div>' +

      // RECHERCHE RAPIDE
      '<div class="frow" style="position:relative">' +
        '<div class="flabel">🔍 Recherche rapide (tapez 2 lettres)</div>' +
        '<input class="finput" id="allerg_search_' + id + '" placeholder="' + getBySection('Ex : beurre, saumon, soja, curry...', 'Ex : beurre, farine, œuf, chocolat...', 'Ex : viande hachée, pain burger, sauce, fromage...', 'Ex : bœuf, porc, épices, boyaux...', 'Ex : poulet, légumes, sauce, fromage...') + '" autocomplete="off" oninput="onSearchIngredient(' + id + ')" onkeydown="onSearchKey(event,' + id + ')"/>' +
        '<div id="allerg_results_' + id + '" style="display:none;position:absolute;top:100%;left:0;right:0;background:white;border:1.5px solid #fed7aa;border-radius:12px;box-shadow:0 8px 24px rgba(0,0,0,.15);z-index:100;max-height:220px;overflow-y:auto;margin-top:2px"></div>' +
      '</div>' +

      // MENU PAR CATÉGORIE
      '<div class="frow"><div class="flabel">📋 Ou parcourir par catégorie</div>' +
        '<select class="fselect" id="allerg_sel_' + id + '" onchange="ajouterIngredientSelect(' + id + ')">' +
          '<option value="">-- Sélectionner dans la liste --</option>' + catOpts +
        '</select>' +
      '</div>' +

      // SAISIE LIBRE
      '<div class="frow"><div class="flabel">✏️ Ingrédient non trouvé ? Saisie libre</div>' +
        '<div style="display:flex;gap:8px">' +
          '<input class="finput" id="allerg_libre_' + id + '" placeholder="Nom de l\'ingrédient" style="flex:1" onkeydown="if(event.key===\'Enter\')ajouterIngredientLibre(' + id + ')"/>' +
          '<button onclick="ajouterIngredientLibre(' + id + ')" style="padding:10px 14px;background:#b45309;color:white;border:none;border-radius:10px;font-weight:700;cursor:pointer;font-family:Outfit,sans-serif;flex-shrink:0">+ Ajouter</button>' +
        '</div>' +
        '<div style="font-size:11px;color:var(--dim);margin-top:4px">Ses allergènes seront marqués à vérifier manuellement</div>' +
      '</div>' +

      '<div id="allerg_liste_' + id + '" style="margin-top:8px;display:flex;flex-wrap:wrap;gap:6px"></div>' +
    '</div>';
  container.appendChild(div);

  // Close results on outside click
  document.addEventListener('click', function closeResults(e) {
    var results = document.getElementById('allerg_results_' + id);
    var search = document.getElementById('allerg_search_' + id);
    if (results && search && !results.contains(e.target) && e.target !== search) {
      results.style.display = 'none';
    }
  });
}

function onSearchIngredient(platId) {
  var input = document.getElementById('allerg_search_' + platId);
  var resultsDiv = document.getElementById('allerg_results_' + platId);
  var q = input.value.trim();
  if (q.length < 2) { resultsDiv.style.display='none'; return; }
  var results = getIngredientsBySearch(q);
  if (!results.length) { resultsDiv.style.display='none'; return; }
  resultsDiv.innerHTML = results.map(function(r, idx) {
    var allergTxt = r.allergenes.length ? r.allergenes.map(function(i){return ALLERG_NOMS[i];}).join(', ') : 'Aucun allergène';
    return '<div onclick="selectIngredientResult(' + platId + ',\'' + r.nom.replace(/'/g,"\\'") + '\',[' + r.allergenes.join(',') + '])" ' +
      'style="padding:10px 14px;cursor:pointer;border-bottom:1px solid #fef3c7;' +
      'font-size:13px;transition:background .1s" ' +
      'onmouseover="this.style.background=\'#fff7ed\'" onmouseout="this.style.background=\'white\'">' +
      '<div style="font-weight:700;color:#1a1a2e">' + r.nom + '</div>' +
      '<div style="font-size:10px;color:' + (r.allergenes.length ? '#dc2626' : '#6b7280') + ';margin-top:2px">' +
      (r.allergenes.length ? '⚠️ ' : '✅ ') + allergTxt + '</div>' +
      '<div style="font-size:9px;color:#9ca3af;margin-top:1px">' + r.cat + '</div>' +
      '</div>';
  }).join('');
  resultsDiv.style.display = 'block';
}

function onSearchKey(event, platId) {
  if (event.key === 'Escape') {
    document.getElementById('allerg_results_' + platId).style.display = 'none';
  }
}

function selectIngredientResult(platId, nom, allergIdx) {
  addIngredientTag(platId, nom, allergIdx, false);
  document.getElementById('allerg_search_' + platId).value = '';
  document.getElementById('allerg_results_' + platId).style.display = 'none';
}

function ajouterIngredientSelect(platId) {
  var sel = document.getElementById('allerg_sel_' + platId);
  var opt = sel.options[sel.selectedIndex];
  if (!opt || opt.value === '') return;
  var nom = opt.getAttribute('data-nom');
  var allergIdx = opt.value ? opt.value.split(',').filter(function(v){return v!=='';}).map(Number) : [];
  addIngredientTag(platId, nom, allergIdx, false);
  sel.selectedIndex = 0;
}

