// Merge custom ingredients into search
function getIngredientsBySearch(query) {
  var results = [];
  var q = query.toLowerCase();
  // Custom first
  Object.keys(CUSTOM_INGREDIENTS).forEach(function(nom) {
    if (nom.toLowerCase().indexOf(q) !== -1) {
      results.push({cat:'Mes ingrédients personnalisés', nom:nom, allergenes:CUSTOM_INGREDIENTS[nom]});
    }
  });
  // Then DB
  Object.keys(INGREDIENTS_DB).forEach(function(cat) {
    INGREDIENTS_DB[cat].forEach(function(item) {
      if (item[0].toLowerCase().indexOf(q) !== -1) {
        results.push({cat:cat, nom:item[0], allergenes:item[1]});
      }
    });
  });
  return results.slice(0, 14);
}

// ── MODAL ALLERGÈNES INGRÉDIENT LIBRE ──
var _pendingLibrePlatId = null;
var _pendingLibreNom = '';

function ajouterIngredientLibre(platId) {
  var input = document.getElementById('allerg_libre_' + platId);
  var nom = input.value.trim();
  if (!nom) return;

  // Check if already in custom DB
  if (CUSTOM_INGREDIENTS[nom] !== undefined) {
    addIngredientTag(platId, nom, CUSTOM_INGREDIENTS[nom], false);
    input.value = '';
    return;
  }

  // Open allergen selection modal
  _pendingLibrePlatId = platId;
  _pendingLibreNom = nom;
  input.value = '';

  var modal = document.getElementById('modalIngredientLibre');
  document.getElementById('modal_libre_nom').textContent = '"' + nom + '"';
  // Reset checkboxes
  for (var i=0; i<14; i++) {
    var cb = document.getElementById('libre_allerg_' + i);
    if (cb) cb.checked = false;
  }
  modal.classList.add('visible');
}

function confirmerIngredientLibre() {
  var allergIdx = [];
  for (var i=0; i<14; i++) {
    var cb = document.getElementById('libre_allerg_' + i);
    if (cb && cb.checked) allergIdx.push(i);
  }
  // Save to custom DB
  CUSTOM_INGREDIENTS[_pendingLibreNom] = allergIdx;
  saveCustomIngredients();
  // Add tag
  addIngredientTag(_pendingLibrePlatId, _pendingLibreNom, allergIdx, false);
  document.getElementById('modalIngredientLibre').classList.remove('visible');
  _pendingLibrePlatId = null;
  _pendingLibreNom = '';
}

function annulerIngredientLibre() {
  document.getElementById('modalIngredientLibre').classList.remove('visible');
  _pendingLibrePlatId = null;
  _pendingLibreNom = '';
}

function addIngredientTag(platId, nom, allergIdx, isManual) {
  var liste = document.getElementById('allerg_liste_' + platId);
  if (!liste) return;
  var existing = liste.querySelectorAll('[data-nom]');
  for (var i=0; i<existing.length; i++) {
    if (existing[i].getAttribute('data-nom') === nom) return;
  }
  var tag = document.createElement('div');
  tag.setAttribute('data-nom', nom);
  tag.setAttribute('data-allerg', allergIdx.join(','));
  tag.setAttribute('data-manual', '0');
  var hasAllerg = allergIdx.length > 0;
  var allergTxt = hasAllerg
    ? allergIdx.map(function(i){return ALLERG_NOMS[i];}).join(', ')
    : 'Aucun allergène';
  tag.style.cssText = 'display:inline-flex;align-items:center;gap:6px;background:' +
    (hasAllerg ? '#fef9c3' : '#f0fdf4') +
    ';border:1.5px solid ' + (hasAllerg ? '#ca8a04' : '#16a34a') +
    ';border-radius:20px;padding:5px 12px;font-size:12px;font-weight:600;color:' +
    (hasAllerg ? '#92400e' : '#15803d') + ';max-width:100%';
  tag.innerHTML =
    '<span style="font-weight:700">' + nom + '</span>' +
    '<span style="font-size:10px;opacity:.7;font-weight:500"> · ' + allergTxt + '</span>' +
    '<span onclick="retirerIngredient(this)" style="color:#dc2626;font-weight:800;font-size:14px;padding:0 2px;cursor:pointer;flex-shrink:0">✕</span>';
  liste.appendChild(tag);
}

function retirerIngredient(btn) {
  btn.parentElement.remove();
}


function genererMatrice() {
  var plats = [];
  document.querySelectorAll('[id^="allerg_nom_"]').forEach(function(el) {
    var id = el.id.replace('allerg_nom_','');
    var nom = el.value.trim() || 'Plat N°' + id;
    var allergSet = new Array(14).fill(false);
    var hasManual = false;
    var liste = document.getElementById('allerg_liste_' + id);
    if (liste) {
      liste.querySelectorAll('[data-allerg]').forEach(function(tag) {
        var isManual = tag.getAttribute('data-manual') === '1';
        if (isManual) { hasManual = true; return; }
        var idxs = tag.getAttribute('data-allerg');
        if (idxs) idxs.split(',').filter(Boolean).forEach(function(i){ allergSet[parseInt(i)] = true; });
      });
    }
    plats.push({nom:nom, allergSet:allergSet, hasManual:hasManual});
  });
  if (!plats.length) { showToast('Ajoutez au moins un plat avec ses ingrédients.', 'warn'); return; }

  // EN-TÊTE ÉTABLISSEMENT
  var etabNom = 'RESTAURANT TEST';
  var dateStr = new Date().toLocaleDateString('fr-FR', {day:'2-digit',month:'long',year:'numeric'});

  var html =
    '<div style="font-family:Arial,sans-serif;padding:0">' +
    // Header
    '<div style="background:linear-gradient(135deg,#78350f,#b45309);color:white;border-radius:12px 12px 0 0;padding:16px 20px;margin-bottom:0">' +
      '<div style="font-size:16px;font-weight:900;margin-bottom:2px">🥜 Matrice des Allergènes</div>' +
      '<div style="font-size:12px;opacity:.85">' + etabNom + ' · Mise à jour le ' + dateStr + '</div>' +
      '<div style="font-size:11px;opacity:.6;margin-top:2px">Conformément au Règlement UE N°1169/2011 — 14 allergènes obligatoires</div>' +
    '</div>' +

    // Légende
    '<div style="background:#fff7ed;border:1px solid #fed7aa;border-top:none;padding:8px 16px;display:flex;gap:16px;font-size:10px;color:#92400e;align-items:center">' +
      '<span>🟡 <strong>●</strong> = Allergène présent</span>' +
      '<span>⚪ <strong>○</strong> = Absent</span>' +
      '<span style="color:#ca8a04">⚠️ * = À vérifier manuellement</span>' +
    '</div>' +

    // Table
    '<div style="overflow-x:auto">' +
    '<table style="border-collapse:collapse;width:100%;font-size:10px;min-width:600px">' +
    '<thead>' +
    '<tr style="background:#b45309">' +
      '<th style="border:1px solid #92400e;padding:8px 12px;text-align:left;color:white;font-size:11px;min-width:120px;position:sticky;left:0;background:#b45309">Plat / Préparation</th>';

  ALLERG_NOMS.forEach(function(a, i) {
    var short = ['Gluten','Crustaces','Oeufs','Poissons','Arachides','Soja','Lait','Fr.coque','Celeri','Moutarde','Sesame','Sulfites','Lupin','Mollusques'][i];
    html += '<th style="border:1px solid #92400e;padding:4px 3px;text-align:center;color:white;font-size:9px;width:42px" title="' + a + '">' + short + '</th>';
  });
  html += '</tr></thead><tbody>';

  plats.forEach(function(p, pi) {
    var rowBg = pi % 2 === 0 ? '#ffffff' : '#fafafa';
    var hasAllerg = p.allergSet.some(function(v){return v;});
    html += '<tr style="background:' + rowBg + '">' +
      '<td style="border:1px solid #e5e7eb;padding:8px 12px;font-weight:700;font-size:11px;color:#1a1a2e;position:sticky;left:0;background:' + rowBg + '">' +
        p.nom + (p.hasManual ? ' <span style="color:#ca8a04;font-size:10px">*</span>' : '') +
      '</td>';
    p.allergSet.forEach(function(has) {
      html += '<td style="border:1px solid #e5e7eb;padding:6px 4px;text-align:center;background:' +
        (has ? '#fef9c3' : rowBg) + ';color:' +
        (has ? '#b45309' : '#d1d5db') + ';font-weight:' +
        (has ? '900' : '400') + ';font-size:16px">' +
        (has ? '●' : '○') +
      '</td>';
    });
    html += '</tr>';
  });

  html += '</tbody></table></div>';

  // Footer
  if (plats.some(function(p){return p.hasManual;})) {
    html += '<div style="font-size:10px;color:#92400e;background:#fff7ed;border:1px solid #fed7aa;border-top:none;padding:8px 16px;border-radius:0 0 8px 8px">* Ingrédient(s) saisi(s) librement — vérifiez leurs allergènes et mettez à jour la matrice.</div>';
  }
  html += '<div style="font-size:9px;color:#9ca3af;padding:6px 0;text-align:right">Généré par HACCP Pro · ' + getNowStr() + ' · ' + plats.length + ' plat(s)</div>';
  html += '</div>';

  document.getElementById('matriceContent').innerHTML = html;
  document.getElementById('matriceAllerg').style.display = 'block';
  document.getElementById('matriceAllerg').scrollIntoView({behavior:'smooth'});
}

function supprimerPlatAllerg(id) {
  if (!confirm('Confirmer la suppression ?')) return;
  var el=document.getElementById('allerg_'+id);
  if(el) el.remove();
  renumeroterBlocs('#allergContainer', 'Plat N°');
}

function imprimerMatrice() {
  var matriceEl = document.getElementById('matriceContent');
  if (!matriceEl || !matriceEl.innerHTML.trim()) { showToast('Generez d\'abord la matrice.', 'warn'); return; }

  var existing = document.getElementById('printOverlay');
  if (existing) existing.remove();
  var overlay = document.createElement('div');
  overlay.id = 'printOverlay';
  overlay.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:white;z-index:99999;overflow-y:auto;-webkit-overflow-scrolling:touch';

  var tb = document.createElement('div');
  tb.className = 'no-print';
  tb.style.cssText = 'background:#065f46;padding:10px 16px;display:flex;justify-content:space-between;align-items:center;position:sticky;top:0;z-index:1';
  var tbTitle = document.createElement('div');
  tbTitle.style.cssText = 'color:white;font-weight:800;font-size:13px';
  tbTitle.textContent = 'Matrice Allergenes — ' + (ETAB.nom||'');
  var tbBtns = document.createElement('div');
  tbBtns.style.cssText = 'display:flex;gap:8px';
  var btnImpr = document.createElement('button');
  btnImpr.textContent = '🖨️ Imprimer';
  btnImpr.style.cssText = 'background:#10b981;color:white;border:none;border-radius:8px;padding:8px 14px;font-weight:700;cursor:pointer;font-size:12px';
  btnImpr.onclick = function() { window.print(); };
  var btnFerm = document.createElement('button');
  btnFerm.textContent = '✕ Fermer';
  btnFerm.style.cssText = 'background:#dc2626;color:white;border:none;border-radius:8px;padding:8px 14px;font-weight:700;cursor:pointer;font-size:12px';
  btnFerm.onclick = function() { var el = document.getElementById('printOverlay'); if (el) el.remove(); };
  tbBtns.appendChild(btnImpr); tbBtns.appendChild(btnFerm);
  tb.appendChild(tbTitle); tb.appendChild(tbBtns);

  // Message iOS
  var iosMsg = document.createElement('div');
  iosMsg.className = 'no-print';
  iosMsg.style.cssText = 'background:#fef3c7;border-bottom:2px solid #fcd34d;padding:8px 16px;font-size:11px;color:#92400e;font-weight:600;text-align:center';
  iosMsg.textContent = 'Sur iPhone/iPad : utilisez le bouton Partager du navigateur → Imprimer';

  var ct = document.createElement('div');
  ct.style.cssText = 'padding:16px';
  var header = '<div style="background:linear-gradient(135deg,#065f46,#10b981);color:white;padding:14px 16px;border-radius:10px;margin-bottom:14px">';
  header += '<div style="font-weight:800;font-size:15px">Matrice Allergenes</div>';
  header += '<div style="font-size:11px;opacity:.85;margin-top:4px">' + _echap(ETAB.nom||'') + ' — ' + getNowStr() + '</div>';
  header += '</div>';
  ct.innerHTML = header + matriceEl.outerHTML;

  overlay.appendChild(tb);
  overlay.appendChild(ct);
  document.body.appendChild(overlay);
  overlay.scrollTop = 0;
}

function exporterMatrice() {
  imprimerMatrice();
}

