var sigCanvasAff, sigCtxAff, isDrawingAff = false, hasSigAff = false;

function initSigAff() {
  sigCanvasAff = document.getElementById('sigCanvasAff');
  if (!sigCanvasAff) return;
  sigCtxAff = sigCanvasAff.getContext('2d');
  hasSigAff=false; isDrawingAff=false;
  var dpr=window.devicePixelRatio||1, w=sigCanvasAff.parentElement.clientWidth||340;
  sigCanvasAff.width=Math.round(w*dpr); sigCanvasAff.height=Math.round(140*dpr);
  sigCanvasAff.style.width=w+'px'; sigCanvasAff.style.height='140px';
  sigCtxAff.scale(dpr,dpr); sigCtxAff.strokeStyle='#1a1a2e';
  sigCtxAff.lineWidth=2.5; sigCtxAff.lineCap='round'; sigCtxAff.lineJoin='round';
  function pos(e){var r=sigCanvasAff.getBoundingClientRect();var s=e.touches?e.touches[0]:e;return{x:s.clientX-r.left,y:s.clientY-r.top};}
  function start(e){e.preventDefault();isDrawingAff=true;var p=pos(e);sigCtxAff.beginPath();sigCtxAff.moveTo(p.x,p.y);}
  function move(e){e.preventDefault();if(!isDrawingAff)return;var p=pos(e);sigCtxAff.lineTo(p.x,p.y);sigCtxAff.stroke();hasSigAff=true;}
  function stop(e){e.preventDefault();isDrawingAff=false;}
  sigCanvasAff.addEventListener('mousedown',start); sigCanvasAff.addEventListener('mousemove',move);
  sigCanvasAff.addEventListener('mouseup',stop); sigCanvasAff.addEventListener('mouseleave',stop);
  sigCanvasAff.addEventListener('touchstart',start,{passive:false}); sigCanvasAff.addEventListener('touchmove',move,{passive:false});
  sigCanvasAff.addEventListener('touchend',stop,{passive:false});
}

function clearSigAff() {
  if (!sigCtxAff||!sigCanvasAff) return;
  sigCtxAff.clearRect(0,0,sigCanvasAff.width,sigCanvasAff.height); hasSigAff=false;
}

