function checkExpiry(fieldId, alertId) {
  var val = document.getElementById(fieldId).value;
  var alertEl = document.getElementById(alertId);
  if (!val || !alertEl) return;
  var expiry = new Date(val);
  var today = new Date();
  var diff = (expiry - today) / (1000 * 60 * 60 * 24);
  var show = diff <= 30;
  alertEl.style.display = show ? 'flex' : 'none';
  var actionEl = document.getElementById('nc_action_' + alertId);
  if (actionEl) actionEl.classList.toggle('visible', show);
}

function checkExpiry6m(fieldId, alertId) {
  var val = document.getElementById(fieldId).value;
  var alertEl = document.getElementById(alertId);
  if (!val || !alertEl) return;
  var last = new Date(val);
  var today = new Date();
  var diffDays = (today - last) / (1000 * 60 * 60 * 24);
  // Alerte si > 150 jours (5 mois) ou > 180 jours (6 mois)
  alertEl.style.display = diffDays >= 150 ? 'flex' : 'none';
}

