// ── NUISIBLES — DOCUMENTS LOCAUX MULTI-FICHIERS — NE PAS MODIFIER ──
function nuisGetDocs(type) {
  try { return JSON.parse(lsGet('haccp_nuis_docs_' + type) || '[]'); } catch(e) { return []; }
}
function nuisSaveDocs(type, docs) {
  try { lsSet('haccp_nuis_docs_' + type, JSON.stringify(docs)); } catch(e) { showToast('Erreur stockage', 'err', 2000); }
}
function nuisRenderDocs(type) {
  var list = document.getElementById('nuis_docs_' + type + '_list');
  if (!list) return;
  var docs = nuisGetDocs(type);
  list.innerHTML = '';
  if (docs.length === 0) {
    var empty = document.createElement('div');
    empty.style.cssText = 'font-size:12px;color:#9ca3af;padding:4px 0';
    empty.textContent = 'Aucun document';
    list.appendChild(empty);
    return;
  }
  docs.forEach(function(doc, i) {
    var isImage = doc.data && doc.data.startsWith('data:image');
    var isPDF = doc.name && doc.name.toLowerCase().endsWith('.pdf');

    var row = document.createElement('div');
    row.style.cssText = 'background:#f9fafb;border:1px solid #e5e7eb;border-radius:8px;padding:8px;margin-bottom:8px';

    // Miniature image
    if (isImage) {
      var img = document.createElement('img');
      img.src = doc.data;
      img.style.cssText = 'max-width:100%;max-height:100px;border-radius:6px;display:block;margin-bottom:6px;cursor:pointer;border:1px solid #e5e7eb';
      (function(d) { img.onclick = function() { nuisViewDoc(d); }; })(doc);
      row.appendChild(img);
    } else if (isPDF) {
      var pdfIcon = document.createElement('div');
      pdfIcon.style.cssText = 'background:#fee2e2;border-radius:6px;padding:10px;text-align:center;margin-bottom:6px;font-size:24px';
      pdfIcon.textContent = '📄';
      row.appendChild(pdfIcon);
    }

    // Nom du fichier
    var nameEl = document.createElement('div');
    nameEl.style.cssText = 'font-size:12px;color:#374151;font-weight:600;margin-bottom:6px';
    nameEl.textContent = doc.name;
    row.appendChild(nameEl);

    // Boutons actions
    var btns = document.createElement('div');
    btns.style.cssText = 'display:flex;gap:6px';

    if (isImage) {
      var btnVoir = document.createElement('button');
      btnVoir.textContent = '🔍 Voir';
      btnVoir.style.cssText = 'background:#7c3aed;color:white;border:none;border-radius:6px;padding:5px 10px;font-size:11px;font-weight:700;cursor:pointer;flex:1';
      (function(d) { btnVoir.onclick = function() { nuisViewDoc(d); }; })(doc);
      btns.appendChild(btnVoir);
    }
    if (isPDF) {
      var btnOuvrir = document.createElement('button');
      btnOuvrir.textContent = '📂 Ouvrir';
      btnOuvrir.style.cssText = 'background:#2563eb;color:white;border:none;border-radius:6px;padding:5px 10px;font-size:11px;font-weight:700;cursor:pointer;flex:1';
      // V116 Livraison 7 — passer par la visionneuse PDF intégrée (avec bouton Fermer)
      (function(d) { btnOuvrir.onclick = function() { ouvrirVisionneusePDF(d.data); }; })(doc);
      btns.appendChild(btnOuvrir);
    }

    var btnSuppr = document.createElement('button');
    btnSuppr.textContent = '✕ Supprimer';
    btnSuppr.style.cssText = 'background:#dc2626;color:white;border:none;border-radius:6px;padding:5px 10px;font-size:11px;font-weight:700;cursor:pointer;flex:1';
    (function(t, idx) { btnSuppr.onclick = function() { nuisDeleteDocItem(t, idx); }; })(type, i);
    btns.appendChild(btnSuppr);

    row.appendChild(btns);
    list.appendChild(row);
  });
}

// V116 Livraison 7 — Visionneuse PDF intégrée à l'app (avec bouton Fermer)
// Évite que l'ouverture d'un PDF fasse sortir l'utilisateur de l'app.
function ouvrirVisionneusePDF(url) {
  var existing = document.getElementById('pdfViewerOverlay');
  if (existing) existing.remove();
  var overlay = document.createElement('div');
  overlay.id = 'pdfViewerOverlay';
  overlay.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,.95);z-index:999999;display:flex;flex-direction:column';
  var topBar = document.createElement('div');
  topBar.style.cssText = 'background:#1e1b4b;padding:10px 16px;display:flex;align-items:center;justify-content:space-between;color:white';
  var titre = document.createElement('div');
  titre.style.cssText = 'font-weight:700;font-size:14px';
  titre.textContent = '📄 Document';
  var btnsZone = document.createElement('div');
  btnsZone.style.cssText = 'display:flex;gap:8px';
  var openBtn = document.createElement('a');
  openBtn.textContent = '⤓ Télécharger';
  openBtn.href = url;
  openBtn.target = '_blank';
  openBtn.rel = 'noopener';
  openBtn.style.cssText = 'background:#374151;color:white;border-radius:8px;padding:8px 14px;font-weight:600;cursor:pointer;font-size:13px;text-decoration:none';
  var closeBtn = document.createElement('button');
  closeBtn.textContent = '✕ Fermer';
  closeBtn.style.cssText = 'background:#dc2626;color:white;border:none;border-radius:8px;padding:8px 16px;font-weight:700;cursor:pointer;font-size:14px';
  closeBtn.onclick = function() { overlay.remove(); };
  btnsZone.appendChild(openBtn);
  btnsZone.appendChild(closeBtn);
  topBar.appendChild(titre);
  topBar.appendChild(btnsZone);
  var iframe = document.createElement('iframe');
  iframe.src = url;
  iframe.style.cssText = 'flex:1;width:100%;border:0;background:white';
  overlay.appendChild(topBar);
  overlay.appendChild(iframe);
  document.body.appendChild(overlay);
}

function nuisViewDoc(doc) {
  // V116 Livraison 7 — Si c'est un PDF, on bascule vers la visionneuse PDF intégrée
  var estPdf = false;
  if (doc && doc.name && doc.name.toLowerCase().endsWith('.pdf')) estPdf = true;
  if (doc && doc.data && typeof doc.data === 'string' && doc.data.indexOf('application/pdf') !== -1) estPdf = true;
  if (estPdf) { ouvrirVisionneusePDF(doc.data); return; }
  // Sinon, ancien comportement : on affiche l'image dans un overlay
  var existing = document.getElementById('nuisDocOverlay');
  if (existing) existing.remove();
  var overlay = document.createElement('div');
  overlay.id = 'nuisDocOverlay';
  overlay.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,.9);z-index:99999;display:flex;flex-direction:column;align-items:center;justify-content:center';
  var closeBtn = document.createElement('button');
  closeBtn.textContent = '✕ Fermer';
  closeBtn.style.cssText = 'background:#dc2626;color:white;border:none;border-radius:8px;padding:10px 20px;font-weight:700;cursor:pointer;margin-bottom:12px;font-size:14px';
  closeBtn.onclick = function() { overlay.remove(); };
  var img = document.createElement('img');
  img.src = doc.data;
  img.style.cssText = 'max-width:95%;max-height:80vh;border-radius:8px;object-fit:contain';
  overlay.appendChild(closeBtn);
  overlay.appendChild(img);
  document.body.appendChild(overlay);
}
function nuisAddDoc(type) {
  var input = document.createElement('input');
  input.type = 'file';
  input.accept = 'image/*,.pdf';
  input.multiple = true;
  // V116 — Fix bug iPhone Safari : input doit être dans le DOM
  input.style.position = 'absolute';
  input.style.left = '-9999px';
  document.body.appendChild(input);
  input.onchange = function() {
    if (!input.files || input.files.length === 0) { try { document.body.removeChild(input); } catch(_){} return; }
    var files = Array.from(input.files);
    var docs = nuisGetDocs(type);
    var loaded = 0;
    var total = files.length;
    files.forEach(function(file) {
      var reader = new FileReader();
      reader.onload = function(e) {
        // Compresser les images avant stockage (évite la saturation du localStorage)
        _compresserSiImage(e.target.result, function(dataURL) {
          docs.push({ name: file.name, data: dataURL });
          // V116 — Range aussi dans la boîte d'attente (cloud)
          apresLaCapturePhoto(dataURL, type, 'nuisibles_' + type);
          loaded++;
          if (loaded === total) {
            nuisSaveDocs(type, docs);
            nuisRenderDocs(type);
            showToast(total === 1 ? 'Document ajouté' : total + ' documents ajoutés', 'ok', 2000);
            // V116 — Nettoyage
            try { document.body.removeChild(input); } catch(_){}
          }
        });
      };
      reader.onerror = function() {
        loaded++;
        if (loaded === total) {
          nuisSaveDocs(type, docs);
          nuisRenderDocs(type);
        }
      };
      reader.readAsDataURL(file);
    });
  };
  input.click();
}
function nuisDeleteDocItem(type, idx) {
  var docs = nuisGetDocs(type);
  docs.splice(idx, 1);
  nuisSaveDocs(type, docs);
  nuisRenderDocs(type);
  showToast('Document supprimé', 'ok', 1500);
}
function nuisLoadDocs() {
  ['contrat','cr','rapport'].forEach(function(type) { nuisRenderDocs(type); });
}
