// ── initSigCanvas — helper signature générique ──
function initSigCanvas(canvasId, onDraw) {
  var canvas = document.getElementById(canvasId);
  if (!canvas) return;
  var dpr = window.devicePixelRatio || 1;
  var w = canvas.parentElement.clientWidth || 340;
  canvas.width = Math.round(w * dpr); canvas.height = Math.round(140 * dpr);
  canvas.style.width = w + 'px'; canvas.style.height = '140px';
  var ctx = canvas.getContext('2d');
  ctx.scale(dpr, dpr);
  ctx.strokeStyle = '#1a1a2e'; ctx.lineWidth = 2.5; ctx.lineCap = 'round';
  var drawing = false;
  canvas.addEventListener('mousedown', function(e) { var r=canvas.getBoundingClientRect(); ctx.beginPath(); ctx.moveTo(e.clientX-r.left, e.clientY-r.top); drawing=true; });
  canvas.addEventListener('mousemove', function(e) { if(!drawing) return; var r=canvas.getBoundingClientRect(); ctx.lineTo(e.clientX-r.left, e.clientY-r.top); ctx.stroke(); onDraw(true); });
  canvas.addEventListener('mouseup', function(){ drawing=false; });
  canvas.addEventListener('touchstart', function(e){ e.preventDefault(); var r=canvas.getBoundingClientRect(); var t=e.touches[0]; ctx.beginPath(); ctx.moveTo(t.clientX-r.left, t.clientY-r.top); drawing=true; }, {passive:false});
  canvas.addEventListener('touchmove', function(e){ e.preventDefault(); var r=canvas.getBoundingClientRect(); var t=e.touches[0]; ctx.lineTo(t.clientX-r.left, t.clientY-r.top); ctx.stroke(); onDraw(true); }, {passive:false});
  canvas.addEventListener('touchend', function(){ drawing=false; });
}


// ══ HISTORIQUE — NE PAS MODIFIER ══
var _histFilter = 'all';

function chargerHistorique() {
  var container = document.getElementById('histContainer');
  var countEl = document.getElementById('hist_count');
  if (!container) return;
  var stored = lsGet('haccp_historique');
  var historique = [];
  if (stored) { try { historique = JSON.parse(stored); } catch(e) {} }
  historique.reverse();

  var now = new Date();
  var _curSecteur = (typeof SECTEUR_ACTIF !== 'undefined' && SECTEUR_ACTIF) ? SECTEUR_ACTIF : (ETAB.secteur || '');
  var filtered = historique.filter(function(h) {
    // Masque les tests des autres secteurs ; les anciennes entrées sans secteur restent visibles.
    if (h.secteur && _curSecteur && h.secteur !== _curSecteur) return false;
    if (_histFilter === 'all') return true;
    var d = new Date(h.date);
    if (_histFilter === 'today') return h.date === now.toISOString().split('T')[0];
    if (_histFilter === 'week') { var wk = new Date(now); wk.setDate(wk.getDate()-7); return d >= wk; }
    if (_histFilter === 'month') { var mo = new Date(now); mo.setMonth(mo.getMonth()-1); return d >= mo; }
    return true;
  });

  if (countEl) countEl.textContent = '(' + filtered.length + ')';

  if (filtered.length === 0) {
    container.innerHTML = '<div style="font-size:12px;color:#9ca3af;padding:12px;text-align:center">Aucun enregistrement trouvé</div>';
    return;
  }

  container.innerHTML = '';
  // V113 — K : mapping nom historique → identifiant exportModule
  var _moduleNameToExportId = {
    'Réception & Traçabilité': 'reception',
    'Traçabilité produits': 'tracabilite',
    'Températures enceintes': 'temperatures',
    'Hygiène & Tenue': 'hygiene',
    'Nettoyage ouverture': 'ouverture',
    'Cuisson & Remise T': 'cuisson',
    'Refroidissement rapide': 'refroidissement',
    'Huiles de friture': 'huiles',
    'Étiquetage interne': 'etiquetage',
    'Déchets & Biodéchets': 'dechets',
    'Pertes & Invendus': 'pertes',
    'Nettoyage fermeture': 'fermeture',
    'NC & Actions correctives': 'nc',
    'Affichages réglementaires': 'affichage',
    'Contrôle documentaire': 'documents',
    'Suivi nuisibles': 'nuisibles'
  };
  filtered.forEach(function(h) {
    var row = document.createElement('div');
    row.style.cssText = 'background:#f9fafb;border:1px solid #e5e7eb;border-radius:8px;padding:10px 12px;margin-bottom:6px;display:flex;align-items:center;gap:10px';
    var ico = document.createElement('div');
    ico.style.cssText = 'width:36px;height:36px;border-radius:8px;background:#eff6ff;display:flex;align-items:center;justify-content:center;font-size:18px;flex-shrink:0';
    ico.textContent = '✅';
    var info = document.createElement('div');
    info.style.flex = '1';
    info.innerHTML = '<div style="font-size:13px;font-weight:700">' + (h.module||'Module') + '</div>' +
      '<div style="font-size:11px;color:#6b7280">' + (h.date||'') + ' — ' + (h.heure||'') + '</div>' +
      '<div style="font-size:11px;color:#374151">Signé : ' + (h.signe||'—') + '</div>';
    row.appendChild(ico);
    row.appendChild(info);
    // V113 — K : bouton 📄 pour re-générer le PDF du module
    var exportId = _moduleNameToExportId[h.module];
    if (exportId) {
      var btnPdf = document.createElement('button');
      btnPdf.textContent = '📄';
      btnPdf.title = 'Re-générer le PDF de ce contrôle';
      btnPdf.style.cssText = 'background:#eff6ff;border:1px solid #93c5fd;color:#1d4ed8;border-radius:8px;padding:6px 10px;font-size:16px;cursor:pointer;flex-shrink:0';
      btnPdf.onclick = function() {
        if (typeof exportModule === 'function') exportModule(exportId);
        else if (typeof showToast === 'function') showToast('Export indisponible', 'warn');
      };
      row.appendChild(btnPdf);
    }
    container.appendChild(row);
  });
}

function filtrerHistorique(filter) {
  _histFilter = filter;
  ['all','today','week','month'].forEach(function(f) {
    var btn = document.getElementById('hist_' + f);
    if (btn) { btn.style.background = f === filter ? '#2563eb' : ''; btn.style.color = f === filter ? 'white' : ''; }
  });
  chargerHistorique();
}
