var _advancedVisible = false;
function toggleAdvanced() {
  _advancedVisible = !_advancedVisible;
  document.body.dataset.adv = _advancedVisible ? '1' : '0';
  document.querySelectorAll('.haccp-adv').forEach(function(el) {
    if (!_advancedVisible) {
      el.style.display = 'none';
    } else {
      // Choisir le bon display selon le type d'élément (bloc fblock ou ligne frow)
      el.style.display = el.classList.contains('fblock') ? 'block' : 'flex';
    }
  });
  // V54 — synchroniser tous les boutons toggle partageant la classe .btn-toggle-adv
  document.querySelectorAll('.btn-toggle-adv').forEach(function(b) {
    var labelType = b.dataset.advLabel || 'facultatifs';
    b.textContent = (_advancedVisible ? '⚙️ Masquer champs ' : '⚙️ Afficher champs ') + labelType;
  });
  // V80 fix — Pas de persistance : on repart toujours sur "masqué" à chaque chargement (règle Léa)
}

function initAdvancedMode() {
  // V80 fix — Toujours masqué par défaut au démarrage (pas de mémorisation)
  _advancedVisible = false;
  // Nettoyer une éventuelle persistance précédente
  try { lsRemove('haccp_adv_mode'); } catch(e) {}
}

// V80 — Auto-marquer comme facultatifs TOUS les champs sans ★ rouge.
// Règle Léa : "Tous les champs qui ne sont pas obligatoires légalement seront masqués par défaut"
// Le bouton ⚙️ "Afficher champs facultatifs" permet au client de les voir s'il le souhaite.
function marquerChampsFacultatifsAuto() {
  var pagesModules = ['page-reception','page-temperatures','page-hygiene','page-ouverture',
    'page-cuisson','page-refroidissement','page-huiles','page-etiquetage','page-fermeture',
    'page-pertes','page-dechets','page-nuisibles','page-documents','page-affichage',
    'page-nc','page-audits','page-plat-temoin','page-liaison-thermique',
    'page-registre-convives','page-analyses-micro','page-allergenes'];
  pagesModules.forEach(function(pageId) {
    var page = document.getElementById(pageId);
    if (!page) return;
    page.querySelectorAll('.frow').forEach(function(row) {
      // Ignorer si déjà marqué
      if (row.classList.contains('haccp-adv')) return;
      // Ignorer si explicitement marqué « toujours visible » (no-adv)
      if (row.classList.contains('no-adv')) return;
      // Ignorer si contient un champ obligatoire (★)
      if (row.querySelector('.flabel.req')) return;
      // Ignorer si dans un bloc d'action corrective (.nc-action) — toujours visible quand actif
      if (row.closest('.nc-action')) return;
      if (row.closest('[id*="_action_"]')) return;
      // Ignorer si contient une signature (zone obligatoire)
      if (row.querySelector('canvas[id*="ig"]')) return;
      // Ignorer si contient une status-group (boutons OK/NC = saisie critique HACCP)
      if (row.querySelector('.status-group')) return;
      // Ignorer si contient un bouton photo (≠ champ texte)
      if (row.querySelector('.photo-btn')) return;
      // Ignorer si contient un select avec onchange (pilote l'affichage de blocs dépendants)
      if (row.querySelector('select[onchange]')) return;
      // Ignorer si contient un input avec onchange/oninput (pilote la conformité)
      if (row.querySelector('input[oninput], input[onchange]')) return;
      // Ignorer si pas de champ saisissable (label seul, etc.)
      var hasField = row.querySelector('input:not([type="button"]):not([type="hidden"]), select, textarea');
      if (!hasField) return;
      // Ignorer si un champ ★ est dans un parent direct
      var parent = row.parentElement;
      if (parent && parent.classList && parent.classList.contains('frow') && parent.querySelector('.flabel.req')) return;
      // OK : ce champ n'a pas de ★ → masquer par défaut (haccp-adv)
      row.classList.add('haccp-adv');
      if (!_advancedVisible) row.style.display = 'none';
    });
  });
}

