// V85 — Raccourci direct depuis la page de connexion : tout en 1 clic
function modeTestLea() {
  console.log('[TEST LEA] Démarrage');
  try {
    // 1. Forcer toutes les variables nécessaires
    if (typeof ETAB_ID === 'undefined' || !ETAB_ID) ETAB_ID = 'local-test';
    if (typeof MODE_LOCAL !== 'undefined') MODE_LOCAL = true;
    if (typeof SB_READY !== 'undefined') SB_READY = true;
    if (typeof CLIENT_MODE !== 'undefined') CLIENT_MODE = false;
    if (typeof ETAB === 'undefined' || !ETAB) { window.ETAB = {}; }
    ETAB.nom = 'RESTAURANT TEST';
    ETAB.secteur = 'resto';
    ETAB.adresse = '1 rue de la Cuisine';
    ETAB.cp = '75001';
    ETAB.ville = 'Paris';
    ETAB.responsable = 'Léa Test';
    if (typeof SECTEUR_ACTIF !== 'undefined') SECTEUR_ACTIF = 'resto';
    try { if (typeof INGREDIENTS_DB !== 'undefined') INGREDIENTS_DB = (typeof INGREDIENTS_RESTO !== 'undefined' ? INGREDIENTS_RESTO : []); } catch(e){}
    // 2. Sauvegarder session pour persister
    try {
      var s = { etabId: ETAB_ID, etabNom: ETAB.nom, secteur: ETAB.secteur, pwdOk: true, loginAt: Date.now() };
      if (typeof sessionWrite === 'function') sessionWrite(JSON.stringify(s));
      if (typeof lsSet === 'function') {
        lsSet('haccp_mode', 'expert');
        lsSet('haccp_etab_id', ETAB_ID);
        lsSet('haccp_etab', ETAB.nom);
      }
    } catch(e){}
    // 3. Afficher tableau de bord (page-home)
    if (typeof showPage === 'function') {
      showPage('page-home');
      if (typeof renderMods === 'function') {
        try { renderMods('quotidien'); } catch(e){}
      }
    }
    console.log('[TEST LEA] Connecté, ouverture panneau');
    // 4. Ouvrir le panneau de test après un court délai
    setTimeout(function() {
      afficherPanneauTest();
    }, 500);
  } catch(e) {
    console.error('[TEST LEA] Erreur:', e);
    alert('Erreur Mode Test Léa : ' + (e.message||e));
  }
}

