// Génère une session archivée pour un module donné
function _testCreerSession(pageId, sessionData, customTimestamp) {
  try {
    var key = 'haccp_module_data_' + pageId + '_' + (typeof ETAB_ID !== 'undefined' && ETAB_ID ? ETAB_ID : 'local');
    var ts = customTimestamp || new Date().toISOString();
    var entry = {
      pageId: pageId,
      timestamp: ts,
      data: sessionData
    };
    // Conserver le timestamp dans data aussi (pour l'affichage)
    if (sessionData && !sessionData.timestamp) sessionData.timestamp = ts;
    var stored = [];
    try { stored = JSON.parse(localStorage.getItem(key) || '[]'); } catch(e) {}
    stored.unshift(entry);
    // V86 — Limite augmentée à 200 pour 7 jours de tests
    if (stored.length > 200) stored = stored.slice(0, 200);
    localStorage.setItem(key, JSON.stringify(stored));
  } catch(e) { console.warn('test session err:', e); }
}

// Transforme un libellé de point de nettoyage positif (« Sols propres »,
// « Hottes nettoyées ») en constat de non-conformité réaliste (« Sols non
// nettoyés / sales »). Utilisé par le générateur de test pour produire des NC
// crédibles au lieu d'afficher l'affirmation positive comme un défaut.
function _constatNettoyage(label) {
  var l = String(label || '');
  var zone = l
    .replace(/\s*(propres?|nettoyée?s?|lavée?s?|désinfectée?s?|désinfecté|vérifiée?s?|vérifié|vidées?|vidé|rangée?s?|rangé|effectuée?s?|effectué)\b.*$/i, '')
    .replace(/\s*\(T°\)\s*$/i, '')
    .trim();
  if (!zone) zone = l;
  return zone + ' — non nettoyé(e) / propreté insuffisante';
}

