function testLancerPackDDPP() {
  console.log('[TEST] testLancerPackDDPP appelée');
  // Supprimer panneau immédiatement
  var pn = document.getElementById('panneauTest');
  if (pn) pn.remove();
  console.log('[TEST] Panneau supprimé');

  try {
    _testEnsureConnected();
    console.log('[TEST] _testEnsureConnected OK, ETAB_ID=', ETAB_ID);
  } catch(e) {
    console.error('[TEST] erreur _testEnsureConnected:', e);
    alert('Erreur init : ' + (e.message||e));
    return;
  }

  if (typeof lancerPackDDPP !== 'function') {
    console.error('[TEST] lancerPackDDPP introuvable');
    alert('lancerPackDDPP introuvable');
    return;
  }

  var today = new Date();
  var d = today.toISOString().slice(0,10);
  console.log('[TEST] Appel lancerPackDDPPAvecPhotos avec date=', d);
  try {
    lancerPackDDPPAvecPhotos(d, d, null);
    console.log('[TEST] lancerPackDDPPAvecPhotos retournée sans erreur');
  } catch(e) {
    console.error('[TEST] erreur lancerPackDDPP:', e);
    alert('Erreur Pack DDPP : ' + (e.message||e));
    return;
  }

  setTimeout(function() {
    var overlay = document.getElementById('printOverlay');
    if (overlay) {
      overlay.style.zIndex = '999999';
      overlay.scrollTop = 0;
      console.log('[TEST] Overlay créé OK, force z-index 999999');
      alert('✅ Pack DDPP affiché — fais défiler pour voir');
    } else {
      console.error('[TEST] Overlay PAS créé');
      alert('❌ Pack DDPP non affiché — l\'overlay n\'existe pas');
    }
  }, 500);
}

