function testEffacerDonnees() {
  if (!confirm('Effacer toutes les données de test (et tes vraies saisies si tu en as) ?')) return;
  var keys = [];
  for (var i = 0; i < localStorage.length; i++) {
    var k = localStorage.key(i);
    if (k && k.indexOf('haccp_module_data_') === 0) keys.push(k);
  }
  keys.forEach(function(k) { localStorage.removeItem(k); });
  _testLog('🗑️ ' + keys.length + ' modules effacés du localStorage.', '#f59e0b');
}
