  ws.getCell(obsL + hdr1).value = 'Observations'; ws.mergeCells(obsL + hdr1 + ':' + obsL + hdr3);
  ws.getCell(sigL + hdr1).value = 'Signature'; ws.mergeCells(sigL + hdr1 + ':' + sigL + hdr3);

