    oc.value = (obsJour[jour] || []).join(' ; ');
    oc.alignment = { horizontal: 'left', vertical: 'middle', wrapText: true };
    oc.border = border; oc.font = { size: 8, color: { argb: 'FFB91C1C' } };
    // Émargement : SÉPARÉ capteur (auto) et manuel (noms des signataires).
