    if (_au && !_nb) sc.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFDBEAFE' } };
    else if (_nb && !_au) sc.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFD9DEE3' } };
    sc.alignment = { horizontal: 'center', vertical: 'middle', wrapText: true };
